'use client';

import React from 'react';

import { useBookmarks } from '@/app/providers/BookmarkContext';
import { UnifiedModal } from '@/app/shared/components/modal/UnifiedModal';
import { CloseIcon } from '@/app/shared/icons';

import {
  ModalHeader,
  FormActions,
  PlannerForm,
  usePlannerCalculations,
  useFormState,
  buildPlannerPlanDefinitions,
  createPlannerPlansForRange,
} from './create-planner-modal';

import type { PlanFormData } from './create-planner-modal';
import type { Chapter, PlannerPlan } from '@/types';

interface CreatePlannerModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export const CreatePlannerModal = ({
  isOpen,
  onClose,
}: CreatePlannerModalProps): React.JSX.Element => {
  const { formData, handleFormDataChange, resetForm } = useFormState();
  const { chapters, planner, createPlannerPlan } = useBookmarks();

  const { totalVerses, versesPerDay, isValidRange } = usePlannerCalculations(
    chapters,
    formData.startSurah,
    formData.startVerse,
    formData.endSurah,
    formData.endVerse,
    formData.estimatedDays
  );

  const planDefinitions = React.useMemo(
    () => buildPlannerPlanDefinitions(formData, chapters),
    [formData, chapters]
  );
  const duplicatePlanName = useDuplicatePlanName(formData, chapters, planner, planDefinitions);

  const canSubmit =
    formData.planName.trim().length > 0 && isValidRange && totalVerses > 0 && !duplicatePlanName;

  const handleSubmit = (e: React.FormEvent): void => {
    e.preventDefault();
    if (!canSubmit) return;
    createPlannerPlansForRange(formData, chapters, createPlannerPlan);
    handleClose();
  };

  const handleClose = useCloseHandler(resetForm, onClose);

  return (
    <UnifiedModal
      isOpen={isOpen}
      onClose={handleClose}
      ariaLabel="Create planner"
      contentClassName="max-w-lg max-h-[calc(100dvh-2rem)] sm:max-h-[calc(100dvh-4rem)] overflow-hidden flex flex-col min-h-0"
    >
      <CreatePlannerForm
        formData={formData}
        onFormDataChange={handleFormDataChange}
        totalVerses={totalVerses}
        versesPerDay={versesPerDay}
        isValidRange={isValidRange}
        canSubmit={canSubmit}
        duplicatePlanName={duplicatePlanName}
        onSubmit={handleSubmit}
        chapters={chapters}
        onClose={handleClose}
      />
    </UnifiedModal>
  );
};

function useDuplicatePlanName(
  formData: PlanFormData,
  chapters: Chapter[],
  planner: Record<string, PlannerPlan>,
  planDefinitions: ReturnType<typeof buildPlannerPlanDefinitions>
): string | null {
  return React.useMemo(() => {
    if (planDefinitions.length === 0) return null;

    const trimmedInputName = formData.planName.trim();
    if (trimmedInputName.length === 0) return null;
    const normalizedInput = trimmedInputName.toLowerCase();

    const hasConflict = Object.values(planner).some((plan) => {
      const rawName = plan.notes?.trim();
      if (!rawName) return false;
      let normalizedExisting = rawName.toLowerCase();

      const chapter = chapters.find((c) => c.id === plan.surahId);
      const chapterName = chapter?.name_simple?.trim();
      if (chapterName) {
        const suffix = ` - ${chapterName}`.toLowerCase();
        if (normalizedExisting.endsWith(suffix)) {
          normalizedExisting = normalizedExisting
            .slice(0, normalizedExisting.length - suffix.length)
            .trim();
        }
      }

      return normalizedExisting === normalizedInput;
    });

    return hasConflict ? trimmedInputName : null;
  }, [planDefinitions, formData.planName, planner, chapters]);
}

function useCloseHandler(resetForm: () => void, onClose: () => void): () => void {
  return React.useCallback(() => {
    resetForm();
    onClose();
  }, [resetForm, onClose]);
}

function CreatePlannerForm({
  formData,
  onFormDataChange,
  totalVerses,
  versesPerDay,
  isValidRange,
  canSubmit,
  duplicatePlanName,
  onSubmit,
  chapters,
  onClose,
}: {
  formData: PlanFormData;
  onFormDataChange: (updates: Partial<PlanFormData>) => void;
  totalVerses: number;
  versesPerDay: number;
  isValidRange: boolean;
  canSubmit: boolean;
  duplicatePlanName: string | null;
  onSubmit: (e: React.FormEvent) => void;
  chapters: Chapter[];
  onClose: () => void;
}): React.JSX.Element {
  const formId = React.useId();
  return (
    <div className="flex min-h-0 flex-col px-3 sm:px-4 pt-4 pb-4">
      <div className="flex items-start justify-between gap-4 shrink-0">
        <ModalHeader />
        <button
          type="button"
          onClick={onClose}
          aria-label="Close planner modal"
          className="shrink-0 p-1.5 rounded-full hover:bg-interactive-hover transition-colors flex items-center justify-center text-muted hover:text-foreground"
        >
          <CloseIcon size={18} />
        </button>
      </div>

      <div className="flex-1 min-h-0 overflow-y-auto overscroll-contain touch-pan-y scrollbar-hide pr-1">
        <PlannerForm
          formData={formData}
          onFormDataChange={onFormDataChange}
          totalVerses={totalVerses}
          versesPerDay={versesPerDay}
          isValidRange={isValidRange}
          canSubmit={canSubmit}
          {...(duplicatePlanName ? { duplicatePlanName } : {})}
          onSubmit={onSubmit}
          chapters={chapters}
          formId={formId}
          showActions={false}
        />
      </div>

      <div className="shrink-0">
        <FormActions canSubmit={canSubmit} formId={formId} />
      </div>
    </div>
  );
}

'use client';

import React, { useCallback, useMemo } from 'react';

import { SurahVerseSelector } from '@/app/shared/components/SurahVerseSelector';

import type { PlanFormData } from '@/app/(features)/bookmarks/components/create-planner-modal/types';
import type { Chapter } from '@/types';

interface SurahSelectionSectionProps {
  formData: PlanFormData;
  onFormDataChange: (updates: Partial<PlanFormData>) => void;
  chapters: Chapter[];
}

const clampVerseToChapter = (
  verse: number | undefined,
  chapter: Chapter,
  fallback: number
): number => {
  const maxVerse = chapter.verses_count;
  if (!maxVerse || maxVerse <= 0) return fallback;
  if (typeof verse !== 'number' || !Number.isFinite(verse) || verse < 1) return fallback;
  if (verse > maxVerse) return maxVerse;
  return verse;
};

export const SurahSelectionSection = ({
  formData,
  onFormDataChange,
  chapters,
}: SurahSelectionSectionProps): React.JSX.Element => {
  const chapterLookup = useMemo(() => {
    return chapters.reduce<Record<number, Chapter>>((acc, chapter) => {
      acc[chapter.id] = chapter;
      return acc;
    }, {});
  }, [chapters]);

  const handleStartSurahChange = useCallback(
    (nextSurah: number | undefined) => {
      const chapter = nextSurah ? chapterLookup[nextSurah] : undefined;
      const updates: Partial<PlanFormData> = { startSurah: nextSurah };
      if (!chapter) {
        updates.startVerse = undefined;
      } else {
        updates.startVerse = clampVerseToChapter(formData.startVerse, chapter, 1);
      }
      onFormDataChange(updates);
    },
    [chapterLookup, formData.startVerse, onFormDataChange]
  );

  const handleEndSurahChange = useCallback(
    (nextSurah: number | undefined) => {
      const chapter = nextSurah ? chapterLookup[nextSurah] : undefined;
      const updates: Partial<PlanFormData> = { endSurah: nextSurah };
      if (!chapter) {
        updates.endVerse = undefined;
      } else {
        updates.endVerse = clampVerseToChapter(
          formData.endVerse,
          chapter,
          chapter.verses_count ?? 1
        );
      }
      onFormDataChange(updates);
    },
    [chapterLookup, formData.endVerse, onFormDataChange]
  );

  const handleStartVerseChange = useCallback(
    (nextVerse: number | undefined) => {
      onFormDataChange({ startVerse: nextVerse });
    },
    [onFormDataChange]
  );

  const handleEndVerseChange = useCallback(
    (nextVerse: number | undefined) => {
      onFormDataChange({ endVerse: nextVerse });
    },
    [onFormDataChange]
  );

  return (
    <div className="space-y-4">
      <RangeBoundarySection
        label="Start"
        surahValue={formData.startSurah}
        verseValue={formData.startVerse}
        chapters={chapters}
        onSurahChange={handleStartSurahChange}
        onVerseChange={handleStartVerseChange}
      />

      <RangeBoundarySection
        label="End"
        surahValue={formData.endSurah}
        verseValue={formData.endVerse}
        chapters={chapters}
        onSurahChange={handleEndSurahChange}
        onVerseChange={handleEndVerseChange}
      />
    </div>
  );
};

interface RangeBoundarySectionProps {
  label: string;
  surahValue: number | undefined;
  verseValue: number | undefined;
  chapters: Chapter[];
  onSurahChange: (value: number | undefined) => void;
  onVerseChange: (value: number | undefined) => void;
}

const RangeBoundarySection = ({
  label,
  surahValue,
  verseValue,
  chapters,
  onSurahChange,
  onVerseChange,
}: RangeBoundarySectionProps): React.JSX.Element => {
  return (
    <section>
      <SurahVerseSelector
        chapters={chapters}
        selectedSurah={surahValue}
        selectedVerse={verseValue}
        onSurahChange={onSurahChange}
        onVerseChange={onVerseChange}
        surahLabel={`${label} Surah`}
        verseLabel="Verse"
      />
    </section>
  );
};

'use client';

import { useMemo, useState } from 'react';

import type { PlanFormData } from './types';
import type { Chapter } from '@/types';

// Custom hook for planner calculations
const clampVerse = (verse: number | undefined, maxVerse: number, fallback: number): number => {
  if (maxVerse <= 0) return fallback;
  if (typeof verse !== 'number' || !Number.isFinite(verse) || verse < 1) {
    return fallback;
  }
  if (verse > maxVerse) return maxVerse;
  return verse;
};

export function usePlannerCalculations(
  chapters: Chapter[],
  startSurah?: number,
  startVerse?: number,
  endSurah?: number,
  endVerse?: number,
  estimatedDays: number = 5
): { totalVerses: number; versesPerDay: number; isValidRange: boolean } {
  const chapterLookup = useMemo(() => {
    return chapters.reduce<Record<number, Chapter>>((acc, chapter) => {
      acc[chapter.id] = chapter;
      return acc;
    }, {});
  }, [chapters]);

  const startChapter = typeof startSurah === 'number' ? chapterLookup[startSurah] : undefined;
  const endChapter = typeof endSurah === 'number' ? chapterLookup[endSurah] : undefined;

  const normalizedStartVerse =
    startChapter?.verses_count != null
      ? clampVerse(startVerse, startChapter.verses_count, 1)
      : undefined;
  const normalizedEndVerse =
    endChapter?.verses_count != null && endChapter.verses_count > 0
      ? clampVerse(endVerse, endChapter.verses_count, endChapter.verses_count)
      : undefined;

  const calculateTotalVerses = (): number => {
    if (
      typeof startSurah !== 'number' ||
      typeof endSurah !== 'number' ||
      startSurah > endSurah ||
      !startChapter ||
      !endChapter ||
      typeof normalizedStartVerse !== 'number' ||
      typeof normalizedEndVerse !== 'number'
    ) {
      return 0;
    }

    if (startSurah === endSurah) {
      if (normalizedStartVerse > normalizedEndVerse) return 0;
      return normalizedEndVerse - normalizedStartVerse + 1;
    }

    let total = 0;
    total += startChapter.verses_count - (normalizedStartVerse - 1);
    total += normalizedEndVerse;

    for (let surahId = startSurah + 1; surahId < endSurah; surahId++) {
      const chapter = chapterLookup[surahId];
      if (chapter) {
        total += chapter.verses_count;
      }
    }

    return total;
  };

  const totalVerses = calculateTotalVerses();
  const versesPerDay = estimatedDays > 0 ? Math.ceil(totalVerses / estimatedDays) : 0;
  const isValidRange =
    typeof startSurah === 'number' &&
    typeof endSurah === 'number' &&
    startSurah <= endSurah &&
    !!startChapter &&
    !!endChapter &&
    (startSurah !== endSurah ||
      (typeof normalizedStartVerse === 'number' &&
        typeof normalizedEndVerse === 'number' &&
        normalizedStartVerse <= normalizedEndVerse));

  return {
    totalVerses,
    versesPerDay,
    isValidRange,
  };
}

// Helper hook for form state management
export function useFormState(): {
  formData: PlanFormData;
  handleFormDataChange: (updates: Partial<PlanFormData>) => void;
  resetForm: () => void;
} {
  const [formData, setFormData] = useState<PlanFormData>({
    planName: '',
    startSurah: undefined,
    startVerse: undefined,
    endSurah: undefined,
    endVerse: undefined,
    estimatedDays: 5,
  });

  const handleFormDataChange = (updates: Partial<PlanFormData>): void => {
    setFormData((prev) => ({ ...prev, ...updates }));
  };

  const resetForm = (): void => {
    setFormData({
      planName: '',
      startSurah: undefined,
      startVerse: undefined,
      endSurah: undefined,
      endVerse: undefined,
      estimatedDays: 5,
    });
  };

  return { formData, handleFormDataChange, resetForm };
}

import type { PlanFormData } from './types';
import type { Chapter } from '@/types';

export interface PlannerPlanDefinition {
  surahId: number;
  planName: string;
  versesCount: number;
  startVerse: number;
  endVerse: number;
}

const clampVerse = (chapter: Chapter, verse: number | undefined, fallback: number): number => {
  const max = chapter.verses_count ?? 0;
  if (max <= 0) return fallback;
  if (typeof verse !== 'number' || !Number.isFinite(verse) || verse < 1) {
    return fallback;
  }
  if (verse > max) return max;
  return verse;
};

const pushDefinition = (
  definitions: PlannerPlanDefinition[],
  chapter: Chapter,
  planName: string,
  rangeStart: number,
  rangeEnd: number
): void => {
  const max = chapter.verses_count ?? 0;
  if (max <= 0) return;
  const safeStart = Math.max(1, rangeStart);
  const safeEnd = Math.max(safeStart, Math.min(rangeEnd, max));
  const versesCount = safeEnd - safeStart + 1;
  if (versesCount <= 0) return;

  definitions.push({
    surahId: chapter.id,
    planName,
    versesCount,
    startVerse: safeStart,
    endVerse: safeEnd,
  });
};

export const buildPlannerPlanDefinitions = (
  formData: PlanFormData,
  chapters: Chapter[]
): PlannerPlanDefinition[] => {
  const { startSurah, startVerse, endSurah, endVerse } = formData;
  const trimmedBaseName = formData.planName.trim();

  if (!startSurah || !endSurah || startSurah > endSurah || trimmedBaseName.length === 0) {
    return [];
  }

  const startChapter = chapters.find((c) => c.id === startSurah);
  const endChapter = chapters.find((c) => c.id === endSurah);
  if (!startChapter || !endChapter) return [];

  const normalizedStartVerse = clampVerse(startChapter, startVerse, 1);
  const normalizedEndVerse = clampVerse(endChapter, endVerse, endChapter.verses_count ?? 1);

  if (startSurah === endSurah) {
    if (normalizedStartVerse > normalizedEndVerse) return [];
    const definitions: PlannerPlanDefinition[] = [];
    pushDefinition(
      definitions,
      startChapter,
      trimmedBaseName,
      normalizedStartVerse,
      normalizedEndVerse
    );
    return definitions;
  }

  const definitions: PlannerPlanDefinition[] = [];
  pushDefinition(
    definitions,
    startChapter,
    trimmedBaseName,
    normalizedStartVerse,
    startChapter.verses_count ?? normalizedStartVerse
  );

  for (let surahId = startSurah + 1; surahId < endSurah; surahId++) {
    const chapter = chapters.find((c) => c.id === surahId);
    if (!chapter) continue;
    pushDefinition(definitions, chapter, trimmedBaseName, 1, chapter.verses_count ?? 1);
  }

  pushDefinition(definitions, endChapter, trimmedBaseName, 1, normalizedEndVerse);

  return definitions;
};

// Helper function to create planner plans for a range of surahs
export function createPlannerPlansForRange(
  formData: PlanFormData,
  chapters: Chapter[],
  createPlannerPlan: (
    surahId: number,
    versesCount: number,
    planName: string,
    estimatedDays?: number,
    options?: { startVerse?: number; endVerse?: number }
  ) => void
): void {
  const definitions = buildPlannerPlanDefinitions(formData, chapters);
  if (definitions.length === 0) return;

  for (const definition of definitions) {
    createPlannerPlan(
      definition.surahId,
      definition.versesCount,
      definition.planName,
      formData.estimatedDays,
      {
        startVerse: definition.startVerse,
        endVerse: definition.endVerse,
      }
    );
  }
}

'use client';

import Link from 'next/link';
import React from 'react';

import { colors } from '@/app/shared/design-system/card-tokens';
import { FolderGlyph } from '@/app/shared/ui/cards/FolderGlyph';
import { cn } from '@/lib/utils/cn';
import { Bookmark, Folder } from '@/types';

interface FolderHeaderProps {
  folderItem: Folder;
  isCurrentFolder: boolean;
  folderBookmarks: Bookmark[];
  onToggle: (folderId: string) => void;
  href: string;
  className?: string;
  showDivider?: boolean;
}

interface FolderIconProps {
  folderItem: Folder;
}

interface FolderInfoProps {
  folderItem: Folder;
  folderBookmarks: Bookmark[];
  isCurrentFolder: boolean;
}

const FolderIconDisplay = ({ folderItem }: FolderIconProps): React.JSX.Element => (
  <FolderGlyph
    folder={folderItem}
    size="lg"
    backgroundOpacity={0.95}
    shadowOpacity={0.25}
    shadowOverride="0 12px 28px -18px"
  />
);

const FolderInfo = ({
  folderItem,
  folderBookmarks,
  isCurrentFolder,
}: FolderInfoProps): React.JSX.Element => {
  const verseCount = `${folderBookmarks.length} ${
    folderBookmarks.length === 1 ? 'verse' : 'verses'
  }`;

  return (
    <div className="min-w-0 flex flex-col gap-1">
      <p
        className={cn(
          'line-clamp-2 text-[1.08rem] leading-[1.1] font-semibold transition-colors duration-200',
          isCurrentFolder ? colors.text.accent : `${colors.text.primary} ${colors.text.hoverAccent}`
        )}
      >
        {folderItem.name}
      </p>
      <p
        className={cn(
          'text-sm leading-[1.1] font-medium transition-colors duration-200',
          colors.text.secondary
        )}
      >
        {verseCount}
      </p>
    </div>
  );
};

export const FolderHeader = ({
  folderItem,
  isCurrentFolder,
  folderBookmarks,
  onToggle,
  href,
  className,
  showDivider = false,
}: FolderHeaderProps): React.JSX.Element => {
  // If already on the current folder, clicking toggles expand/collapse
  // Otherwise, navigation is handled by the Link
  const handleClick = (e: React.MouseEvent): void => {
    if (isCurrentFolder) {
      e.preventDefault();
      onToggle(folderItem.id);
    }
    // Let Link handle navigation for non-current folders
  };

  const handleKeyDown = (e: React.KeyboardEvent): void => {
    if (e.key === 'Enter' || e.key === ' ') {
      if (isCurrentFolder) {
        e.preventDefault();
        onToggle(folderItem.id);
      }
      // Let Link handle navigation for non-current folders
    }
  };

  const content = (
    <>
      <div className="flex items-center gap-4 flex-1 min-w-0">
        <FolderIconDisplay folderItem={folderItem} />
        <FolderInfo
          folderItem={folderItem}
          folderBookmarks={folderBookmarks}
          isCurrentFolder={isCurrentFolder}
        />
      </div>
      {showDivider ? (
        <div className="absolute bottom-0 left-4 right-4 h-px bg-border transition-opacity duration-200" />
      ) : null}
    </>
  );

  const sharedClassName = cn(
    'relative flex w-full min-h-[80px] items-center gap-4 cursor-pointer px-4 py-4 transition-colors duration-200 focus:outline-none focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-border/40 focus-visible:ring-offset-0',
    className
  );

  return (
    <Link
      href={href}
      prefetch={true}
      scroll={false}
      className={sharedClassName}
      onClick={handleClick}
      onKeyDown={handleKeyDown}
      aria-label={
        isCurrentFolder ? `Toggle folder ${folderItem.name}` : `Open folder ${folderItem.name}`
      }
    >
      {content}
    </Link>
  );
};

'use client';

import { useRouter } from 'next/navigation';
import React from 'react';

import { CircularProgress } from '@/app/(features)/bookmarks/components/CircularProgress';
import { CloseIcon } from '@/app/shared/icons';
import { buildSurahRoute } from '@/app/shared/navigation/routes';
import { Chapter } from '@/types';

interface LastReadCardProps {
  surahId: string;
  verseId: number;
  chapter?: Chapter;
  index: number;
  onRemove: () => void;
}

export const LastReadCard = ({
  surahId,
  verseId,
  chapter,
  index,
  onRemove,
}: LastReadCardProps): React.JSX.Element => {
  const router = useRouter();
  const total = chapter?.verses_count || 0;
  const percent = Math.min(100, Math.max(0, Math.round((verseId / total) * 100)));
  const isVisible = useMountVisible();
  const handleNavigate = React.useCallback((): void => {
    router.push(buildSurahRoute(surahId, { startVerse: verseId, forceSeq: true }), {
      scroll: false,
    });
  }, [router, surahId, verseId]);

  const handleRemove = React.useCallback(
    (e: React.MouseEvent) => {
      e.stopPropagation();
      onRemove();
    },
    [onRemove]
  );

  const ariaLabel = `Continue reading ${chapter?.name_simple || `Surah ${surahId}`} at verse ${verseId}`;

  return (
    <CardContainer
      ariaLabel={ariaLabel}
      onActivate={handleNavigate}
      isVisible={isVisible}
      index={index}
    >
      <button
        onClick={handleRemove}
        className="group absolute top-0.5 right-0.5 min-h-touch min-w-touch touch-manipulation grid place-items-center rounded-full opacity-100 sm:opacity-0 sm:group-hover:opacity-100 focus:opacity-100 focus:outline-none z-10"
        aria-label="Remove from recent"
        title="Remove"
      >
        <span className="rounded-full p-1.5 text-muted transition-colors group-hover:bg-red-500/10 group-hover:text-red-500 group-focus-visible:bg-red-500/10 group-focus-visible:text-red-500">
          <CloseIcon size={16} />
        </span>
      </button>

      <div className="flex w-full flex-1 items-center justify-center">
        <CircularProgress
          percentage={percent}
          label="Completed"
          size={100}
          strokeWidth={10}
          valueClassName="text-sm sm:text-base"
          labelClassName="text-[10px]"
        />
      </div>
      <div className="mt-4">
        <p className="text-sm sm:text-base font-bold text-foreground truncate">
          {chapter?.name_simple || `Surah ${surahId}`}
        </p>
        <p className="text-[11px] sm:text-xs text-muted mt-1">
          Verse {verseId} of {total}
        </p>
      </div>
    </CardContainer>
  );
};

function CardContainer({
  ariaLabel,
  onActivate,
  isVisible,
  index,
  children,
}: {
  ariaLabel: string;
  onActivate: () => void;
  isVisible: boolean;
  index: number;
  children: React.ReactNode;
}): React.JSX.Element {
  const onKeyDown = (e: React.KeyboardEvent): void => {
    if (e.key === 'Enter') onActivate();
  };
  return (
    <div
      role="button"
      tabIndex={0}
      aria-label={ariaLabel}
      onClick={onActivate}
      onKeyDown={onKeyDown}
      className={`group relative flex h-full min-h-[10rem] sm:min-h-[11rem] lg:min-h-[12rem] w-full transform flex-col items-center justify-between rounded-lg border border-border/50 bg-surface p-3 sm:p-4 lg:p-5 text-center shadow-lg transition-[transform,opacity] duration-300 ease-out active:scale-95 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-accent ${
        isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'
      }`}
      style={{ transitionDelay: `${Math.min(index, 10) * 100}ms` }}
    >
      {children}
    </div>
  );
}

function useMountVisible(): boolean {
  const [isVisible, setIsVisible] = React.useState(false);
  React.useEffect(() => setIsVisible(true), []);
  return isVisible;
}

import { redirect } from 'next/navigation';

