'use client';

import { memo, useState, useEffect, useRef, useMemo } from 'react';

import { cleanTranslationText } from '@/lib/text/cleanTranslationText';

import type { Chapter, Verse } from '@/types';

// Renamed from VerseOfDaySimple
interface VerseOfDayProps {
  /** Pre-fetched verses from server (up to 5) */
  verses: readonly Verse[];
  /** Pre-fetched chapters for name lookup */
  chapters: ReadonlyArray<Chapter>;
  className?: string;
}

/**
 * Optimized Verse of the Day component.
 *
 * Features:
 * - Uses preloaded UthmanicHafs font (instant LCP)
 * - Simple 10-second rotation between pre-fetched verses
 * - Only rotates when component is mounted (homepage visible)
 * - No loading states - content is always available from SSG
 * - Minimal client-side logic for best performance
 */
export const VerseOfDay = memo(function VerseOfDay({
  verses,
  chapters,
  className,
}: VerseOfDayProps) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const hasVerses = verses && verses.length > 0;
  const versesLength = verses?.length ?? 0;

  const chapterNameById = useMemo(() => {
    const map = new Map<number, string>();
    for (const chapter of chapters) {
      map.set(chapter.id, chapter.name_simple);
    }
    return map;
  }, [chapters]);

  // Rotate verse every 15 seconds
  useEffect(() => {
    if (!hasVerses || versesLength <= 1) return;

    timerRef.current = setInterval(() => {
      setIsTransitioning(true);

      // After fade-out, change verse
      setTimeout(() => {
        setCurrentIndex((prev) => (prev + 1) % versesLength);
        setIsTransitioning(false);
      }, 300);
    }, 15000);

    return () => {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    };
  }, [hasVerses, versesLength]);

  // Memoize current verse data
  const verseData = useMemo(() => {
    if (!hasVerses) return null;
    const verse = verses[currentIndex];
    if (!verse) return null;

    const [surahNum, ayahNum] = verse.verse_key.split(':');
    const sahihTranslation = verse.translations?.find((t) => t.resource_id === 20)?.text;
    return {
      text: verse.text_uthmani,
      translation: sahihTranslation ?? verse.translations?.[0]?.text,
      surahNum,
      ayahNum,
    };
  }, [hasVerses, verses, currentIndex]);

  // Don't render if no verses available
  if (!verseData) {
    return null;
  }

  // Remove unwanted marks like "Small High Rounded Zero" (0x06DF) which renders as a large circle in this font
  const cleanArabicText = verseData.text.replace(/[\u06df\u06e0]/g, '');
  const referenceChapterName =
    chapterNameById.get(Number(verseData.surahNum)) ?? `Surah ${verseData.surahNum}`;
  const referenceText = `${referenceChapterName} ${verseData.surahNum}:${verseData.ayahNum}`;
  const cleanedTranslation = verseData.translation
    ? cleanTranslationText(verseData.translation)
    : null;

  return (
    <div
      className={`w-full p-4 md:p-6 lg:p-8 rounded-2xl shadow-lg bg-surface-navigation border border-border/30 dark:border-border/20 min-h-[180px] ${className || ''}`}
    >
      <div
        className={`transition-opacity duration-300 ease-in-out space-y-4 ${isTransitioning ? 'opacity-0' : 'opacity-100'}`}
      >
        {/* Arabic text - uses preloaded UthmanicHafs font */}
        <h3
          className="text-2xl md:text-3xl lg:text-4xl leading-relaxed text-right text-content-accent"
          dir="rtl"
          style={{ fontFamily: 'UthmanicHafs1Ver18, Arial, sans-serif' }}
        >
          {cleanArabicText}
        </h3>

        {/* Translation - uses system font */}
        {cleanedTranslation && (
          <p className="text-left text-sm md:text-base text-content-secondary">
            &quot;{cleanedTranslation}&quot; - [{referenceText}]
          </p>
        )}
      </div>
    </div>
  );
});

'use client';

import { useCallback, useState } from 'react';
import useSWR from 'swr';

import { getRandomVerse } from '@/lib/api';
import { logger } from '@/src/infrastructure/monitoring/Logger';
import { Verse } from '@/types';

export const RETRY_LIMIT = 3;
const SWR_OPTIONS = {
  revalidateOnFocus: false,
  revalidateOnReconnect: false,
  shouldRetryOnError: false,
  dedupingInterval: 30000, // Don't refetch for 30 seconds
} as const;

interface UseRandomVerseOptions {
  translationId: number;
  onError?: (error: Error) => void;
}

interface UseRandomVerseReturn {
  verse: Verse | null;
  loading: boolean;
  error: string | null;
  refresh: () => void;
  isAvailable: boolean;
}

type RandomVerseAvailability = {
  isAvailable: boolean;
  lastError: string | null;
  markAvailable: () => void;
  markUnavailable: (error: Error) => void;
  requestRetry: (onAvailable: () => void) => void;
};

type RandomVerseFetcher = () => Promise<Verse>;

/**
 * Hook for fetching random verses from the API
 * Handles graceful fallback when random API is unavailable
 */
export function useRandomVerse({
  translationId,
  onError,
}: UseRandomVerseOptions): UseRandomVerseReturn {
  const { isAvailable, lastError, markAvailable, markUnavailable, requestRetry } =
    useRandomVerseAvailability(onError, shouldPreferRemoteRandomVerse());
  const fetchRandomVerse = useRandomVerseFetcher(translationId, markAvailable, markUnavailable);

  const {
    data: verse,
    error: swrError,
    mutate,
  } = useSWR(isAvailable ? ['random-verse', translationId] : null, fetchRandomVerse, SWR_OPTIONS);

  const refresh = useCallback(() => {
    requestRetry(() => {
      void mutate();
    });
  }, [mutate, requestRetry]);

  const errorMessage = swrError ? 'Unable to connect to Quran service' : lastError;

  return {
    verse: verse || null,
    loading: isAvailable && !verse && !swrError,
    error: errorMessage,
    refresh,
    isAvailable,
  };
}

function shouldPreferRemoteRandomVerse(): boolean {
  const enableRandomVerseEnv = process.env['NEXT_PUBLIC_ENABLE_RANDOM_VERSE_API'];

  if (enableRandomVerseEnv === 'true') {
    return true;
  }
  if (enableRandomVerseEnv === 'false') {
    return false;
  }
  return process.env.NODE_ENV === 'production';
}

function useRandomVerseAvailability(
  onError: ((error: Error) => void) | undefined,
  preferRemote: boolean
): RandomVerseAvailability {
  const [isAvailable, setIsAvailable] = useState(preferRemote);
  const [, setRetryCount] = useState(0);
  const [lastError, setLastError] = useState<string | null>(null);

  const markAvailable = useCallback(() => {
    setRetryCount(0);
    setIsAvailable(true);
    setLastError(null);
  }, [setRetryCount, setIsAvailable, setLastError]);

  const markUnavailable = useCallback(
    (error: Error) => {
      setIsAvailable(false);
      setRetryCount(0);
      setLastError('Unable to connect to Quran service');
      onError?.(error);
    },
    [onError, setIsAvailable, setLastError, setRetryCount]
  );

  const requestRetry = useCallback(
    (onAvailable: () => void) => {
      if (!isAvailable) {
        setRetryCount((count) => {
          const next = count + 1;
          if (next >= RETRY_LIMIT) {
            setIsAvailable(true);
            setLastError(null);
            return 0;
          }
          return next;
        });
        return;
      }

      onAvailable();
    },
    [isAvailable, setIsAvailable, setLastError, setRetryCount]
  );

  return { isAvailable, lastError, markAvailable, markUnavailable, requestRetry };
}

function useRandomVerseFetcher(
  translationId: number,
  markAvailable: () => void,
  markUnavailable: (error: Error) => void
): RandomVerseFetcher {
  return useCallback(async (): Promise<Verse> => {
    try {
      const verseData = await getRandomVerse(translationId);
      markAvailable();
      return verseData;
    } catch (error) {
      const handledError = error instanceof Error ? error : new Error('Random verse fetch failed');
      logger.warn('Random verse API failed', undefined, handledError);
      markUnavailable(handledError);
      throw handledError;
    }
  }, [translationId, markAvailable, markUnavailable]);
}

