  getPageFontFamily: (pageNumber: number) => string;
  isPageFontLoaded: (pageNumber: number) => boolean;
  settings: ReaderSettings;
};

type PageFontInfo = { fontFamily: string; isFontLoaded: boolean };

const resolvePageFont = ({
  pageNumber,
  mushafFlags,
  getPageFontFamily,
  isPageFontLoaded,
  settings,
}: PageFontInfoArgs): PageFontInfo => {
  const pageFontLoaded =
    mushafFlags.isQcfMushaf && typeof pageNumber === 'number' && isPageFontLoaded(pageNumber);

  if (mushafFlags.isQcfMushaf && pageFontLoaded && typeof pageNumber === 'number') {
    return {
      fontFamily: getPageFontFamily(pageNumber),
      isFontLoaded: true,
    };
  }

  if (mushafFlags.isQpcHafsMushaf) {
    return { fontFamily: 'UthmanicHafs1Ver18', isFontLoaded: true };
  }

  if (mushafFlags.isIndopakMushaf) {
    return { fontFamily: 'IndoPak', isFontLoaded: true };
  }

  return {
    fontFamily: settings.arabicFontFace,
    isFontLoaded: !mushafFlags.isQcfMushaf || pageFontLoaded,
  };
};

const INCREASE_VIEWPORT_BY_PIXELS = 2000; // Increased buffer for smoother measurement
const QCF_VISIBLE_BUFFER_PAGES = 2;

const resolveFirstPageNumber = (pages: Record<number, PagesLookupRecord>): number | null => {
  const keys = Object.keys(pages ?? {});
  const numericKeys = keys
    .map((key) => Number.parseInt(key, 10))
    .filter((value) => Number.isFinite(value));

  if (!numericKeys.length) return null;
  return Math.min(...numericKeys);
};

const clampIndex = (value: number, max: number): number => Math.min(Math.max(0, value), max);

const toVerseSortValue = (verseKey?: string): number | null => {
  if (!verseKey) return null;
  const [chapterRaw, ayahRaw] = verseKey.split(':');
  const chapter = Number.parseInt(chapterRaw ?? '', 10);
  const ayah = Number.parseInt(ayahRaw ?? '', 10);
  if (Number.isFinite(chapter) && Number.isFinite(ayah)) {
    return chapter * 1000 + ayah;
  }
  if (Number.isFinite(ayah)) {
    return ayah;
  }
  return null;
};

const resolvePageNumberForVerseKey = (
  verseKey: string,
  pages: Record<number, PagesLookupRecord>
): number | null => {
  const targetValue = toVerseSortValue(verseKey);
  if (targetValue === null) return null;

  const pageNumbers = Object.keys(pages ?? {})
    .map((key) => Number.parseInt(key, 10))
    .filter((value) => Number.isFinite(value))
    .sort((a, b) => a - b);

  for (const pageNumber of pageNumbers) {
    const record = pages[pageNumber];
    const fromValue = toVerseSortValue(record?.from);
    const toValue = toVerseSortValue(record?.to);
    if (fromValue === null || toValue === null) continue;
    if (targetValue >= fromValue && targetValue <= toValue) {
      return pageNumber;
    }
  }

  return null;
};

const MushafEndOfList = ({ surahId }: { surahId?: number | undefined }): React.JSX.Element => (
  <div className="py-10 text-center space-y-6">
    {surahId ? <SurahNavigation currentSurahId={surahId} /> : null}
  </div>
);

const MushafPageError = ({ message }: { message: string }): React.JSX.Element => (
  <div className="mx-auto w-full rounded-[32px] border border-status-error bg-status-error/10 px-6 py-10 text-center text-status-error">
    {message}
  </div>
);

const MushafVirtualizedPageRow = ({
  pageNumber,
  verseRange,
  mushafId,
  reciterId,
  wordByWordLocale,
  translationIds,
  settings,
  mushafFlags,
  getPageFontFamily,
  isPageFontLoaded,
  className,
  estimatedHeight,
  isMobile,
}: {
  pageNumber: number;
  verseRange: { from: string; to: string } | undefined;
  mushafId: string;
  reciterId?: number | undefined;
  wordByWordLocale?: string | undefined;
  translationIds?: string | undefined;
  settings: ReaderSettings;
  mushafFlags: MushafFlags;
  getPageFontFamily: (pageNumber: number) => string;
  isPageFontLoaded: (pageNumber: number) => boolean;
  className?: string;
  estimatedHeight: number;
  isMobile: boolean;
}): React.JSX.Element => {
  const { page, isLoading, error } = useDedupedFetchMushafPage({
    pageNumber,
    mushafId,
    ...(typeof reciterId === 'number' ? { reciterId } : {}),
    ...(wordByWordLocale ? { wordByWordLocale } : {}),
    ...(translationIds ? { translationIds } : {}),
    ...(verseRange ? { verseRange } : {}),
  });

  const { fontFamily, isFontLoaded } = resolvePageFont({
    pageNumber,
    mushafFlags,
    getPageFontFamily,
    isPageFontLoaded,
    settings,
  });

  if (error) {
    return <MushafPageError message={error} />;
  }

  if (isLoading || !page || (mushafFlags.isQcfMushaf && !isFontLoaded)) {
    return <MushafPageSkeleton index={pageNumber} minHeight={estimatedHeight} />;
  }

  return (
    <MushafPage
      pageNumber={page.pageNumber}
      lines={page.lines}
      settings={settings}
      fontFamily={fontFamily}
      isQcfMushaf={mushafFlags.isQcfMushaf}
      isQpcHafsMushaf={mushafFlags.isQpcHafsMushaf}
      isIndopakMushaf={mushafFlags.isIndopakMushaf}
      qcfVersion={mushafFlags.qcfVersion}
      isFontLoaded={isFontLoaded}
      {...(className ? { className } : {})}
      isMobile={isMobile}
    />
  );
};

type MushafPageListProps = {
  resourceId: string;
  resourceKind: MushafResourceKind;
  mushafId: string;
  initialPageNumber?: number | undefined;
  initialVerseKey?: string | undefined;
  chapterId?: number | null | undefined;
  juzNumber?: number | null | undefined;
  reciterId?: number | undefined;
  wordByWordLocale?: string | undefined;
  translationIds?: string | undefined;
  settings: ReaderSettings;
  mushafFlags: MushafFlags;
  endLabel: string;
  surahId?: number | undefined;
};

export const MushafPageList = ({
  resourceId,
  resourceKind,
  mushafId,
  initialPageNumber,
  initialVerseKey,
  reciterId,
  wordByWordLocale,
  translationIds,
  settings,
  mushafFlags,
  surahId,
}: MushafPageListProps): React.JSX.Element => {
  // Calculate height estimates based on font size
  // Font size directly affects page height - larger fonts = taller pages
  const fontScaleFactor = settings.arabicFontSize / DEFAULT_ARABIC_FONT_SIZE;
  const scaledDesktopHeight = Math.round(MUSHAF_PAGE_HEIGHT_DESKTOP_BASE * fontScaleFactor);
  const scaledMobileHeight = Math.round(MUSHAF_PAGE_HEIGHT_MOBILE_BASE * fontScaleFactor);

  // Detect mobile viewport to adjust height estimate
  const [isMobile, setIsMobile] = useState(false);
  const [estimatedHeight, setEstimatedHeight] = useState(scaledDesktopHeight);

  useEffect(() => {
    const checkMobile = () => {
      // 640px is standard Tailwind sm breakpoint
      const mobile = window.innerWidth < 640;
      setIsMobile(mobile);
      setEstimatedHeight(mobile ? scaledMobileHeight : scaledDesktopHeight);
    };

    // Check on mount
    checkMobile();

    // Check on resize
    window.addEventListener('resize', checkMobile);
    return () => window.removeEventListener('resize', checkMobile);
  }, [scaledMobileHeight, scaledDesktopHeight]);

  const {
    data: lookupData,
    isLoading,
    error,
  } = useMushafPagesLookup({
    resourceId,
    resourceKind,
    mushafId,
  });

  const firstPageNumber = useMemo(
    () => (lookupData ? resolveFirstPageNumber(lookupData.pages) : null),
    [lookupData]
  );
  const totalPages = lookupData?.totalPage ?? 0;

  const [visibleRange, setVisibleRange] = useState<{ startIndex: number; endIndex: number }>({
    startIndex: 0,
    endIndex: 0,
  });

  const qcfFontPageNumbers = useMemo(() => {
    if (!mushafFlags.isQcfMushaf) return [];
    if (!firstPageNumber || totalPages <= 0) return [];

    const maxIndex = totalPages - 1;
    const startIndex = clampIndex(visibleRange.startIndex - QCF_VISIBLE_BUFFER_PAGES, maxIndex);
    const endIndex = clampIndex(visibleRange.endIndex + QCF_VISIBLE_BUFFER_PAGES, maxIndex);
    return Array.from(
      { length: endIndex - startIndex + 1 },
      (_value, idx) => firstPageNumber + startIndex + idx
    );
  }, [firstPageNumber, mushafFlags.isQcfMushaf, totalPages, visibleRange]);

  const { getPageFontFamily, isPageFontLoaded } = useQcfMushafFont(
    mushafFlags.isQcfMushaf ? qcfFontPageNumbers : [],
    mushafFlags.qcfVersion
  );

  const virtuosoRef = useRef<VirtuosoHandle>(null);
  const initialScrollToken = useMemo(
    () =>
      `${resourceKind}:${resourceId}:${mushafId}:${initialPageNumber ?? 'none'}:${initialVerseKey ?? 'no-verse'}`,
    [resourceKind, resourceId, mushafId, initialPageNumber, initialVerseKey]
  );
  const lastInitialScrollTokenRef = useRef<string | null>(null);

  useEffect(() => {
    if (!lookupData) return;
    if (!firstPageNumber) return;
    if (totalPages <= 0) return;

    if (lastInitialScrollTokenRef.current === initialScrollToken) return;
    lastInitialScrollTokenRef.current = initialScrollToken;

    const maxIndex = totalPages - 1;
    const pageNumberFromVerseKey =
      typeof initialVerseKey === 'string'
        ? resolvePageNumberForVerseKey(initialVerseKey, lookupData.pages)
        : null;
    const fallbackPageNumber =
      typeof initialPageNumber === 'number' ? initialPageNumber : firstPageNumber;
    const targetPageNumber = pageNumberFromVerseKey ?? fallbackPageNumber;
    const targetIndex = clampIndex(targetPageNumber - firstPageNumber, maxIndex);

    virtuosoRef.current?.scrollToIndex({ index: targetIndex, align: 'start', offset: -20 });
  }, [
    firstPageNumber,
    initialPageNumber,
    initialScrollToken,
    initialVerseKey,
    lookupData,
    totalPages,
  ]);

  if (isLoading) {
    return (
      <LoadingStatus className="space-y-8">
        <MushafPageSkeleton index={0} minHeight={estimatedHeight} />
        <MushafPageSkeleton index={1} minHeight={estimatedHeight} />
      </LoadingStatus>
    );
  }

  if (error) {
    return <MushafPageError message={error} />;
  }

  if (!lookupData || !firstPageNumber || totalPages <= 0) {
    return (
      <div className="py-16 text-center text-muted-foreground">
        No pages available for this selection.
      </div>
    );
  }

  return (
    <>
      <TajweedFontPalettes pageNumbers={qcfFontPageNumbers} version={mushafFlags.qcfVersion} />
      <Virtuoso
        ref={virtuosoRef}
        useWindowScroll
        increaseViewportBy={INCREASE_VIEWPORT_BY_PIXELS}
        initialItemCount={1}
        totalCount={totalPages + 1}
        rangeChanged={setVisibleRange}
        // Provide default height estimate matching skeleton to reduce scroll jumps
        defaultItemHeight={estimatedHeight}
        computeItemKey={(index) =>
          index === totalPages
            ? `end:${resourceKind}:${resourceId}:${mushafId}`
            : `page:${firstPageNumber + index}`
        }
        itemContent={(index) => {
          const wrapperClassName = index === 0 ? undefined : 'mt-8';

          if (index === totalPages) {
            return (
              <div className={wrapperClassName}>
                <MushafEndOfList {...(surahId ? { surahId } : {})} />
              </div>
            );
          }

          const pageNumber = firstPageNumber + index;
          const verseRange = lookupData.pages[pageNumber];

          return (
            <div
              className={wrapperClassName}
              style={
                {
                  // Minimal containment to avoid interfering with Virtuoso's measurement
                  contain: 'layout',
                } as React.CSSProperties
              }
            >
              <MushafVirtualizedPageRow
                pageNumber={pageNumber}
                verseRange={verseRange ? { from: verseRange.from, to: verseRange.to } : undefined}
                mushafId={mushafId}
                {...(typeof reciterId === 'number' ? { reciterId } : {})}
                {...(wordByWordLocale ? { wordByWordLocale } : {})}
                {...(translationIds ? { translationIds } : {})}
                settings={settings}
                mushafFlags={mushafFlags}
                getPageFontFamily={getPageFontFamily}
                isPageFontLoaded={isPageFontLoaded}
                {...(index === 0 ? { className: 'pt-0 sm:pt-0' } : {})}
                estimatedHeight={estimatedHeight}
                isMobile={isMobile}
              />
            </div>
          );
        }}
      />
    </>
  );
};

import { MushafWordText } from './MushafWordText';

import type { ReaderSettings } from './MushafMain.types';
import type { QcfFontVersion } from '@/app/(features)/surah/hooks/useQcfMushafFont';
import type { MushafLineGroup, MushafWord } from '@/types';
import type React from 'react';

type MushafReflowContentProps = {
  lines: MushafLineGroup[];
  settings: ReaderSettings;
  isQcfMushaf: boolean;
  isQpcHafsMushaf: boolean;
  isIndopakMushaf: boolean;
  qcfVersion: QcfFontVersion;
  indopakVersion?: '15' | '16' | null | undefined;
  fontSize: string | number;
  fontFamily: string;
  isFontLoaded: boolean;
};

/**
 * MushafReflowContent - Mobile reflow mode component (quran.com style)
 *
 * Based on quran.com's approach: when text would overflow on mobile,
 * use centered text with words displayed inline. Words flow naturally
 * and wrap to fill the screen.
 */
export const MushafReflowContent = ({
  lines,
  settings,
  isQcfMushaf,
  isQpcHafsMushaf,
  isIndopakMushaf,
  qcfVersion,
  fontSize,
  fontFamily,
  isFontLoaded,
}: MushafReflowContentProps): React.JSX.Element => {
  // Flatten all words from all lines into a single array
  const allWords: { word: MushafWord; lineKey: string; index: number }[] = [];

  lines.forEach((line) => {
    line.words.forEach((word, index) => {
      allWords.push({ word, lineKey: line.key, index });
    });
  });

  return (
    <div
      dir="rtl"
      className="w-full"
      style={{
        fontFamily,
        fontSize: typeof fontSize === 'number' ? `${fontSize}px` : fontSize,
        // CSS containment for improved scroll performance on mobile
        contain: 'layout style',
      }}
    >
      {/* Container with centered text - like quran.com's .mobileCenterText */}
      <div
        className="leading-[1.8] mx-auto"
        style={{
          textAlign: 'center',
          direction: 'rtl',
        }}
        translate="no"
      >
        {allWords.map(({ word, lineKey, index }) => (
          <MushafWordText
            key={word.id ?? `${lineKey}-${word.verseKey ?? 'word'}-${word.position}-${index}`}
            word={word}
            settings={settings}
            isQcfMushaf={isQcfMushaf}
            isQpcHafsMushaf={isQpcHafsMushaf}
            isIndopakMushaf={isIndopakMushaf}
            qcfVersion={qcfVersion}
            isFontLoaded={isFontLoaded}
          />
        ))}
      </div>
    </div>
  );
};

import { HybridVerseMarker } from '@/app/shared/components/verse-marker/VerseMarker';
import { sanitizeHtml } from '@/lib/text/sanitizeHtml';
import { cn } from '@/lib/utils/cn';

import type { ReaderSettings } from './MushafMain.types';
import type { QcfFontVersion } from '@/app/(features)/surah/hooks/useQcfMushafFont';
import type { MushafWord } from '@/types';
import type React from 'react';

const getBaseText = (word: MushafWord, isIndopakMushaf: boolean): string =>
  isIndopakMushaf
    ? word.textIndopak || word.textUthmani || ''
    : word.textUthmani || word.textIndopak || '';

// For QCF mushafs, we strip ayah markers since they use special glyph codes
// For IndoPak and QPC Hafs, the font renders markers naturally - no stripping needed
const stripAyahMarkers = (text: string, isQcfMushaf: boolean): string => {
  if (!isQcfMushaf) {
    // IndoPak and QPC Hafs: keep the markers as the font renders them beautifully
    return text;
  }
  // QCF mushafs use glyph codes, so strip Unicode markers from text fallback
  return text.replace(/[\u06DF\u06DD]/g, '');
};

/**
 * Wraps U+06DF (Arabic Small High Rounded Zero - ۟) in a span with Scheherazade New font.
 * This is needed because UthmanicHafs1Ver18 doesn't have a glyph for this character,
 * causing it to render as a dotted circle. CSS unicode-range fallback doesn't work
 * for combining marks, so we need to explicitly wrap the character with a different font.
 */
const wrapUnsupportedGlyphs = (text: string, isQpcHafsMushaf: boolean): string => {
  if (!isQpcHafsMushaf) {
    return text;
  }
  // Replace U+06DF with a span that uses Scheherazade New
  // The span uses inline style to ensure the fallback font is used
  return text.replace(
    /\u06DF/g,
    '<span style="font-family: \'Scheherazade New\', serif;">۟</span>'
  );
};

// V4 (Tajweed) uses the same glyph codes as V2 (code_v2 field), with the COLRv1 color font
const getGlyphCode = (word: MushafWord, qcfVersion: QcfFontVersion): string | undefined =>
  qcfVersion === 'v2' || qcfVersion === 'v4' ? word.codeV2 : word.codeV1;

type WordHtmlArgs = {
  isQcfMushaf: boolean;
  isQpcHafsMushaf: boolean;
  isFontLoaded: boolean;
  settings: ReaderSettings;
  baseText: string;
  displayText: string;
  glyphCode?: string | undefined;
};

const buildWordHtml = ({
  isQcfMushaf,
  isQpcHafsMushaf,
  isFontLoaded,
  settings,
  baseText,
  displayText,
  glyphCode,
}: WordHtmlArgs): string => {
  if (isQcfMushaf && isFontLoaded && glyphCode) {
    return glyphCode;
  }

  if (isQpcHafsMushaf) {
    // Wrap unsupported glyphs (U+06DF) with fallback font for proper rendering
    return wrapUnsupportedGlyphs(displayText, true);
  }

  if (baseText) {
    return baseText;
  }

  return '';
};

const getVerseNumberFromWord = (word: MushafWord): number | undefined => {
  if (typeof word.verseKey === 'string') {
    const [, ayah] = word.verseKey.split(':');
    const parsed = Number(ayah);
    if (Number.isFinite(parsed)) {
      return parsed;
    }
  }

  if (typeof word.location === 'string') {
    const [, ayah] = word.location.split(':');
    const parsed = Number(ayah);
    if (Number.isFinite(parsed)) {
      return parsed;
    }
  }

  return undefined;
};

const getVerseKeyFromWord = (word: MushafWord): string | undefined => {
  if (typeof word.verseKey === 'string') {
    return word.verseKey;
  }

  if (typeof word.location === 'string') {
    const [surah, ayah] = word.location.split(':');
    if (surah && ayah) {
      return `${surah}:${ayah}`;
    }
  }

  return undefined;
};

type MushafWordTextProps = {
  word: MushafWord;
  settings: ReaderSettings;
  isQcfMushaf: boolean;
  isQpcHafsMushaf: boolean;
  isIndopakMushaf: boolean;
  qcfVersion: QcfFontVersion;
  isFontLoaded: boolean;
};

export const MushafWordText = ({
  word,
  settings,
  isQcfMushaf,
  isQpcHafsMushaf,
  isIndopakMushaf,
  qcfVersion,
  isFontLoaded,
}: MushafWordTextProps): React.JSX.Element | null => {
  // Handle verse end markers (charType === 'end')
  if (word.charType === 'end') {
    const verseKey = getVerseKeyFromWord(word);

    // For QCF Mushafs (V1, V2, V4), use the glyph code for proper verse marker rendering
    if (isQcfMushaf && isFontLoaded) {
      const glyphCode = getGlyphCode(word, qcfVersion);
      if (glyphCode) {
        return (
          <span
            data-mushaf-word="true"
            data-verse-key={verseKey || undefined}
            data-word-position={String(word.position)}
            className="inline-flex flex-none items-center text-foreground"
            dangerouslySetInnerHTML={{ __html: sanitizeHtml(glyphCode) }}
          />
        );
      }
    }

    // For IndoPak: the font doesn't combine U+06DD with numerals into a ligature.
    // Render a lightweight overlay marker so the verse number appears inside the ornament.
    if (isIndopakMushaf) {
      const verseNum = getVerseNumberFromWord(word);
      if (verseNum !== undefined) {
        return (
          <span
            data-mushaf-word="true"
            data-verse-key={verseKey || undefined}
            data-word-position={String(word.position)}
            className="inline-flex flex-none items-center text-foreground"
          >
            <HybridVerseMarker
              verseNumber={verseNum}
              {...(settings.arabicFontFace ? { fontFamily: settings.arabicFontFace } : {})}
              className="mx-0.5"
            />
          </span>
        );
      }
      return null;
    }

    // For QPC Uthmani Hafs: the font renders beautiful verse markers natively
    // Just render the text directly - no SVG overlay needed
    const markerText = word.textUthmani || '';
    if (markerText) {
      return (
        <span
          data-mushaf-word="true"
          data-verse-key={verseKey || undefined}
          data-word-position={String(word.position)}
          className="inline-flex flex-none items-center text-foreground"
        >
          {markerText}
        </span>
      );
    }

    return null;
  }

  const baseText = getBaseText(word, isIndopakMushaf);
  const verseKey = getVerseKeyFromWord(word);
  const glyphCode = getGlyphCode(word, qcfVersion);
  const hasGlyphCode = typeof glyphCode === 'string' && glyphCode.length > 0;

  if (!baseText && (!isQcfMushaf || !hasGlyphCode)) {
    return null;
  }

  const displayText = stripAyahMarkers(baseText, isQcfMushaf);
  const copyText = displayText.trim();
  const rawHtml = buildWordHtml({
    isQcfMushaf,
    isQpcHafsMushaf,
    isFontLoaded,
    settings,
    baseText,
    displayText,
    glyphCode,
  });

  if (!rawHtml) {
    return null;
  }

  return (
    <span
      data-mushaf-word="true"
      data-copy-text={copyText || undefined}
      {...(verseKey ? { 'data-verse-key': verseKey } : {})}
      data-word-position={String(word.position)}
      className={cn(
        'inline-flex flex-none items-center text-foreground',
        isQcfMushaf && 'font-medium',
        isQcfMushaf && !isFontLoaded && hasGlyphCode && 'opacity-0'
      )}
      dangerouslySetInnerHTML={{ __html: sanitizeHtml(rawHtml) }}
    />
  );
};

