'use client';

import useSWRImmutable from 'swr/immutable';

import { getReadingViewPage } from '@infra/quran/readingViewClient';

import { mapVersesToPage } from './mushafReadingViewMapping';

import type { MushafPageLines } from '@/types';

type VerseRange = { from: string; to: string };

interface UseDedupedFetchMushafPageParams {
  pageNumber: number;
  mushafId: string;
  reciterId?: number | undefined;
  wordByWordLocale?: string | undefined;
  translationIds?: string | undefined;
  verseRange?: VerseRange | undefined;
  enabled?: boolean;
}

export function useDedupedFetchMushafPage({
  pageNumber,
  mushafId,
  reciterId,
  wordByWordLocale,
  translationIds,
  verseRange,
  enabled = true,
}: UseDedupedFetchMushafPageParams): {
  page: MushafPageLines | null;
  isLoading: boolean;
  error: string | null;
} {
  const requestKey = enabled
    ? [
        'mushaf-page',
        mushafId,
        pageNumber,
        typeof reciterId === 'number' ? reciterId : 'no-reciter',
        wordByWordLocale ?? 'no-wbw',
        translationIds ?? 'no-translations',
        verseRange?.from ?? 'no-from',
        verseRange?.to ?? 'no-to',
      ]
    : null;

  const { data, error, isLoading } = useSWRImmutable<MushafPageLines>(requestKey, async () => {
    const verses = await getReadingViewPage({
      pageNumber,
      mushafId,
      ...(typeof reciterId === 'number' ? { reciterId } : {}),
      ...(wordByWordLocale ? { wordByWordLocale } : {}),
      ...(translationIds ? { translationIds } : {}),
      ...(verseRange ? { from: verseRange.from, to: verseRange.to } : {}),
    });

    return mapVersesToPage(pageNumber, verses);
  });

  return {
    page: data ?? null,
    isLoading,
    error: error instanceof Error ? error.message : error ? String(error) : null,
  };
}

import { useCallback, useEffect, type MutableRefObject } from 'react';

import type { LookupFn } from './useVerseListing';
import type { Key, MutatorCallback, MutatorOptions } from 'swr';

export const VERSES_PER_PAGE = 10;

export type SetSize = (size: number | ((size: number) => number)) => Promise<unknown>;
type Mutate = <Data = unknown>(
  key: Key,
  data?: Data | Promise<Data> | MutatorCallback<Data>,
  opts?: MutatorOptions<Data>
) => Promise<Data | undefined>;

export const buildSWRKeyFactory = (
  id?: string,
  stableTranslationIds?: string,
  wordLang?: string,
  tajweed?: boolean
) => {
  return (index: number) =>
    id ? ['verses', id, stableTranslationIds, wordLang, index + 1, tajweed] : null;
};

export const createFetcher = (lookup: LookupFn, setError: (msg: string) => void) => {
  return ([, pId, translationIdsStr, wl, page, tajweed]: [
    string,
    string,
    string,
    string,
    number,
    boolean | undefined,
  ]) => {
    const translationIds = translationIdsStr.split(',').map(Number);
    return lookup({
      id: pId as string,
      translationIds,
      page: page as number,
      perPage: VERSES_PER_PAGE,
      wordLang: wl as string,
      tajweed: !!tajweed,
    }).catch((err) => {
      setError(`Failed to load content. ${err.message}`);
      return { verses: [], totalPages: 1 };
    });
  };
};

export const useTargetVersePreload = (
  targetVerseNumber: number | undefined,
  size: number,
  setSize: SetSize,
  surahId?: string
): void => {
  useEffect(() => {
    if (!targetVerseNumber || targetVerseNumber <= 0) return;
    const requiredPages = Math.max(1, Math.ceil(targetVerseNumber / VERSES_PER_PAGE));
    if (requiredPages > size) {
      setSize(requiredPages);
    }
  }, [targetVerseNumber, size, setSize, surahId]);
};

interface PrefetchNextPageParams {
  id?: string | undefined;
  keyFactory: (index: number) => Key;
  isReachingEnd: boolean;
  mutateGlobal: Mutate;
  lookup: LookupFn;
  size: number;
  prefetchedPagesRef: MutableRefObject<Set<number>>;
}

interface ParsedNextKey {
  chapterId: string;
  translationIds: number[];
  wordLang: string;
  page: number;
  tajweed: boolean;
  key: Key;
}

const parseNextKey = (nextKey: Key): ParsedNextKey | null => {
  if (!nextKey || !Array.isArray(nextKey)) return null;

  const [, chapterId, translationIdsValue, wordLang, page, tajweed] = nextKey;
  if (
    typeof chapterId !== 'string' ||
    typeof translationIdsValue !== 'string' ||
    typeof wordLang !== 'string' ||
    typeof page !== 'number'
  ) {
    return null;
  }

  const translationIds = translationIdsValue
    .split(',')
    .filter((value) => value.length > 0)
    .map((value) => Number(value));

  return {
    chapterId,
    translationIds,
    wordLang,
    page,
    tajweed: !!tajweed,
    key: nextKey,
  };
};

export const usePrefetchNextPage = ({
  id,
  keyFactory,
  isReachingEnd,
  mutateGlobal,
  lookup,
  size,
  prefetchedPagesRef,
}: PrefetchNextPageParams): (() => void) => {
  return useCallback(() => {
    if (!id || !keyFactory || isReachingEnd) return;

    const nextPageIndex = size;
    if (prefetchedPagesRef.current.has(nextPageIndex)) return;

    const parsedKey = parseNextKey(keyFactory(nextPageIndex));
    if (!parsedKey) return;

    const { chapterId, translationIds, wordLang, page, tajweed, key } = parsedKey;

    prefetchedPagesRef.current.add(nextPageIndex);

    void mutateGlobal(
      key,
      () =>
        lookup({
          id: chapterId,
          translationIds,
          page,
          perPage: VERSES_PER_PAGE,
          wordLang,
          tajweed,
        }).catch((err) => {
          prefetchedPagesRef.current.delete(nextPageIndex);
          throw err;
        }),
      { populateCache: true, revalidate: false }
    ).catch(() => {});
  }, [id, keyFactory, isReachingEnd, mutateGlobal, lookup, size, prefetchedPagesRef]);
};

import { useEffect, type MutableRefObject, type RefObject } from 'react';

import type { SetSize } from './useInfiniteVerseLoader.fetcher';

export const PREFETCH_SCROLL_THRESHOLD_PX = 800;

const findScrollRoot = (start: HTMLElement | null): Element | null => {
  let node: HTMLElement | null = start?.parentElement ?? null;
  while (node && getComputedStyle(node).overflowY !== 'auto') {
    node = node.parentElement;
  }
  return node;
};

export const useResetPrefetchedPages = (
  prefetchedPagesRef: MutableRefObject<Set<number>>,
  id?: string,
  stableTranslationIds?: string,
  wordLang?: string,
  tajweed?: boolean
): void => {
  useEffect(() => {
    prefetchedPagesRef.current.clear();
  }, [prefetchedPagesRef, id, stableTranslationIds, wordLang, tajweed]);
};

interface LoadMoreParams {
  loadMoreRef: RefObject<HTMLDivElement | null>;
  isReachingEnd: boolean;
  isValidating: boolean;
  setSize: SetSize;
  verseCount: number;
}

export const useIntersectionLoadMore = ({
  loadMoreRef,
  isReachingEnd,
  isValidating,
  setSize,
  verseCount,
}: LoadMoreParams): void => {
  useEffect(() => {
    const loadMoreTarget = loadMoreRef.current;
    if (!loadMoreTarget) return;

    const scrollRoot = findScrollRoot(loadMoreTarget);
    const observer = new IntersectionObserver(
      (entries) => {
        const first = entries[0];
        if (first && first.isIntersecting && !isReachingEnd && !isValidating) {
          setSize((previous) => previous + 1);
        }
      },
      { root: scrollRoot, rootMargin: '100px', threshold: 0.1 }
    );

    observer.observe(loadMoreTarget);
    return () => {
      observer.disconnect();
    };
  }, [isReachingEnd, isValidating, setSize, loadMoreRef, verseCount]);
};

export const useScrollPrefetch = (
  loadMoreRef: RefObject<HTMLDivElement | null>,
  prefetchNextPage: () => void,
  verseCount: number
): void => {
  useEffect(() => {
    const loadMoreTarget = loadMoreRef.current;
    if (!loadMoreTarget) return;

    const scrollRoot = findScrollRoot(loadMoreTarget);
    if (!(scrollRoot instanceof HTMLElement)) return;

    const handleScroll = (): void => {
      const remaining = scrollRoot.scrollHeight - (scrollRoot.scrollTop + scrollRoot.clientHeight);
      if (remaining <= PREFETCH_SCROLL_THRESHOLD_PX) {
        prefetchNextPage();
      }
    };

    scrollRoot.addEventListener('scroll', handleScroll, { passive: true });
    handleScroll();

    return () => {
      scrollRoot.removeEventListener('scroll', handleScroll);
    };
  }, [prefetchNextPage, loadMoreRef, verseCount]);
};

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import { useInfiniteVerseLoader } from '@/app/(features)/surah/hooks/useInfiniteVerseLoader';
import { useTranslationOptions } from '@/app/(features)/surah/hooks/useTranslationOptions';
import { useSettings } from '@/app/providers/SettingsContext';
import { useAudio } from '@/app/shared/player/context/AudioContext';

import { VERSES_PER_PAGE } from './useInfiniteVerseLoader.fetcher';
import {
  resolveVerses,
  useStableTranslationIds,
  useVerseListingErrorState,
} from './verse-listing/internal';
import { useNavigationHandlers } from './verse-listing/useNavigationHandlers';

export type {
  UseVerseListingReturn,
  LookupOptions,
  LookupFn,
  UseVerseListingParams,
} from './verse-listing/types';

import type { UseVerseListingParams, UseVerseListingReturn } from './verse-listing/types';
import type { Verse } from '@/types';

const EMPTY_LOADER_STATE: {
  verses: Verse[];
  isLoading: boolean;
  isValidating: boolean;
  isReachingEnd: boolean;
} = {
  verses: [],
  isLoading: false,
  isValidating: false,
  isReachingEnd: true,
};

const parseVerseNumber = (verse: Verse): number | null => {
  if (typeof verse.verse_number === 'number' && Number.isFinite(verse.verse_number)) {
    return verse.verse_number;
  }

  const [, versePart] = verse.verse_key.split(':');
  const parsed = Number.parseInt(versePart ?? '', 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : null;
};

const getPageNumberFromVerseNumber = (verseNumber: number, perPage: number): number =>
  Math.floor((verseNumber - 1) / perPage) + 1;

export function useVerseListing({
  id,
  resourceKind,
  totalVerses,
  lookup,
  initialVerses,
  initialVersesParams,
  initialVerseNumber,
}: UseVerseListingParams): UseVerseListingReturn {
  const errorState = useVerseListingErrorState();
  const settingsState = useSettings();
  const audio = useAudio();
  const translation = useTranslationOptions();

  const stableTranslationIds = useStableTranslationIds(settingsState.settings);
  const wordLang = settingsState.settings.wordLang;
  const tajweed = settingsState.settings.tajweed ?? false;
  const translationIds = useMemo(
    () =>
      stableTranslationIds
        .split(',')
        .filter((value) => value.length > 0)
        .map((value) => Number(value))
        .filter((value) => Number.isFinite(value)),
    [stableTranslationIds]
  );

  const mode: UseVerseListingReturn['mode'] =
    resourceKind === 'surah' && typeof totalVerses === 'number' && totalVerses > 0
      ? 'quran-com'
      : 'infinite';

  const canUseInitialVerses =
    mode === 'quran-com' &&
    Boolean(initialVerses?.length) &&
    Boolean(initialVersesParams) &&
    !tajweed &&
    initialVersesParams?.wordLang === wordLang &&
    stableTranslationIds ===
      (initialVersesParams?.translationIds ?? [])
        .filter((value) => Number.isFinite(value))
        .sort((a, b) => a - b)
        .join(',');

  const effectiveInitialVerses =
    mode === 'quran-com' ? (canUseInitialVerses ? initialVerses : undefined) : initialVerses;

  const infiniteLoaderParams: Parameters<typeof useInfiniteVerseLoader>[0] = {
    lookup,
    stableTranslationIds,
    wordLang,
    loadMoreRef: errorState.loadMoreRef,
    error: errorState.error,
    setError: errorState.handleLoaderError,
    ...(mode === 'infinite' && typeof initialVerseNumber === 'number' && initialVerseNumber > 0
      ? { targetVerseNumber: initialVerseNumber }
      : {}),
    ...(mode === 'infinite' && id !== undefined ? { id } : {}),
    tajweed,
  } as const;

  const infiniteLoaderState = useInfiniteVerseLoader(infiniteLoaderParams);
  const infiniteState =
    mode === 'infinite' && id !== undefined
      ? { ...EMPTY_LOADER_STATE, ...infiniteLoaderState }
      : EMPTY_LOADER_STATE;

  const [apiPageToVersesMap, setApiPageToVersesMap] = useState<Record<number, Verse[]>>(() =>
    effectiveInitialVerses?.length ? { 1: effectiveInitialVerses } : {}
  );
  const prefetchedPagesRef = useRef<Set<number>>(new Set());
  useEffect(() => {
    prefetchedPagesRef.current.clear();
    if (mode !== 'quran-com') return;

    setApiPageToVersesMap(effectiveInitialVerses?.length ? { 1: effectiveInitialVerses } : {});
  }, [
    effectiveInitialVerses,
    mode,
    id,
    stableTranslationIds,
    wordLang,
    tajweed,
    lookup,
    translationIds,
  ]);

  const prefetchVersePage = useCallback(
    async (verseNumber: number): Promise<void> => {
      if (mode !== 'quran-com') return;
      if (!id) return;
      if (verseNumber <= 0) return;

      const pageNumber = getPageNumberFromVerseNumber(verseNumber, VERSES_PER_PAGE);
      if (apiPageToVersesMap[pageNumber]?.length) return;
      if (prefetchedPagesRef.current.has(pageNumber)) return;

      prefetchedPagesRef.current.add(pageNumber);

      try {
        const result = await lookup({
          id,
          translationIds,
          page: pageNumber,
          perPage: VERSES_PER_PAGE,
          wordLang,
          tajweed,
        });
        setApiPageToVersesMap((prev) => ({ ...prev, [pageNumber]: result.verses }));
      } catch (error) {
        prefetchedPagesRef.current.delete(pageNumber);
      }
    },
    [apiPageToVersesMap, id, lookup, mode, translationIds, wordLang, tajweed]
  );

  // Keep the next verse's page warm for audio next/auto-advance.
  useEffect(() => {
    if (mode !== 'quran-com') return;
    if (typeof totalVerses !== 'number' || totalVerses <= 0) return;
    if (!audio.activeVerse) return;

    const current = parseVerseNumber(audio.activeVerse);
    if (!current) return;

    const nextVerseNumber = current + 1;
    if (nextVerseNumber > totalVerses) return;

    void prefetchVersePage(nextVerseNumber);
  }, [audio.activeVerse, mode, prefetchVersePage, totalVerses]);

  const quranComLoadedVerses = useMemo(
    () => Object.values(apiPageToVersesMap).flat(),
    [apiPageToVersesMap]
  );

  const rawVerses =
    mode === 'quran-com'
      ? quranComLoadedVerses
      : resolveVerses(initialVerses, infiniteState.verses);

  const verses = useMemo(() => {
    if (!translation.translationOptions.length) {
      return rawVerses;
    }
    const resourceMap = new Map(translation.translationOptions.map((t) => [t.id, t.name]));
    return rawVerses.map((verse) => {
      if (!verse.translations) {
        return verse;
      }
      return {
        ...verse,
        translations: verse.translations.map((t) => {
          const resourceName = resourceMap.get(t.resource_id) ?? t.resource_name;
          return {
            ...t,
            ...(resourceName ? { resource_name: resourceName } : {}),
          };
        }),
      };
    });
  }, [rawVerses, translation.translationOptions]);

  const infiniteNavigation = useNavigationHandlers({
    verses,
    activeVerse: audio.activeVerse,
    setActiveVerse: audio.setActiveVerse,
    openPlayer: audio.openPlayer,
  });

  const getVerseByNumber = useCallback(
    (verseNumber: number): Verse | null => {
      if (verseNumber <= 0) return null;
      const pageNumber = getPageNumberFromVerseNumber(verseNumber, VERSES_PER_PAGE);
      const idxInPage = (verseNumber - 1) % VERSES_PER_PAGE;
      return apiPageToVersesMap[pageNumber]?.[idxInPage] ?? null;
    },
    [apiPageToVersesMap]
  );

  const handleNext = useCallback((): boolean => {
    if (mode !== 'quran-com') return infiniteNavigation.handleNext();
    if (typeof totalVerses !== 'number' || totalVerses <= 0) return false;
    if (!audio.activeVerse) return false;

    const current = parseVerseNumber(audio.activeVerse);
    if (!current) return false;

    const nextVerseNumber = current + 1;
    if (nextVerseNumber > totalVerses) return false;

    const nextVerse = getVerseByNumber(nextVerseNumber);
    if (!nextVerse) {
      void prefetchVersePage(nextVerseNumber);
      return false;
    }

    audio.setActiveVerse(nextVerse);
    audio.openPlayer();
    return true;
  }, [audio, getVerseByNumber, infiniteNavigation, mode, prefetchVersePage, totalVerses]);

  const handlePrev = useCallback((): boolean => {
    if (mode !== 'quran-com') return infiniteNavigation.handlePrev();
    if (!audio.activeVerse) return false;

    const current = parseVerseNumber(audio.activeVerse);
    if (!current) return false;

    const prevVerseNumber = current - 1;
    if (prevVerseNumber <= 0) return false;

    const prevVerse = getVerseByNumber(prevVerseNumber);
    if (!prevVerse) {
      void prefetchVersePage(prevVerseNumber);
      return false;
    }

    audio.setActiveVerse(prevVerse);
    audio.openPlayer();
    return true;
  }, [audio, getVerseByNumber, infiniteNavigation, mode, prefetchVersePage]);

  const isLoading =
    mode === 'quran-com'
      ? verses.length === 0 && !errorState.error && Boolean(id)
      : infiniteState.isLoading;

  return {
    mode,
    error: errorState.error,
    setError: errorState.handleLoaderError,
    isLoading,
    verses,
    isValidating: mode === 'quran-com' ? false : infiniteState.isValidating,
    isReachingEnd: mode === 'quran-com' ? true : infiniteState.isReachingEnd,
    loadMoreRef: errorState.loadMoreRef,
    ...(typeof totalVerses === 'number' ? { totalVerses } : {}),
    perPage: VERSES_PER_PAGE,
    apiPageToVersesMap,
    setApiPageToVersesMap,
    lookup,
    ...(id !== undefined ? { resourceId: id } : {}),
    translationIds,
    wordLang,
    ...(effectiveInitialVerses ? { initialVerses: effectiveInitialVerses } : {}),
    translationOptions: translation.translationOptions,
    wordLanguageOptions: translation.wordLanguageOptions,
    wordLanguageMap: translation.wordLanguageMap,
    settings: settingsState.settings,
    setSettings: settingsState.setSettings,
    activeVerse: audio.activeVerse,
    reciter: audio.reciter,
    isPlayerVisible: audio.isPlayerVisible,
    handleNext,
    handlePrev,
  };
}

import { useEffect, useMemo } from 'react';
import useSWRImmutable from 'swr/immutable';

import type { LookupFn } from './types';
import type { Verse } from '@/types';

export type ApiPageToVersesMap = Record<number, Verse[]>;

interface UseDedupedFetchVerseParams {
  resourceId: string;
  verseIdx: number;
  perPage: number;
  lookup: LookupFn;
  translationIds: number[];
  wordLang: string;
  /** When true, fetches code_v2 and page_number for Tajweed rendering */
  tajweed?: boolean;
  initialPageVerses?: Verse[];
  setApiPageToVersesMap: React.Dispatch<React.SetStateAction<ApiPageToVersesMap>>;
  onError?: (message: string) => void;
  enabled?: boolean;
}

interface UseDedupedFetchVerseResult {
  verse: Verse | null;
  pageNumber: number;
  isLoading: boolean;
}

const getPageNumberFromIndex = (index: number, perPage: number): number =>
  Math.floor(index / perPage) + 1;

export function useDedupedFetchVerse({
  resourceId,
  verseIdx,
  perPage,
  lookup,
  translationIds,
  wordLang,
  tajweed = false,
  initialPageVerses,
  setApiPageToVersesMap,
  onError,
  enabled = true,
}: UseDedupedFetchVerseParams): UseDedupedFetchVerseResult {
  const pageNumber = useMemo(() => getPageNumberFromIndex(verseIdx, perPage), [verseIdx, perPage]);
  const idxInPage = verseIdx % perPage;

  // Include tajweed in the cache key so SWR refetches when tajweed changes
  const requestKey = enabled
    ? [
        'verses',
        resourceId,
        translationIds.join(','),
        wordLang,
        pageNumber,
        perPage,
        String(tajweed),
      ]
    : null;

  const {
    data: versesInPage,
    error,
    isLoading,
  } = useSWRImmutable<Verse[]>(
    requestKey,
    async () => {
      const result = await lookup({
        id: resourceId,
        translationIds,
        page: pageNumber,
        perPage,
        wordLang,
        tajweed,
      });
      return result.verses;
    },
    {
      // Don't use fallbackData when tajweed is true, since initial verses don't have codeV2
      ...(pageNumber === 1 && initialPageVerses && !tajweed
        ? { fallbackData: initialPageVerses }
        : {}),
    }
  );

  useEffect(() => {
    if (!versesInPage?.length) return;
    setApiPageToVersesMap((prev) =>
      prev[pageNumber] === versesInPage ? prev : { ...prev, [pageNumber]: versesInPage }
    );
  }, [pageNumber, setApiPageToVersesMap, versesInPage]);

  useEffect(() => {
    if (!error) return;
    const message = error instanceof Error ? error.message : String(error);
    onError?.(`Failed to load verses. ${message}`);
  }, [error, onError]);

  return {
    verse: versesInPage?.[idxInPage] ?? null,
    pageNumber,
    isLoading,
  };
}

import { useCallback } from 'react';

import { useAudio } from '@/app/shared/player/context/AudioContext';

import type { Verse } from '@/types';

interface UseNavigationHandlersParams {
  verses: Verse[];
  activeVerse: ReturnType<typeof useAudio>['activeVerse'];
  setActiveVerse: ReturnType<typeof useAudio>['setActiveVerse'];
  openPlayer: ReturnType<typeof useAudio>['openPlayer'];
}

interface UseNavigationHandlersReturn {
  handleNext: () => boolean;
  handlePrev: () => boolean;
}

export function useNavigationHandlers({
  verses,
  activeVerse,
  setActiveVerse,
  openPlayer,
}: UseNavigationHandlersParams): UseNavigationHandlersReturn {
  const handleNext = useCallback((): boolean => {
    let nextVerse: Verse | undefined;
    setActiveVerse((prev) => {
      if (!prev) return prev;
      const currentIndex = verses.findIndex((v) => v.id === prev.id);
      if (currentIndex < verses.length - 1) {
        nextVerse = verses[currentIndex + 1]!;
        return nextVerse;
      }
      return prev;
    });
    if (nextVerse) {
      openPlayer();
      return true;
    }
    return false;
  }, [verses, setActiveVerse, openPlayer]);

  const handlePrev = useCallback((): boolean => {
    let nextVerse: Verse | undefined;
    setActiveVerse((prev) => {
      if (!prev) return prev;
      const currentIndex = verses.findIndex((v) => v.id === prev.id);
      if (currentIndex > 0) {
        nextVerse = verses[currentIndex - 1]!;
        return nextVerse;
      }
      return prev;
    });
    if (nextVerse) {
      openPlayer();
      return true;
    }
    return false;
  }, [verses, setActiveVerse, openPlayer]);

  return { handleNext, handlePrev } as const;
}

'use client';
import { useEffect, useRef, useState } from 'react';

import { useSettings } from '@/app/providers/SettingsContext';
import { applyArabicFont } from '@/lib/tafsir/applyArabicFont';

import { TafsirSkeleton } from './TafsirSkeleton';
import { useTafsirTabsState } from './useTafsirTabsState';

interface TafsirTabsProps {
  verseKey: string;
  tafsirIds: number[];
}

export function TafsirTabs({ verseKey, tafsirIds }: TafsirTabsProps): React.JSX.Element {
  const { settings } = useSettings();
  const { tabs, activeId, setActiveId, contents, loading } = useTafsirTabsState(
    verseKey,
    tafsirIds
  );

  // Track content container ref for height measurement
  const contentRef = useRef<HTMLDivElement>(null);
  // Store the last known content height to prevent layout shift during loading
  const [stableHeight, setStableHeight] = useState<number>(0);

  // Capture content height when loaded content is rendered
  useEffect(() => {
    if (!loading[activeId ?? 0] && contentRef.current && contents[activeId ?? 0]) {
      // Use requestAnimationFrame to ensure accurate measurement after paint
      requestAnimationFrame(() => {
        if (contentRef.current) {
          const height = contentRef.current.offsetHeight;
          if (height > 0) {
            setStableHeight(height);
          }
        }
      });
    }
  }, [loading, activeId, contents]);

  if (!tabs.length) {
    return (
      <div className="p-4 text-center text-muted">
        No tafsir resources available. Please check your settings.
      </div>
    );
  }

  if (!activeId) {
    return <div className="p-4 text-center text-muted">Loading tafsir...</div>;
  }

  const activeTab = tabs.find((t) => t.id === activeId);
  const isLoading = !!loading[activeId];

  return (
    <div>
      <TabsHeader tabs={tabs} activeId={activeId} onSelect={setActiveId} />
      {/* Wrapper div maintains stable height during loading to prevent layout shift */}
      <div style={stableHeight > 0 ? { minHeight: `${stableHeight}px` } : undefined}>
        <TafsirContent
          ref={contentRef}
          title={activeTab?.name || ''}
          isLoading={isLoading}
          html={applyArabicFont(contents[activeId] || '', settings.arabicFontFace)}
          fontSizePx={settings.tafsirFontSize}
        />
      </div>
    </div>
  );
}

function TabsHeader({
  tabs,
  activeId,
  onSelect,
}: {
  tabs: { id: number; name: string }[];
  activeId: number | undefined;
  onSelect: (id: number) => void;
}): React.JSX.Element {
  return (
    <div
      onTouchStart={(e) => e.stopPropagation()}
      onTouchEnd={(e) => e.stopPropagation()}
      className="flex w-full flex-nowrap items-center p-1 rounded-full bg-interactive border border-border mx-0 sm:mx-4 overflow-x-auto scrollbar-hide gap-1"
    >
      {tabs.map((t) => (
        <button
          key={t.id}
          onClick={() => onSelect(t.id)}
          className={`flex-1 text-center py-2.5 px-4 sm:py-3 sm:px-5 rounded-full text-xs sm:text-sm font-semibold transition-colors whitespace-nowrap ${
            activeId === t.id
              ? 'bg-surface shadow text-foreground'
              : 'text-muted hover:text-foreground hover:bg-surface/30'
          }`}
        >
          {t.name}
        </button>
      ))}
    </div>
  );
}

