'use client';
import { createContext, useCallback, useContext, useEffect, useMemo, useState } from 'react';

import { useBodyScrollLock } from './hooks/useBodyScrollLock';
import { useSidebarScrollPositions } from './hooks/useSidebarScrollPositions';

// Helper hook for keyboard controls
const useSidebarKeyboard = (
  isSurahListOpen: boolean,
  setSurahListOpen: (open: boolean) => void,
  isBookmarkSidebarOpen: boolean,
  setBookmarkSidebarOpen: (open: boolean) => void,
  isSearchSidebarOpen: boolean,
  setSearchSidebarOpen: (open: boolean) => void
): void => {
  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent): void => {
      if (event.key === 'Escape') {
        if (isSurahListOpen) setSurahListOpen(false);
        if (isBookmarkSidebarOpen) setBookmarkSidebarOpen(false);
        if (isSearchSidebarOpen) setSearchSidebarOpen(false);
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [
    isSurahListOpen,
    setSurahListOpen,
    isBookmarkSidebarOpen,
    setBookmarkSidebarOpen,
    isSearchSidebarOpen,
    setSearchSidebarOpen,
  ]);
};

interface SidebarContextType {
  isSurahListOpen: boolean;
  setSurahListOpen: (open: boolean) => void;
  isBookmarkSidebarOpen: boolean;
  setBookmarkSidebarOpen: (open: boolean) => void;
  isSearchSidebarOpen: boolean;
  setSearchSidebarOpen: (open: boolean) => void;
  surahScrollTop: number;
  setSurahScrollTop: (top: number) => void;
  juzScrollTop: number;
  setJuzScrollTop: (top: number) => void;
  pageScrollTop: number;
  setPageScrollTop: (top: number) => void;
}

interface SidebarToggles {
  isSurahListOpen: boolean;
  setSurahListOpen: (open: boolean) => void;
  isBookmarkSidebarOpen: boolean;
  setBookmarkSidebarOpen: (open: boolean) => void;
  isSearchSidebarOpen: boolean;
  setSearchSidebarOpen: (open: boolean) => void;
}

const SidebarContext = createContext<SidebarContextType | undefined>(undefined);

/**
 * Provides global sidebar UI state.
 * Wrap components needing access to sidebar visibility and scroll
 * positions with this provider to synchronize their behavior.
 */
// Local hooks to keep provider lean
const useSidebarToggles = (): SidebarToggles => {
  const [isSurahListOpen, _setSurahListOpen] = useState(false);
  const [isBookmarkSidebarOpen, _setBookmarkSidebarOpen] = useState(false);
  const [isSearchSidebarOpen, _setSearchSidebarOpen] = useState(false);

  const setSurahListOpen = useCallback((open: boolean): void => {
    _setSurahListOpen(open);
  }, []);

  const setBookmarkSidebarOpen = useCallback((open: boolean): void => {
    _setBookmarkSidebarOpen(open);
  }, []);

  const setSearchSidebarOpen = useCallback((open: boolean): void => {
    _setSearchSidebarOpen(open);
  }, []);

  useBodyScrollLock(isSurahListOpen || isBookmarkSidebarOpen || isSearchSidebarOpen);
  useSidebarKeyboard(
    isSurahListOpen,
    setSurahListOpen,
    isBookmarkSidebarOpen,
    setBookmarkSidebarOpen,
    isSearchSidebarOpen,
    setSearchSidebarOpen
  );

  return {
    isSurahListOpen,
    setSurahListOpen,
    isBookmarkSidebarOpen,
    setBookmarkSidebarOpen,
    isSearchSidebarOpen,
    setSearchSidebarOpen,
  };
};

const useSidebarContextValue = (
  toggles: SidebarToggles,
  positions: ReturnType<typeof useSidebarScrollPositions>
): SidebarContextType =>
  useMemo(
    () => ({
      ...toggles,
      surahScrollTop: positions.surahScrollTop,
      setSurahScrollTop: positions.setSurahScrollTop,
      juzScrollTop: positions.juzScrollTop,
      setJuzScrollTop: positions.setJuzScrollTop,
      pageScrollTop: positions.pageScrollTop,
      setPageScrollTop: positions.setPageScrollTop,
    }),
    [toggles, positions]
  );

export const SidebarProvider = ({ children }: { children: React.ReactNode }): React.JSX.Element => {
  const toggles = useSidebarToggles();
  const positions = useSidebarScrollPositions();
  const value = useSidebarContextValue(toggles, positions);
  return <SidebarContext.Provider value={value}>{children}</SidebarContext.Provider>;
};

/**
 * Hook for interacting with sidebar state.
 * Call within components to read or update sidebar visibility and
 * scroll positions managed by `SidebarProvider`.
 */
export const useSidebar = (): SidebarContextType => {
  const ctx = useContext(SidebarContext);
  if (!ctx) throw new Error('useSidebar must be used within SidebarProvider');
  return ctx;
};

'use client';

import { useCallback, useMemo } from 'react';

import { useSettings } from '@/app/providers/SettingsContext';

import { findBookmarkInFolders, isVerseBookmarked, getAllBookmarkedVerses } from './bookmark-utils';
import { BookmarkContext } from './BookmarkContext';
import { useBookmarkData } from './hooks/useBookmarkData';
import { useBookmarkMetadata } from './hooks/useBookmarkMetadata';
import useBookmarkOperations from './hooks/useBookmarkOperations';
import useFolderOperations from './hooks/useFolderOperations';
import { usePinnedBookmarks } from './hooks/usePinnedBookmarks';
import usePlannerOperations from './hooks/usePlannerOperations';

import type { BookmarkContextType } from './types';
import type { Bookmark, Folder } from '@/types';

export const BookmarkProvider = ({
  children,
}: {
  children: React.ReactNode;
}): React.ReactElement => {
  const value = useBookmarkProviderValue();
  return <BookmarkContext.Provider value={value}>{children}</BookmarkContext.Provider>;
};

function useBookmarkProviderValue(): BookmarkContextType {
  const {
    folders,
    setFolders,
    pinnedVerses,
    setPinnedVerses,
    lastRead,
    setLastReadState,
    planner,
    setPlannerState,
    chapters,
  } = useBookmarkData();
  const { settings } = useSettings();

  const fetchBookmarkMetadata = useBookmarkMetadata(settings, setFolders, setPinnedVerses);

  const folderOps = useFolderOperations(setFolders);
  const bookmarkOps = useBookmarkOperations({
    folders,
    setFolders,
    pinned: pinnedVerses,
    setPinned: setPinnedVerses,
    chapters,
    fetchMetadata: fetchBookmarkMetadata,
  });
  const plannerOps = usePlannerOperations(planner, setPlannerState);
  const helpers = useBookmarkHelpers(folders, pinnedVerses, bookmarkOps, setLastReadState);

  return useMemo(
    () => ({
      folders,
      pinnedVerses,
      ...folderOps,
      ...bookmarkOps,
      ...helpers,
      lastRead,
      chapters,
      planner,
      ...plannerOps,
    }),
    [
      folders,
      pinnedVerses,
      folderOps,
      bookmarkOps,
      helpers,
      lastRead,
      chapters,
      planner,
      plannerOps,
    ]
  );
}

function useBookmarkHelpers(
  folders: Folder[],
  pinnedVerses: Bookmark[],
  bookmarkOps: ReturnType<typeof useBookmarkOperations>,
  setLastReadState: ReturnType<typeof useBookmarkData>['setLastReadState']
): {
  isBookmarked: (verseId: string) => boolean;
  findBookmark: (verseId: string) => ReturnType<typeof findBookmarkInFolders>;
  bookmarkedVerses: string[];
  togglePinned: (verseId: string, metadata?: Partial<Bookmark>) => void;
  isPinned: (verseId: string) => boolean;
  setLastRead: (
    surahId: string,
    verseNumber: number,
    verseKey?: string,
    globalVerseId?: number
  ) => void;
  removeLastRead: (surahId: string) => void;
} {
  const isBookmarked = useCallback(
    (verseId: string) => isVerseBookmarked(folders, verseId),
    [folders]
  );

  const findBookmark = useCallback(
    (verseId: string) => findBookmarkInFolders(folders, verseId),
    [folders]
  );

  const bookmarkedVerses = useMemo(() => getAllBookmarkedVerses(folders), [folders]);
  const { togglePinned, isPinned } = usePinnedBookmarks(pinnedVerses, bookmarkOps);

  const setLastRead = useCallback(
    (surahId: string, verseNumber: number, verseKey?: string, globalVerseId?: number) => {
      setLastReadState((prev) => {
        const updated = {
          ...prev,
          [surahId]: {
            verseNumber,
            verseId: verseNumber,
            ...(typeof verseKey === 'string' ? { verseKey } : {}),
            ...(typeof globalVerseId === 'number' ? { globalVerseId } : {}),
            updatedAt: Date.now(),
          },
        };

        // Limit to 5 most recent entries
        const entries = Object.entries(updated);
        if (entries.length <= 5) {
          return updated;
        }

        // Sort by updatedAt (most recent first) and keep only top 5
        const sorted = entries.sort(([, a], [, b]) => b.updatedAt - a.updatedAt);
        const limited = sorted.slice(0, 5);

        return Object.fromEntries(limited);
      });
    },
    [setLastReadState]
  );

  const removeLastRead = useCallback(
    (surahId: string) => {
      setLastReadState((prev) => {
        const next = { ...prev };
        delete next[surahId];
        return next;
      });
    },
    [setLastReadState]
  );

  return {
    isBookmarked,
    findBookmark,
    bookmarkedVerses,
    togglePinned,
    isPinned,
    setLastRead,
    removeLastRead,
  } as const;
}

import { Folder, Bookmark, PlannerPlan } from '@/types';

const generateId = (): string => {
  if (typeof globalThis !== 'undefined') {
    const cryptoGlobal = globalThis as typeof globalThis & { crypto?: Crypto };
    const cryptoApi = cryptoGlobal.crypto;

    if (cryptoApi) {
      const ensuredCrypto = cryptoApi;

      if (typeof ensuredCrypto.randomUUID === 'function') {
        return ensuredCrypto.randomUUID();
      }

      if (typeof ensuredCrypto.getRandomValues === 'function') {
        const bytes = ensuredCrypto.getRandomValues(new Uint8Array(16)) as Uint8Array;
        const sixth = bytes[6] ?? 0;
        const eighth = bytes[8] ?? 0;
        bytes[6] = (sixth & 0x0f) | 0x40;
        bytes[8] = (eighth & 0x3f) | 0x80;
        const hex = Array.from(bytes, (b) => b.toString(16).padStart(2, '0')).join('');
        return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20)}`;
      }
    }
  }

  const randomSuffix = Math.random().toString(16).slice(2);
  return `id-${Date.now()}-${randomSuffix}`;
};

const normalizeVerseId = (id: string | number): string => String(id);

const matchesVerseId = (bookmark: Bookmark, verseId: string | number): boolean =>
  normalizeVerseId(bookmark.verseId) === normalizeVerseId(verseId);

export const createNewFolder = (name: string, color?: string): Folder => {
  const base: Folder = {
    id: generateId(),
    name,
    createdAt: Date.now(),
    bookmarks: [],
  };

  if (color !== undefined) {
    base.color = color;
  }

  return base;
};

export const findBookmarkInFolders = (
  folders: Folder[],
  verseId: string
): { folder: Folder; bookmark: Bookmark } | null => {
  for (const folder of folders) {
    const bookmark = folder.bookmarks.find((b) => matchesVerseId(b, verseId));
    if (bookmark) {
      return { folder, bookmark };
    }
  }
  return null;
};

export const isVerseBookmarked = (folders: Folder[], verseId: string): boolean => {
  return findBookmarkInFolders(folders, verseId) !== null;
};

export const getAllBookmarkedVerses = (folders: Folder[]): string[] => {
  const allVerses = folders.flatMap((folder) =>
    folder.bookmarks.map((bookmark) => normalizeVerseId(bookmark.verseId))
  );
  return [...new Set(allVerses)];
};

export const addBookmarkToFolder = (
  folders: Folder[],
  verseId: string,
  folderId?: string,
  metadata: Partial<Bookmark> = {}
): Folder[] => {
  const normalizedVerseId = normalizeVerseId(verseId);
  let targetFolderId = folderId;
  if (!targetFolderId) {
    let defaultFolder = folders.find((f) => f.name === 'Uncategorized');
    if (!defaultFolder) {
      defaultFolder = createNewFolder('Uncategorized');
      folders = [defaultFolder, ...folders];
    }
    targetFolderId = defaultFolder.id;
  }

  const targetFolder = folders.find((folder) => folder.id === targetFolderId);
  if (targetFolder?.bookmarks.some((bookmark) => matchesVerseId(bookmark, normalizedVerseId))) {
    return folders;
  }

  const newBookmark: Bookmark = {
    verseId: normalizedVerseId,
    createdAt: Date.now(),
    ...metadata,
  };

  return folders.map((folder) =>
    folder.id === targetFolderId
      ? { ...folder, bookmarks: [...folder.bookmarks, newBookmark] }
      : folder
  );
};

export const removeBookmarkFromFolder = (
  folders: Folder[],
  verseId: string,
  folderId: string
): Folder[] => {
  const normalizedVerseId = normalizeVerseId(verseId);
  return folders.map((folder) =>
    folder.id === folderId
      ? {
          ...folder,
          bookmarks: folder.bookmarks.filter((b) => !matchesVerseId(b, normalizedVerseId)),
        }
      : folder
  );
};

export const updateBookmarkInFolders = (
  folders: Folder[],
  verseId: string,
  data: Partial<Bookmark>
): Folder[] => {
  const normalizedVerseId = normalizeVerseId(verseId);
  return folders.map((folder) => ({
    ...folder,
    bookmarks: folder.bookmarks.map((bookmark) =>
      matchesVerseId(bookmark, normalizedVerseId) ? { ...bookmark, ...data } : bookmark
    ),
  }));
};

export const DEFAULT_PLANNER_ESTIMATED_DAYS = 5;

export interface PlannerPlanRangeConfig {
  startVerse?: number;
  endVerse?: number;
}

const normalizeVerseNumber = (value: number | undefined): number | undefined => {
  if (typeof value !== 'number' || !Number.isFinite(value)) return undefined;
  const rounded = Math.max(1, Math.floor(value));
  return rounded;
};

export const createPlannerPlan = (
  surahId: number,
  targetVerses: number,
  planName?: string,
  estimatedDays?: number,
  range?: PlannerPlanRangeConfig
): PlannerPlan => {
  const normalizedEstimatedDays =
    typeof estimatedDays === 'number' && estimatedDays > 0 ? Math.round(estimatedDays) : undefined;
  const normalizedStartVerse = normalizeVerseNumber(range?.startVerse) ?? 1;
  const explicitEnd = normalizeVerseNumber(range?.endVerse);
  const normalizedEndVerse =
    typeof explicitEnd === 'number' && explicitEnd >= normalizedStartVerse
      ? explicitEnd
      : normalizedStartVerse + Math.max(0, targetVerses - 1);

  return {
    id: generateId(),
    surahId,
    startVerse: normalizedStartVerse,
    endVerse: normalizedEndVerse,
    targetVerses,
    completedVerses: 0,
    createdAt: Date.now(),
    lastUpdated: Date.now(),
    notes: planName || `Surah ${surahId} Plan`,
    estimatedDays: normalizedEstimatedDays ?? DEFAULT_PLANNER_ESTIMATED_DAYS,
  };
};

export const updatePlannerProgress = (
  planner: Record<string, PlannerPlan>,
  planId: string,
  completedVerses: number
): Record<string, PlannerPlan> => {
  const existing = planner[planId];
  if (!existing) return planner;

  return {
    ...planner,
    [planId]: {
      ...existing,
      completedVerses,
      lastUpdated: Date.now(),
    },
  };
};

import { useCallback } from 'react';

import type useBookmarkOperations from './useBookmarkOperations';
import type { Bookmark } from '@/types';

/**
 * Check if a verseId matches a bookmark by comparing against multiple identifiers.
 * This handles cases where pins were created with different ID formats:
 * - Numeric API ID (e.g., "1" for verse 1:1)
 * - VerseKey format (e.g., "1:1")
 * - VerseApiId field
 */
const matchesBookmark = (bookmark: Bookmark, searchId: string): boolean => {
  const id = String(searchId);
  const bookmarkVerseId = String(bookmark.verseId);

  // Direct match on verseId
  if (bookmarkVerseId === id) return true;

  // Match on verseKey (handles both directions)
  if (bookmark.verseKey) {
    const verseKey = String(bookmark.verseKey);
    // searchId matches verseKey directly
    if (verseKey === id) return true;
    // bookmarkVerseId stored as verseKey format, searchId is numeric
    if (bookmarkVerseId === verseKey && bookmark.verseApiId) {
      if (String(bookmark.verseApiId) === id) return true;
    }
  }

  // Match on verseApiId if available
  if (bookmark.verseApiId && String(bookmark.verseApiId) === id) return true;

  // Handle case where bookmark.verseId is in verseKey format but searchId is numeric
  // by checking if searchId matches the verseApiId or if they share the same verseKey
  if (bookmarkVerseId.includes(':') && !id.includes(':')) {
    // bookmark was stored with verseKey as verseId
    // We can't reliably match numeric ID to verseKey without API lookup
    // But check verseApiId as fallback
    if (bookmark.verseApiId && String(bookmark.verseApiId) === id) return true;
  }

  return false;
};

export function usePinnedBookmarks(
  pinnedVerses: Bookmark[],
  bookmarkOps: ReturnType<typeof useBookmarkOperations>
): {
  togglePinned: (verseId: string, metadata?: Partial<Bookmark>) => void;
  isPinned: (verseId: string) => boolean;
} {
  const togglePinned = useCallback(
    (verseId: string, metadata?: Partial<Bookmark>) => {
      const alreadyPinned = pinnedVerses.some((b) => matchesBookmark(b, verseId));
      if (alreadyPinned) {
        // Find the actual bookmark to remove (might have different verseId format)
        const bookmark = pinnedVerses.find((b) => matchesBookmark(b, verseId));
        if (bookmark) {
          bookmarkOps.removeBookmark(bookmark.verseId, 'pinned');
        }
      } else {
        bookmarkOps.addBookmark(verseId, 'pinned', metadata);
      }
    },
    [pinnedVerses, bookmarkOps]
  );

  const isPinned = useCallback(
    (verseId: string) => pinnedVerses.some((b) => matchesBookmark(b, verseId)),
    [pinnedVerses]
  );

  return { togglePinned, isPinned } as const;
}

'use client';
import { useCallback } from 'react';

import {
  createPlannerPlan,
  updatePlannerProgress,
  type PlannerPlanRangeConfig,
} from '@/app/providers/bookmarks/bookmark-utils';
import { PlannerPlan } from '@/types';

export interface PlannerOperations {
  addToPlanner(surahId: number, targetVerses?: number, estimatedDays?: number): void;
  createPlannerPlan(
    surahId: number,
    targetVerses: number,
    planName?: string,
    estimatedDays?: number,
    range?: PlannerPlanRangeConfig
  ): void;
  updatePlannerProgress(planId: string, completedVerses: number): void;
  removeFromPlanner(planId: string): void;
}
export default function usePlannerOperations(
  planner: Record<string, PlannerPlan>,
  setPlanner: React.Dispatch<React.SetStateAction<Record<string, PlannerPlan>>>
): PlannerOperations {
  const addToPlanner = useCallback(
    (surahId: number, targetVerses = 10, estimatedDays?: number) => {
      const plan = createPlannerPlan(surahId, targetVerses, undefined, estimatedDays);
      setPlanner((prev) => ({ ...prev, [plan.id]: plan }));
    },
    [setPlanner]
  );
  const createPlan = useCallback(
    (
      surahId: number,
      targetVerses: number,
      planName?: string,
      estimatedDays?: number,
      range?: PlannerPlanRangeConfig
    ) => {
      const plan = createPlannerPlan(surahId, targetVerses, planName, estimatedDays, range);
      setPlanner((prev) => ({ ...prev, [plan.id]: plan }));
    },
    [setPlanner]
  );
  const updateProgress = useCallback(
    (planId: string, completed: number) => {
      setPlanner((prev) => updatePlannerProgress(prev, planId, completed));
    },
    [setPlanner]
  );
  const removeFromPlanner = useCallback(
    (planId: string) => {
      setPlanner((prev) => {
        const next = { ...prev };
        delete next[planId];
        return next;
      });
    },
    [setPlanner]
  );
  return {
    addToPlanner,
    createPlannerPlan: createPlan,
    updatePlannerProgress: updateProgress,
    removeFromPlanner,
  };
}

import { getItem, setItem, removeItem } from '@/lib/utils/safeLocalStorage';
import { Folder, Bookmark, PlannerPlan, LastReadMap, LastReadEntry } from '@/types';

import {
  BOOKMARKS_STORAGE_KEY,
  OLD_BOOKMARKS_STORAGE_KEY,
  PINNED_STORAGE_KEY,
  LAST_READ_STORAGE_KEY,
  PLANNER_STORAGE_KEY,
  LEGACY_MEMORIZATION_STORAGE_KEY,
} from './constants';

const normalizeBookmark = (bookmark: Bookmark): Bookmark => ({
  ...bookmark,
  verseId: String((bookmark as Bookmark & { verseId: string | number }).verseId),
});

const normalizeFolders = (folders: Folder[]): Folder[] =>
  folders.map((folder) => ({
    ...folder,
    bookmarks: folder.bookmarks.map(normalizeBookmark),
  }));

export const loadBookmarksFromStorage = (): Folder[] => {
  if (typeof window === 'undefined') return [];

  const savedFolders = getItem(BOOKMARKS_STORAGE_KEY);
  if (savedFolders) {
    try {
      const parsed = JSON.parse(savedFolders) as Folder[];
      return Array.isArray(parsed) ? normalizeFolders(parsed) : [];
    } catch {
      return [];
    }
  }

  // Migration from old format
  const oldBookmarks = getItem(OLD_BOOKMARKS_STORAGE_KEY);
  if (oldBookmarks) {
    try {
      const verseIds: string[] = JSON.parse(oldBookmarks);
      if (Array.isArray(verseIds) && verseIds.every((id) => typeof id === 'string')) {
        const migratedFolder: Folder = {
          id:
            typeof globalThis.crypto !== 'undefined' &&
            typeof globalThis.crypto.randomUUID === 'function'
              ? globalThis.crypto.randomUUID()
              : `migrated-${Date.now()}`,
          name: 'Uncategorized',
          createdAt: Date.now(),
          bookmarks: verseIds.map((verseId) => ({
            verseId,
            createdAt: Date.now(),
          })),
        };
        removeItem(OLD_BOOKMARKS_STORAGE_KEY);
        return normalizeFolders([migratedFolder]);
      }
    } catch {
      return [];
    }
  }

  return [];
};

export const saveBookmarksToStorage = (folders: Folder[]): void => {
  if (typeof window !== 'undefined') {
    setItem(BOOKMARKS_STORAGE_KEY, JSON.stringify(folders));
  }
};

export const loadPinnedFromStorage = (): Bookmark[] => {
  if (typeof window === 'undefined') return [];

  const savedPinned = getItem(PINNED_STORAGE_KEY);
  if (savedPinned) {
    try {
      const parsed = JSON.parse(savedPinned) as Bookmark[];
      return Array.isArray(parsed) ? parsed.map(normalizeBookmark) : [];
    } catch {
      return [];
    }
  }
  return [];
};

export const savePinnedToStorage = (pinnedVerses: Bookmark[]): void => {
  if (typeof window !== 'undefined') {
    setItem(PINNED_STORAGE_KEY, JSON.stringify(pinnedVerses));
  }
};

const normalizeLastReadEntry = (
  value: unknown,
  fallbackUpdatedAt: number
): LastReadEntry | null => {
  if (typeof value === 'number' && Number.isFinite(value) && value > 0) {
    return {
      verseNumber: value,
      verseId: value,
      updatedAt: fallbackUpdatedAt,
    };
  }

  if (value && typeof value === 'object') {
    const maybeEntry = value as Partial<LastReadEntry> & { verseId?: unknown };

    const verseNumber =
      typeof maybeEntry.verseNumber === 'number' && Number.isFinite(maybeEntry.verseNumber)
        ? maybeEntry.verseNumber
        : typeof maybeEntry.verseId === 'number' && Number.isFinite(maybeEntry.verseId)
          ? maybeEntry.verseId
          : typeof maybeEntry.verseKey === 'string'
            ? Number(maybeEntry.verseKey.split(':')[1])
            : undefined;

    if (!verseNumber || Number.isNaN(verseNumber) || verseNumber <= 0) {
      return null;
    }

    const updatedAt =
      typeof maybeEntry.updatedAt === 'number' && Number.isFinite(maybeEntry.updatedAt)
        ? maybeEntry.updatedAt
        : fallbackUpdatedAt;

    const entry: LastReadEntry = {
      verseNumber,
      updatedAt,
      ...(typeof maybeEntry.verseKey === 'string' && maybeEntry.verseKey.length > 0
        ? { verseKey: maybeEntry.verseKey }
        : {}),
      ...(typeof maybeEntry.globalVerseId === 'number' && Number.isFinite(maybeEntry.globalVerseId)
        ? { globalVerseId: maybeEntry.globalVerseId }
        : {}),
      verseId: verseNumber,
    };

    return entry;
  }

  return null;
};

export const loadLastReadFromStorage = (): LastReadMap => {
  if (typeof window === 'undefined') return {};

  const savedLastRead = getItem(LAST_READ_STORAGE_KEY);
  if (savedLastRead) {
    try {
      const raw = JSON.parse(savedLastRead) as Record<string, unknown>;
      if (!raw || typeof raw !== 'object') {
        return {};
      }

      const entries = Object.entries(raw);
      const now = Date.now();

      return entries.reduce<LastReadMap>((acc, [surahId, value], index) => {
        const entry = normalizeLastReadEntry(value, now - index);
        if (entry) {
          acc[surahId] = entry;
        }
        return acc;
      }, {});
    } catch {
      return {};
    }
  }
  return {};
};

export const saveLastReadToStorage = (lastRead: LastReadMap): void => {
  if (typeof window !== 'undefined') {
    setItem(LAST_READ_STORAGE_KEY, JSON.stringify(lastRead));
  }
};

const normalizePlannerRecord = (input: unknown): Record<string, PlannerPlan> => {
  if (!input || typeof input !== 'object' || Array.isArray(input)) {
    return {};
  }

  const entries = Object.entries(input as Record<string, PlannerPlan>);
  if (entries.length === 0) {
    return {};
  }

  return entries.reduce<Record<string, PlannerPlan>>((acc, [, value]) => {
    if (value && typeof value === 'object' && 'id' in value) {
      const plan = value as PlannerPlan;
      acc[plan.id] = plan;
    }
    return acc;
  }, {});
};

export const loadPlannerFromStorage = (): Record<string, PlannerPlan> => {
  if (typeof window === 'undefined') return {};

  const savedPlanner = getItem(PLANNER_STORAGE_KEY);
  if (savedPlanner) {
    try {
      return normalizePlannerRecord(JSON.parse(savedPlanner));
    } catch {
      return {};
    }
  }

  const legacy = getItem(LEGACY_MEMORIZATION_STORAGE_KEY);
  if (legacy) {
    try {
      const parsed = normalizePlannerRecord(JSON.parse(legacy));
      removeItem(LEGACY_MEMORIZATION_STORAGE_KEY);
      setItem(PLANNER_STORAGE_KEY, JSON.stringify(parsed));
      return parsed;
    } catch {
      return {};
    }
  }

  return {};
};

export const savePlannerToStorage = (planner: Record<string, PlannerPlan>): void => {
  if (typeof window !== 'undefined') {
    setItem(PLANNER_STORAGE_KEY, JSON.stringify(planner));
    removeItem(LEGACY_MEMORIZATION_STORAGE_KEY);
  }
};

