import clsx from 'clsx';
import {
  memo,
  type FormEvent,
  type ReactElement,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from 'react';

import { SurahVerseSelector } from '@/app/shared/components/SurahVerseSelector';
import { BookOpenIcon, HashIcon } from '@/app/shared/icons';
import { useSurahNavigationData } from '@/app/shared/navigation/hooks/useSurahNavigationData';
import { Button } from '@/app/shared/ui/Button';

// Search suggestion examples - just labels to fill the search box
const SEARCH_SUGGESTIONS = [
  { label: 'Juz 1', icon: 'juz' },
  { label: 'Page 1', icon: 'page' },
  { label: 'Surah Yasin', icon: 'surah' },
  { label: '2:255', icon: 'ayah' },
];

interface GoToSurahVerseFormProps {
  onNavigate: (surahId: number, verse?: number) => void;
  /** Called when user clicks a search suggestion - fills the search box */
  onSearchSuggestion?: (query: string) => void;
  afterNavigate?: () => void;
  className?: string;
  title?: string;
  subtitle?: string;
  buttonLabel?: string;
}

export const GoToSurahVerseForm = memo(function GoToSurahVerseForm({
  onNavigate,
  onSearchSuggestion,
  afterNavigate,
  className,
  title = 'Search or Go To',
  subtitle,
  buttonLabel = 'Go',
}: GoToSurahVerseFormProps): ReactElement {
  const [selectedSurah, setSelectedSurah] = useState<number | undefined>(undefined);
  const [verse, setVerse] = useState<number | undefined>(undefined);
  const { chapters, isLoading } = useSurahNavigationData();

  const activeChapter = useMemo(
    () => (selectedSurah ? chapters.find((c) => c.id === selectedSurah) : undefined),
    [chapters, selectedSurah]
  );

  // Reset verse if surah changes or if invalid
  useEffect(() => {
    if (!selectedSurah) {
      setVerse(undefined);
      return;
    }
    if (activeChapter?.verses_count && verse && verse > activeChapter.verses_count) {
      setVerse(activeChapter.verses_count);
    }
  }, [selectedSurah, activeChapter, verse]);

  const handleSubmit = useCallback(
    (event: FormEvent<HTMLFormElement>): void => {
      event.preventDefault();
      if (!selectedSurah) return;
      onNavigate(selectedSurah, verse);
      afterNavigate?.();
    },
    [afterNavigate, onNavigate, selectedSurah, verse]
  );

  const handleVerseComplete = useCallback(
    (verseNum: number) => {
      if (selectedSurah) {
        onNavigate(selectedSurah, verseNum);
        afterNavigate?.();
      }
    },
    [afterNavigate, onNavigate, selectedSurah]
  );

  // Get icon for suggestion type
  const getSuggestionIcon = (iconType: string): ReactElement => {
    switch (iconType) {
      case 'juz':
        return <span className="text-[10px] font-bold text-accent">J</span>;
      case 'page':
        return <span className="text-[10px] font-bold text-accent">P</span>;
      case 'surah':
        return <BookOpenIcon size={14} className="text-accent" />;
      case 'ayah':
        return <HashIcon size={14} className="text-accent" />;
      default:
        return <BookOpenIcon size={14} className="text-accent" />;
    }
  };

  const disabled = !selectedSurah || isLoading;
  const subtitleText = subtitle ?? (isLoading ? 'Loading surahs…' : undefined);

  return (
    <form
      className={clsx('pt-4 px-6 pb-6 sm:pt-5 sm:px-8 sm:pb-8 space-y-4 text-left', className)}
      onSubmit={handleSubmit}
    >
      <div className="flex items-center justify-between gap-3">
        <div className="space-y-1 min-w-0">
          <div className="text-lg font-semibold text-foreground leading-tight">{title}</div>
          {subtitleText ? <div className="text-sm text-muted">{subtitleText}</div> : null}
        </div>
        <Button
          type="submit"
          disabled={disabled}
          size="sm"
          className="rounded-lg px-6 min-h-0 h-8 flex-shrink-0"
        >
          {buttonLabel}
        </Button>
      </div>

      <SurahVerseSelector
        chapters={chapters}
        isLoading={isLoading}
        selectedSurah={selectedSurah}
        selectedVerse={verse}
        onSurahChange={setSelectedSurah}
        onVerseChange={setVerse}
        onVerseSelectionComplete={handleVerseComplete}
        verseLabel="Verse"
      />

      {/* Search Suggestions - clicking fills the search box */}
      {onSearchSuggestion && (
        <div className="pt-3 border-t border-border/50">
          <div className="text-xs font-medium text-muted mb-2">Or try searching</div>
          <div className="grid grid-cols-2 gap-1.5">
            {SEARCH_SUGGESTIONS.map((suggestion) => (
              <button
                key={suggestion.label}
                type="button"
                onClick={() => onSearchSuggestion(suggestion.label)}
                className="flex items-center gap-2 px-2.5 py-2 rounded-lg text-left transition-colors hover:bg-interactive/60 group"
              >
                <div className="w-5 h-5 rounded bg-accent/10 flex items-center justify-center flex-shrink-0 group-hover:bg-accent/20 transition-colors">
                  {getSuggestionIcon(suggestion.icon)}
                </div>
                <span className="text-sm text-foreground truncate">{suggestion.label}</span>
              </button>
            ))}
          </div>
        </div>
      )}
    </form>
  );
});

'use client';

import clsx from 'clsx';
import {
  memo,
  forwardRef,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
  useId,
  useLayoutEffect,
  useImperativeHandle,
  type ChangeEvent,
  type FocusEvent,
  type KeyboardEvent,
  type ReactElement,
} from 'react';
import { createPortal } from 'react-dom';

import { ChevronDownIcon } from '@/app/shared/icons';

const DROPDOWN_MAX_HEIGHT = 28 * 16;

export interface SurahOption {
  value: string;
  label: string;
}

interface SurahSelectProps {
  value: string;
  onChange: (value: string) => void;
  options: SurahOption[];
  placeholder?: string;
  disabled?: boolean;
  className?: string;
  clearable?: boolean;
  clearLabel?: string;
  inputId?: string;
  onSelectionComplete?: (value: string) => void;
}

/**
 * Searchable combobox used for Surah and verse selection.
 * Users can type values directly while still getting a styled dropdown list.
 */
export const SurahSelect = memo(
  forwardRef<HTMLInputElement, SurahSelectProps>(function SurahSelect(
    {
      value,
      onChange,
      options,
      placeholder = 'Select an option',
      disabled = false,
      className,
      clearable = false,
      clearLabel = 'Clear selection',
      inputId: inputIdProp,
      onSelectionComplete,
    },
    ref
  ): ReactElement {
    const [open, setOpen] = useState(false);
    const [inputValue, setInputValue] = useState('');
    const [activeIndex, setActiveIndex] = useState(0);
    const [isTyping, setIsTyping] = useState(false);
    // Track if user is interacting with the dropdown list (for mobile scroll)
    const isInteractingWithListRef = useRef(false);

    const containerRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);
    const listRef = useRef<HTMLDivElement>(null);
    const listboxId = useId();
    const generatedInputId = useId();
    const inputId = inputIdProp ?? generatedInputId;

    useImperativeHandle(ref, () => inputRef.current as HTMLInputElement);

    const [dropdownStyle, setDropdownStyle] = useState<{
      top?: number;
      bottom?: number;
      left: number;
      width: number;
      maxHeight: number;
    }>({
      left: 0,
      width: 0,
      maxHeight: DROPDOWN_MAX_HEIGHT,
    });

    const selectedOption = useMemo(
      () => options.find((option) => option.value === value),
      [options, value]
    );

    useEffect(() => {
      const selectedIdx = options.findIndex((option) => option.value === value);
      if (selectedIdx >= 0) {
        setActiveIndex(selectedIdx);
      } else if (!options.length) {
        setActiveIndex(-1);
      }
    }, [options, value]);

    useEffect(() => {
      if (!isTyping) {
        setInputValue(selectedOption?.label ?? '');
      }
    }, [isTyping, selectedOption]);

    // Close dropdown when clicking outside (desktop only - mobile handled differently)
    useEffect(() => {
      if (!open) return;
      const handler = (event: MouseEvent): void => {
        const target = event.target as Node | null;
        if (containerRef.current?.contains(target) || listRef.current?.contains(target)) return;
        isInteractingWithListRef.current = false;
        if (isTyping) setIsTyping(false);
        setInputValue(selectedOption?.label ?? '');
        setOpen(false);
      };
      window.addEventListener('mousedown', handler);
      return () => window.removeEventListener('mousedown', handler);
    }, [isTyping, open, selectedOption?.label]);

    const handleContainerBlur = useCallback(
      (event: FocusEvent<HTMLDivElement>) => {
        // On mobile, when user touches the list, focus leaves the input
        // We use a small delay to check if the touch was on the list
        setTimeout(() => {
          // If still interacting with list, don't close
          if (isInteractingWithListRef.current) return;

          const next = event.relatedTarget as Node | null;
          if (next && (containerRef.current?.contains(next) || listRef.current?.contains(next)))
            return;
          if (isTyping) setIsTyping(false);
          setInputValue(selectedOption?.label ?? '');
          setOpen(false);
        }, 50);
      },
      [isTyping, selectedOption?.label]
    );

    const updateDropdownMetrics = useCallback(() => {
      if (!open || !containerRef.current) return;

      const rect = containerRef.current.getBoundingClientRect();
      const spaceBelow = window.innerHeight - rect.bottom;
      const spaceAbove = rect.top;
      const needsFlip = spaceBelow < 280 && spaceAbove > spaceBelow;

      const width = rect.width;
      const left = rect.left;

      if (needsFlip) {
        // Position above
        setDropdownStyle({
          bottom: window.innerHeight - rect.top + 8,
          left,
          width,
          maxHeight: Math.min(DROPDOWN_MAX_HEIGHT, spaceAbove - 20),
        });
      } else {
        // Position below
        setDropdownStyle({
          top: rect.bottom + 8,
          left,
          width,
          maxHeight: Math.min(DROPDOWN_MAX_HEIGHT, Math.max(150, spaceBelow - 20)),
        });
      }
    }, [open]);

    useLayoutEffect(() => {
      if (!open) return;
      updateDropdownMetrics();

      const handleResize = (event?: Event): void => {
        if (event?.type === 'scroll' && listRef.current && event.target === listRef.current) {
          return;
        }
        updateDropdownMetrics();
      };

      window.addEventListener('resize', handleResize);
      window.addEventListener('scroll', handleResize, true);
      return (): void => {
        window.removeEventListener('resize', handleResize);
        window.removeEventListener('scroll', handleResize, true);
      };
    }, [open, updateDropdownMetrics]);

    const handleInputChange = useCallback(
      (event: ChangeEvent<HTMLInputElement>) => {
        const next = event.target.value;
        setInputValue(next);
        setIsTyping(true);
        if (!open) setOpen(true);
        if (!next.trim()) {
          onChange('');
          setActiveIndex(0);
          return;
        }

        const query = next.trim().toLowerCase();
        const matchIndex = options.findIndex(
          (option) =>
            option.value.toLowerCase().startsWith(query) ||
            option.label.toLowerCase().includes(query)
        );
        if (matchIndex >= 0) {
          const matchedOption = options[matchIndex];
          if (matchedOption) {
            onChange(matchedOption.value);
            setActiveIndex(matchIndex);
          }
        }
      },
      [onChange, open, options]
    );

    const handleOptionSelect = useCallback(
      (option: SurahOption) => {
        onChange(option.value);
        setInputValue(option.label);
        setIsTyping(false);
        setOpen(false);
        onSelectionComplete?.(option.value);
      },
      [onChange, onSelectionComplete]
    );

    const handleInputKeyDown = useCallback(
      (event: KeyboardEvent<HTMLInputElement>) => {
        if (disabled) return;

        if (event.key === 'ArrowDown' || event.key === 'ArrowUp') {
          event.preventDefault();
          if (!open) setOpen(true);
          if (!options.length) return;
          setActiveIndex((prev) => {
            if (prev < 0) return 0;
            const delta = event.key === 'ArrowDown' ? 1 : -1;
            return Math.min(Math.max(prev + delta, 0), options.length - 1);
          });
          return;
        }

        if (event.key === 'Enter') {
          event.preventDefault();
          const option = options[activeIndex] ?? options[0];
          if (option) handleOptionSelect(option);
          return;
        }

        if (event.key === 'Escape') {
          event.preventDefault();
          setOpen(false);
          setIsTyping(false);
          setInputValue(selectedOption?.label ?? '');
        }
      },
      [activeIndex, disabled, handleOptionSelect, open, options, selectedOption?.label]
    );

    useEffect(() => {
      if (!open || activeIndex < 0 || !listRef.current) return;
      const optionEl = listRef.current.querySelector<HTMLButtonElement>(
        `[data-index="${activeIndex}"]`
      );

      if (optionEl && listRef.current) {
        const container = listRef.current;
        const containerRect = container.getBoundingClientRect();
        const optionRect = optionEl.getBoundingClientRect();
        const optionOffset = optionRect.top - containerRect.top + container.scrollTop;
        const topOffset = 8;
        const scrollOffset = isTyping
          ? Math.max(optionOffset - topOffset, 0)
          : optionOffset - container.clientHeight / 2 + optionEl.clientHeight / 2;
        container.scrollTo({
          top: scrollOffset,
          behavior: 'instant', // Use instant to prevent fighting with user scroll
        });
      }
    }, [activeIndex, isTyping, open]);

    const toggleList = useCallback(() => {
      if (disabled || !options.length) return;
      setOpen((prev) => !prev);
      inputRef.current?.focus();
    }, [disabled, options.length]);

    return (
      <div className={clsx('relative', className)} ref={containerRef} onBlur={handleContainerBlur}>
        <div
          className={clsx(
            'relative rounded-lg border border-border bg-interactive/60 transition-colors focus-within:border-transparent focus-within:ring-2 focus-within:ring-accent',
            disabled ? 'opacity-60 cursor-not-allowed' : ''
          )}
        >
          <input
            ref={inputRef}
            type="text"
            role="combobox"
            aria-expanded={open}
            aria-controls={listboxId}
            aria-disabled={disabled}
            id={inputId}
            value={inputValue}
            placeholder={placeholder}
            disabled={disabled}
            onChange={handleInputChange}
            onFocus={(): void => {
              if (!disabled) setOpen(true);
            }}
            onKeyDown={handleInputKeyDown}
            className={clsx(
              'w-full bg-transparent text-foreground text-sm px-3 py-3 pr-7 rounded-lg outline-none placeholder:text-muted'
            )}
          />
          <div className="pointer-events-none absolute inset-y-0 right-2 flex items-center gap-2 text-muted">
            {clearable && !disabled && value ? (
              <button
                type="button"
                aria-label={clearLabel}
                className="pointer-events-auto hover:text-foreground transition-colors"
                onClick={(event): void => {
                  event.preventDefault();
                  event.stopPropagation();
                  setInputValue('');
                  setIsTyping(false);
                  onChange('');
                  inputRef.current?.focus();
                }}
              >
                ×
              </button>
            ) : null}
            <button
              type="button"
              className="pointer-events-auto hover:text-foreground transition-colors"
              aria-label="Toggle options"
              disabled={disabled}
              onClick={(event): void => {
                event.preventDefault();
                event.stopPropagation();
                toggleList();
              }}
            >
              <ChevronDownIcon size={18} />
            </button>
          </div>
        </div>

        {open && typeof document !== 'undefined'
          ? createPortal(
              <div
                ref={listRef}
                id={listboxId}
                role="listbox"
                aria-activedescendant={
                  activeIndex >= 0 ? `${listboxId}-option-${activeIndex}` : undefined
                }
                tabIndex={-1}
                data-surah-select-portal="true"
                className={clsx(
                  'fixed z-[9999] overflow-auto rounded-lg border border-border/40 bg-surface shadow-lg focus:outline-none py-2'
                )}
                style={{
                  top: dropdownStyle.top,
                  bottom: dropdownStyle.bottom,
                  left: dropdownStyle.left,
                  width: dropdownStyle.width,
                  maxHeight: dropdownStyle.maxHeight,
                }}
                onPointerDown={() => {
                  // Mark interaction to prevent close on blur (works for both mouse and touch)
                  isInteractingWithListRef.current = true;
                  // On touch, blur input to hide keyboard
                  inputRef.current?.blur();
                }}
                onPointerUp={() => {
                  setTimeout(() => {
                    isInteractingWithListRef.current = false;
                  }, 100);
                }}
                onScroll={() => {
                  // Hide keyboard when scrolling
                  isInteractingWithListRef.current = true;
                  inputRef.current?.blur();
                  setTimeout(() => {
                    isInteractingWithListRef.current = false;
                  }, 100);
                }}
              >
                <div className="space-y-1 px-1">
                  {options.map((option, index) => {
                    const selected = option.value === value;
                    const isActive = index === activeIndex;
                    const optionId = `${listboxId}-option-${index}`;
                    return (
                      <button
                        key={option.value}
                        id={optionId}
                        type="button"
                        role="option"
                        aria-selected={selected}
                        data-index={index}
                        onClick={(): void => handleOptionSelect(option)}
                        className={clsx(
                          'w-full text-left px-4 py-2.5 rounded-lg text-sm transition-colors',
                          selected
                            ? 'bg-interactive text-foreground'
                            : isActive
                              ? 'bg-interactive text-foreground'
                              : 'text-foreground hover:bg-interactive'
                        )}
                      >
                        <span className="block truncate">{option.label}</span>
                      </button>
                    );
                  })}
                  {isTyping ? (
                    <div
                      aria-hidden="true"
                      className="pointer-events-none"
                      style={{ height: dropdownStyle.maxHeight }}
                    />
                  ) : null}
                </div>
              </div>,
              document.body
            )
          : null}
      </div>
    );
  })
);

'use client';

import { Settings } from 'lucide-react';
import { usePathname } from 'next/navigation';
import { memo, type ReactElement, useCallback } from 'react';

import { useUIState } from '@/app/providers/UIStateContext';

export const HeaderActions = memo(function HeaderActions(): ReactElement {
  const { setSettingsOpen } = useUIState();
  const pathname = usePathname();

  // These pages have NO settings sidebar at all (not even on desktop 2xl),
  // so we should hide the gear icon completely and show a placeholder for centering
  const NO_SETTINGS_PAGES = [
    '/bookmarks/folders',
    '/bookmarks/last-read',
    '/bookmarks/planner',
    '/bookmarks',
  ];

  // Check for exact match or if it starts with bookmarks but is not pinned/folder detail
  const isNoSettingsPage = NO_SETTINGS_PAGES.includes(pathname) || pathname === '/bookmarks';

  const openSettings = useCallback((): void => {
    setSettingsOpen(true);
  }, [setSettingsOpen]);

  // Pages with no settings sidebar at all - show placeholder for centering at all sizes
  // On mobile (< xl): show 44px placeholder to match hamburger menu button
  // On desktop (>= sm): use w-1/3 to match HeaderBrand's w-1/3
  if (isNoSettingsPage) {
    return <div className="w-11 h-11 sm:w-1/3 shrink-0" aria-hidden="true" />;
  }

  // Pages that have settings sidebar (shows at 2xl) - show gear icon below 2xl
  return (
    <div className="flex items-center justify-end gap-2 sm:gap-2.5 w-auto sm:w-1/3 mr-1">
      {/* Settings button - visible when settings sidebar is hidden (< 2xl) */}
      <button
        onClick={openSettings}
        className="btn-touch p-2.5 rounded-xl hover:bg-interactive-hover hover:text-accent transition-all duration-200 active:scale-95 2xl:hidden flex items-center justify-center"
        aria-label="Open settings"
      >
        <Settings size={18} className="text-muted" />
      </button>
    </div>
  );
});

'use client';

import { Menu } from 'lucide-react';
import Link from 'next/link';
