import { useSidebar } from '@/app/providers/SidebarContext';

export const HeaderBrand = memo(function HeaderBrand(): ReactElement {
  const { setSurahListOpen, setBookmarkSidebarOpen, setSearchSidebarOpen } = useSidebar();

  const pathname = usePathname();

  const isNavPath = (path?: string | null): boolean =>
    Boolean(
      path &&
      (path.startsWith('/surah') ||
        path.startsWith('/tafsir') ||
        path.startsWith('/juz') ||
        path.startsWith('/page'))
    );
  const isBookmarkPath = (path?: string | null): boolean =>
    Boolean(path && path.startsWith('/bookmarks'));
  const isSearchPath = (path?: string | null): boolean =>
    Boolean(path && path.startsWith('/search'));

  const shouldShowMenu = isNavPath(pathname) || isBookmarkPath(pathname) || isSearchPath(pathname);

  const handleMobileNavClick = useCallback((): void => {
    if (isBookmarkPath(pathname)) {
      setBookmarkSidebarOpen(true);
      return;
    }
    if (isSearchPath(pathname)) {
      setSearchSidebarOpen(true);
      return;
    }
    if (isNavPath(pathname)) {
      setSurahListOpen(true);
    }
  }, [pathname, setBookmarkSidebarOpen, setSearchSidebarOpen, setSurahListOpen]);

  return (
    <div className="flex items-center justify-start w-auto sm:w-1/3 gap-1">
      {/* Mobile Navigation Menu Button */}
      {shouldShowMenu && (
        <button
          onClick={handleMobileNavClick}
          className="btn-touch p-2.5 rounded-xl hover:bg-muted/60 transition-all duration-200 active:scale-95 xl:hidden flex items-center justify-center"
          aria-label="Open navigation"
        >
          <Menu size={18} className="text-muted" />
        </button>
      )}

      {/* PC: Brand Link (Hidden on mobile) */}
      <Link
        href="/"
        className="hidden xl:flex items-center space-x-2 hover:opacity-80 transition-opacity ml-2"
      >
        {/* Logo Removed on PC as per request, implicitly */}
        <span className="font-semibold text-lg text-foreground">Al Quran</span>
      </Link>
    </div>
  );
});

import { fireEvent, render, screen } from '@testing-library/react';
import React from 'react';

import { UnifiedModal } from '@/app/shared/components/modal/UnifiedModal';

// Mock framer-motion to avoid animation timing issues in tests
jest.mock('framer-motion', () => ({
  motion: {
    div: ({ children, ...props }: any) => {
      // Strip motion-only props to avoid React warnings
      const domProps = { ...props };
      delete domProps.variants;
      delete domProps.initial;
      delete domProps.animate;
      delete domProps.exit;
      delete domProps.transition;
      return React.createElement('div', domProps, children);
    },
  },
  AnimatePresence: ({ children }: any) => <>{children}</>,
}));

describe('UnifiedModal', () => {
  it('locks page scrolling while open', async () => {
    const previousHtmlOverflow = document.documentElement.style.overflow;
    const previousBodyOverflow = document.body.style.overflow;

    document.documentElement.style.overflow = 'auto';
    document.body.style.overflow = 'auto';

    const { rerender } = render(
      <UnifiedModal isOpen onClose={jest.fn()} ariaLabel="Test modal">
        Content
      </UnifiedModal>
    );

    await screen.findByRole('dialog', { name: 'Test modal' });

    expect(document.documentElement.style.overflow).toBe('hidden');
    expect(document.body.style.overflow).toBe('hidden');

    rerender(
      <UnifiedModal isOpen={false} onClose={jest.fn()} ariaLabel="Test modal">
        Content
      </UnifiedModal>
    );

    expect(document.documentElement.style.overflow).toBe('auto');
    expect(document.body.style.overflow).toBe('auto');

    document.documentElement.style.overflow = previousHtmlOverflow;
    document.body.style.overflow = previousBodyOverflow;
  });

  it('keeps scrolling locked until all modals close', async () => {
    const previousHtmlOverflow = document.documentElement.style.overflow;
    const previousBodyOverflow = document.body.style.overflow;

    document.documentElement.style.overflow = 'auto';
    document.body.style.overflow = 'auto';

    const { rerender } = render(
      <>
        <UnifiedModal isOpen onClose={jest.fn()} ariaLabel="Modal A">
          A
        </UnifiedModal>
        <UnifiedModal isOpen onClose={jest.fn()} ariaLabel="Modal B">
          B
        </UnifiedModal>
      </>
    );

    expect(await screen.findByRole('dialog', { name: 'Modal A' })).toBeInTheDocument();
    expect(screen.getByRole('dialog', { name: 'Modal B' })).toBeInTheDocument();
    expect(document.documentElement.style.overflow).toBe('hidden');
    expect(document.body.style.overflow).toBe('hidden');

    rerender(
      <>
        <UnifiedModal isOpen={false} onClose={jest.fn()} ariaLabel="Modal A">
          A
        </UnifiedModal>
        <UnifiedModal isOpen onClose={jest.fn()} ariaLabel="Modal B">
          B
        </UnifiedModal>
      </>
    );

    expect(document.documentElement.style.overflow).toBe('hidden');
    expect(document.body.style.overflow).toBe('hidden');

    rerender(
      <>
        <UnifiedModal isOpen={false} onClose={jest.fn()} ariaLabel="Modal A">
          A
        </UnifiedModal>
        <UnifiedModal isOpen={false} onClose={jest.fn()} ariaLabel="Modal B">
          B
        </UnifiedModal>
      </>
    );

    expect(document.documentElement.style.overflow).toBe('auto');
    expect(document.body.style.overflow).toBe('auto');

    document.documentElement.style.overflow = previousHtmlOverflow;
    document.body.style.overflow = previousBodyOverflow;
  });

  it('does not render when closed', () => {
    render(
      <UnifiedModal isOpen={false} onClose={jest.fn()}>
        Content
      </UnifiedModal>
    );

    expect(screen.queryByRole('dialog')).not.toBeInTheDocument();
  });

  it('renders dialog content when open', async () => {
    render(
      <UnifiedModal isOpen onClose={jest.fn()} ariaLabel="Test modal">
        Content
      </UnifiedModal>
    );

    expect(await screen.findByRole('dialog', { name: 'Test modal' })).toBeInTheDocument();
    expect(screen.getByText('Content')).toBeInTheDocument();
  });

  it('closes on Escape by default', async () => {
    const onClose = jest.fn();
    render(
      <UnifiedModal isOpen onClose={onClose} ariaLabel="Test modal">
        Content
      </UnifiedModal>
    );

    await screen.findByRole('dialog', { name: 'Test modal' });
    fireEvent.keyDown(document, { key: 'Escape' });

    expect(onClose).toHaveBeenCalledTimes(1);
  });

  it('does not close on Escape when disabled', async () => {
    const onClose = jest.fn();
    render(
      <UnifiedModal isOpen onClose={onClose} closeOnEscape={false} ariaLabel="Test modal">
        Content
      </UnifiedModal>
    );

    await screen.findByRole('dialog', { name: 'Test modal' });
    fireEvent.keyDown(document, { key: 'Escape' });

    expect(onClose).not.toHaveBeenCalled();
  });

  it('closes on overlay click by default', async () => {
    const onClose = jest.fn();
    render(
      <UnifiedModal
        isOpen
        onClose={onClose}
        ariaLabel="Test modal"
        backdropClassName="test-backdrop"
      >
        Content
      </UnifiedModal>
    );

    await screen.findByRole('dialog', { name: 'Test modal' });

    const backdrop = document.querySelector('.test-backdrop');
    expect(backdrop).toBeInTheDocument();
    if (!backdrop) return;

    fireEvent.click(backdrop);
    expect(onClose).toHaveBeenCalledTimes(1);
  });

  it('does not close on overlay click when disabled', async () => {
    const onClose = jest.fn();
    render(
      <UnifiedModal
        isOpen
        onClose={onClose}
        closeOnOverlayClick={false}
        ariaLabel="Test modal"
        backdropClassName="test-backdrop"
      >
        Content
      </UnifiedModal>
    );

    await screen.findByRole('dialog', { name: 'Test modal' });

    const backdrop = document.querySelector('.test-backdrop');
    expect(backdrop).toBeInTheDocument();
    if (!backdrop) return;

    fireEvent.click(backdrop);
    expect(onClose).not.toHaveBeenCalled();
  });
});

import { cn } from '@/lib/utils/cn';

type DesktopBreakpoint = 'lg' | 'xl' | '2xl';

interface UseSidebarPositioningOptions {
  position: 'left' | 'right';
  isOpen: boolean;
  isHeaderHidden: boolean;
  desktopBreakpoint?: DesktopBreakpoint;
}

interface UseSidebarPositioningReturn {
  getPositionClasses(): string;
}

export const useSidebarPositioning = ({
  position,
  isOpen,
  isHeaderHidden,
  desktopBreakpoint = 'lg',
}: UseSidebarPositioningOptions): UseSidebarPositioningReturn => {
  const breakpointClass =
    desktopBreakpoint === 'lg' ? 'lg' : desktopBreakpoint === 'xl' ? 'xl' : '2xl';
  const getPositionClasses = (): string => {
    const baseClasses = cn(
      // Use !fixed to avoid being overridden by any accidental 'relative'
      '!fixed w-full bg-surface transition-transform duration-300 ease-in-out will-change-transform',
      'sm:w-80',
      position === 'left'
        ? [
            'lg:w-reader-sidebar-left',
            desktopBreakpoint === 'xl' && 'xl:w-reader-sidebar-left',
            desktopBreakpoint === '2xl' && '2xl:w-reader-sidebar-left',
          ]
        : [
            'lg:w-reader-sidebar-right',
            desktopBreakpoint === 'xl' && 'xl:w-reader-sidebar-right',
            desktopBreakpoint === '2xl' && '2xl:w-reader-sidebar-right',
          ]
    );
    const headerAwareClasses = isHeaderHidden
      ? 'top-0 h-dvh'
      : cn(
          'top-0 h-dvh',
          breakpointClass === 'lg'
            ? 'lg:top-reader-header lg:h-[calc(100dvh-var(--reader-header-height))]'
            : breakpointClass === 'xl'
              ? 'xl:top-reader-header xl:h-[calc(100dvh-var(--reader-header-height))]'
              : '2xl:top-reader-header 2xl:h-[calc(100dvh-var(--reader-header-height))]'
        );

    const shadowClasses = isOpen
      ? position === 'left'
        ? breakpointClass === 'lg'
          ? 'mobile-sidebar-shadow-right lg:shadow-none'
          : breakpointClass === 'xl'
            ? 'mobile-sidebar-shadow-right xl:shadow-none'
            : 'mobile-sidebar-shadow-right 2xl:shadow-none'
        : breakpointClass === 'lg'
          ? 'mobile-sidebar-shadow-left lg:shadow-none'
          : breakpointClass === 'xl'
            ? 'mobile-sidebar-shadow-left xl:shadow-none'
            : 'mobile-sidebar-shadow-left 2xl:shadow-none'
      : '';
    const panelZIndex = 'z-[120]';
    const pinnedTranslateClass = `${breakpointClass}:translate-x-0`;

    if (position === 'left') {
      return cn(
        baseClasses,
        'left-0',
        breakpointClass === 'lg'
          ? 'lg:left-16'
          : breakpointClass === 'xl'
            ? 'xl:left-16'
            : '2xl:left-16',
        shadowClasses,
        headerAwareClasses,
        panelZIndex,
        isOpen ? 'translate-x-0' : '-translate-x-full',
        pinnedTranslateClass
      );
    }
    return cn(
      baseClasses,
      'right-0',
      shadowClasses,
      headerAwareClasses,
      panelZIndex,
      isOpen ? 'translate-x-0' : 'translate-x-full',
      pinnedTranslateClass
    );
  };

  return { getPositionClasses };
};

'use client';

import { memo } from 'react';

import type React from 'react';

/**
 * Converts Western Arabic numerals (0-9) to Eastern Arabic-Indic numerals (٠-٩)
 */
const toArabicIndic = (num: number): string => {
  const arabicIndicDigits = ['٠', '١', '٢', '٣', '٤', '٥', '٦', '٧', '٨', '٩'];
  return String(num)
    .split('')
    .map((digit) => arabicIndicDigits[Number.parseInt(digit, 10)] || digit)
    .join('');
};

type Point = { x: number; y: number };

interface FontAdjustment {
  ornament: Point;
  number: Point;
  containerWidth?: string;
  scale?: number;
}

const DEFAULT_ADJUSTMENT: FontAdjustment = {
  ornament: { x: 0, y: 0 },
  number: { x: 0, y: 0 },
};

const getFontAdjustment = (fontFamily: string | undefined): FontAdjustment => {
  return DEFAULT_ADJUSTMENT;
};

/**
 * List of fonts that have their own built-in verse ornament (U+06DD glyph)
 * These fonts should NOT use the custom overlay marker.
 */
export const FONTS_WITH_NATIVE_ORNAMENT = [
  'UthmanicHafs1Ver18', // QPC Uthmani Hafs - has ornament + number shaping
];

/**
 * Check if a font family string contains a font that has native ornament support
 */
export const fontHasNativeOrnament = (fontFamily: string | undefined): boolean => {
  if (!fontFamily) return false;
  return FONTS_WITH_NATIVE_ORNAMENT.some((font) => fontFamily.includes(font));
};

/**
 * Check if a font needs custom ornament
 */
export const fontNeedsCustomOrnament = (fontFamily: string | undefined): boolean => {
  if (!fontFamily) return true; // Default to custom if no font specified
  return !fontHasNativeOrnament(fontFamily);
};

interface VerseMarkerProps {
  verseNumber: number;
  /** Size of the marker in pixels (defaults to 1.2em relative to parent) */
  size?: number | undefined;
  /** Optional className for additional styling */
  className?: string | undefined;
  /** If true, use the marker even if font has native support */
  forceCustom?: boolean | undefined;
  /** Current font family to determine if custom marker is needed */
  fontFamily?: string | undefined;
}

/**
 * Text-based verse marker using U+06DD (۝) with an overlaid verse number.
 *
 * Avoids inline SVG for performance, while keeping a consistent verse marker
 * experience for fonts that don't support native ornament+number shaping.
 *
 * Note: This component is largely deprecated in favor of the "Unified Hafs Marker"
 * strategy in HybridVerseMarker, but kept for fallback or explicit usage.
 */
export const VerseMarker = memo(function VerseMarker({
  verseNumber,
  size,
  className = '',
  forceCustom = false,
  fontFamily,
}: VerseMarkerProps): React.JSX.Element | null {
  if (!forceCustom && fontHasNativeOrnament(fontFamily)) {
    return null;
  }

  const arabicNumber = toArabicIndic(verseNumber);
  const digitCount = String(verseNumber).length;
  const numberScale = digitCount === 1 ? 0.75 : digitCount === 2 ? 0.65 : 0.5;

  const adjustment = getFontAdjustment(fontFamily);
  const ornamentTransform = `translate(${adjustment.ornament.x}em, ${adjustment.ornament.y}em) scale(${adjustment.scale || 1})`;
  const numberTransform = `translate(${adjustment.number.x}em, ${adjustment.number.y}em)`;

  return (
    <span
      className={`relative inline-grid place-items-center leading-none text-current ${className}`}
      style={{
        fontSize: size ? `${size}px` : '1.2em',
        width: adjustment.containerWidth || '1em',
        height: '1em',
        unicodeBidi: 'isolate',
      }}
      aria-label={`Verse ${verseNumber}`}
      dir="rtl"
    >
      <span
        aria-hidden="true"
        style={{
          transform: ornamentTransform,
        }}
      >
        ۝
      </span>
      <span
        aria-hidden="true"
        dir="ltr"
        className="absolute inset-0 flex items-center justify-center font-bold leading-none"
        style={{ fontSize: `${numberScale}em`, transform: numberTransform }}
      >
        {arabicNumber}
      </span>
    </span>
  );
});

/**
 * Renders a verse marker using Arabic-Indic digits (٠-٩) in the KFGQPC font.
 *
 * In `UthmanicHafs1Ver18`, the digits are drawn as the end-of-ayah ornament with
 * the number inside (like Quran.com). Rendering `U+06DD` as well would produce
 * an extra empty ornament.
 */
export const NativeVerseMarker = ({
  verseNumber,
  className = '',
  fontFamily,
  style,
  size,
}: {
  verseNumber: number;
  className?: string;
  fontFamily?: string;
  style?: React.CSSProperties;
  size?: number;
}): React.JSX.Element => {
  const arabicNumber = toArabicIndic(verseNumber);
  const markerScale = 1.15;
  const baselineShiftEm = 0.08;
  const scaledFontSize =
    typeof size === 'number' ? `${Math.round(size * markerScale)}px` : `${markerScale}em`;

  return (
    <span
      className={`inline-block whitespace-nowrap ${className}`}
      dir="rtl"
      style={{
        fontFamily: fontFamily || 'UthmanicHafs1Ver18',
        fontSize: scaledFontSize,
        lineHeight: 1,
        unicodeBidi: 'isolate',
        ...style,
      }}
      aria-label={`Verse ${verseNumber}`}
    >
      <span
        aria-hidden="true"
        style={{
          display: 'inline-block',
          transform: `translateY(${baselineShiftEm}em)`,
        }}
      >
        {arabicNumber}
      </span>
    </span>
  );
};

/**
 * Hybrid verse marker that automatically selects between native and custom rendering
 * based on the current font's capabilities.
 */
export const HybridVerseMarker = ({
  verseNumber,
  fontFamily,
  className = '',
  size,
  style,
}: {
  verseNumber: number;
  fontFamily?: string;
  size?: number;
  className?: string;
  forceCustom?: boolean;
  style?: React.CSSProperties;
}): React.JSX.Element => {
  const optionalProps = {
    ...(typeof size === 'number' ? { size } : {}),
    ...(style ? { style } : {}),
  };

  // 1. If the current font supports native ornament (e.g. Uthmanic Hafs), use it.
  // This preserves the specific style of the main Quran font if it's capable.
  if (fontHasNativeOrnament(fontFamily)) {
    return <NativeVerseMarker verseNumber={verseNumber} className={className} {...optionalProps} />;
  }

  // 2. For ALL other fonts (Amiri, Me Quran, Lateef, etc.), use the Uthmanic Hafs font
  // to render a unified, high-quality text-based marker.
  // This satisfies the requirement for a "unified text-like thing" without using SVGs
  // and avoids alignment issues present in other fonts.
  return (
    <NativeVerseMarker
      verseNumber={verseNumber}
      className={className}
      fontFamily="UthmanicHafs1Ver18"
      {...optionalProps}
    />
  );
};

export default VerseMarker;

