'use client';

import React, { useCallback, useEffect, useMemo } from 'react';

import { SurahVerseSelector } from '@/app/shared/components/SurahVerseSelector';
import { useSurahNavigationData } from '@/app/shared/navigation/hooks/useSurahNavigationData';
import { CounterInput } from '@/app/shared/ui/inputs/CounterInput';
import { TabToggle } from '@/app/shared/ui/TabToggle';

import type { RepeatOptions } from '@/app/shared/player/types';

interface Props {
  localRepeat: RepeatOptions;
  setLocalRepeat: React.Dispatch<React.SetStateAction<RepeatOptions>>;
  rangeWarning: string | null;
  setRangeWarning: React.Dispatch<React.SetStateAction<string | null>>;
}

export function RepeatPanel({
  localRepeat,
  setLocalRepeat,
  rangeWarning,
  setRangeWarning,
}: Props): React.JSX.Element {
  useEffect(() => {
    setRangeWarning(null);
  }, [localRepeat.mode, setRangeWarning]);

  return (
    <div className="md:col-span-2 flex flex-col gap-4">
      <ModeSelector localRepeat={localRepeat} setLocalRepeat={setLocalRepeat} />
      <RepeatFields
        localRepeat={localRepeat}
        setLocalRepeat={setLocalRepeat}
        rangeWarning={rangeWarning}
        setRangeWarning={setRangeWarning}
      />
    </div>
  );
}

function ModeSelector({
  localRepeat,
  setLocalRepeat,
}: {
  localRepeat: RepeatOptions;
  setLocalRepeat: React.Dispatch<React.SetStateAction<RepeatOptions>>;
}): React.JSX.Element {
  const options = useMemo(
    () => [
      { value: 'single', label: 'Single' },
      { value: 'range', label: 'Range' },
      { value: 'surah', label: 'Surah' },
    ],
    []
  );

  return (
    <TabToggle
      options={options}
      value={localRepeat.mode}
      onChange={(val) => setLocalRepeat({ ...localRepeat, mode: val as RepeatOptions['mode'] })}
    />
  );
}

function RepeatFields({
  localRepeat,
  setLocalRepeat,
  rangeWarning,
  setRangeWarning,
}: Props): React.JSX.Element {
  const isSingle = localRepeat.mode === 'single';
  const isSurah = localRepeat.mode === 'surah';
  // Include 'off' in showRange for backward compatibility
  const showRange = localRepeat.mode === 'range' || localRepeat.mode === 'off';
  const { chapters, isLoading } = useSurahNavigationData();

  return (
    <div className="rounded-lg border border-border p-4 flex flex-col gap-4">
      {rangeWarning && <div className="text-sm text-status-warning">{rangeWarning}</div>}

      {/* Main Selection Area */}
      {isSingle ? (
        <SingleVerseFields
          localRepeat={localRepeat}
          setLocalRepeat={setLocalRepeat}
          setRangeWarning={setRangeWarning}
          chapters={chapters}
          isLoading={isLoading}
        />
      ) : isSurah ? (
        <SurahFields
          localRepeat={localRepeat}
          setLocalRepeat={setLocalRepeat}
          setRangeWarning={setRangeWarning}
          chapters={chapters}
          isLoading={isLoading}
        />
      ) : showRange ? (
        <RangeFields
          localRepeat={localRepeat}
          setLocalRepeat={setLocalRepeat}
          setRangeWarning={setRangeWarning}
          chapters={chapters}
          isLoading={isLoading}
        />
      ) : null}

      {/* Settings Section */}
      <div className={`grid grid-cols-1 gap-3 ${isSingle ? 'sm:grid-cols-2' : 'sm:grid-cols-3'}`}>
        {!isSingle && (
          <CounterInput
            label="Play Count"
            value={localRepeat.playCount ?? 1}
            min={1}
            onChange={(v) => setLocalRepeat({ ...localRepeat, playCount: v })}
          />
        )}
        <CounterInput
          label="Repeat Each"
          value={localRepeat.repeatEach ?? 1}
          min={1}
          onChange={(v) => setLocalRepeat({ ...localRepeat, repeatEach: v })}
        />
        <CounterInput
          label="Delay (s)"
          value={localRepeat.delay ?? 0}
          min={0}
          onChange={(v) => setLocalRepeat({ ...localRepeat, delay: v })}
        />
      </div>
    </div>
  );
}

function SingleVerseFields({
  localRepeat,
  setLocalRepeat,
  setRangeWarning,
  chapters,
  isLoading,
}: {
  localRepeat: RepeatOptions;
  setLocalRepeat: React.Dispatch<React.SetStateAction<RepeatOptions>>;
  setRangeWarning: React.Dispatch<React.SetStateAction<string | null>>;
  chapters: ReturnType<typeof useSurahNavigationData>['chapters'];
  isLoading: boolean;
}): React.JSX.Element {
  const selectedSurah = useMemo(
    () => chapters.find((chapter) => chapter.id === localRepeat.surahId),
    [chapters, localRepeat.surahId]
  );

  useEffect(() => {
    if (!selectedSurah?.verses_count || !localRepeat.verseNumber) return;
    if (localRepeat.verseNumber > selectedSurah.verses_count) {
      setLocalRepeat((prev) => ({ ...prev, verseNumber: selectedSurah.verses_count }));
    }
  }, [localRepeat.verseNumber, selectedSurah, setLocalRepeat]);

  const handleSurahChange = useCallback(
    (id: number | undefined) => {
      setLocalRepeat(
        (prev) =>
          ({
            ...prev,
            surahId: id,
            verseNumber: undefined,
          }) as unknown as RepeatOptions
      );
      setRangeWarning(null);
    },
    [setLocalRepeat, setRangeWarning]
  );

  const handleVerseChange = useCallback(
    (verse: number | undefined) => {
      setLocalRepeat((prev) => ({ ...prev, verseNumber: verse }) as unknown as RepeatOptions);
      setRangeWarning(null);
    },
    [setLocalRepeat, setRangeWarning]
  );

  return (
    <SurahVerseSelector
      chapters={chapters}
      isLoading={isLoading}
      selectedSurah={localRepeat.surahId}
      selectedVerse={localRepeat.verseNumber}
      onSurahChange={handleSurahChange}
      onVerseChange={handleVerseChange}
    />
  );
}

function SurahFields({
  localRepeat,
  setLocalRepeat,
  setRangeWarning,
  chapters,
  isLoading,
}: {
  localRepeat: RepeatOptions;
  setLocalRepeat: React.Dispatch<React.SetStateAction<RepeatOptions>>;
  setRangeWarning: React.Dispatch<React.SetStateAction<string | null>>;
  chapters: ReturnType<typeof useSurahNavigationData>['chapters'];
  isLoading: boolean;
}): React.JSX.Element {
  const noopVerseChange = useCallback(() => undefined, []);
  const handleSurahChange = useCallback(
    (id: number | undefined) => {
      setLocalRepeat((prev) => ({ ...prev, surahId: id, verseNumber: undefined }));
      setRangeWarning(null);
    },
    [setLocalRepeat, setRangeWarning]
  );

  return (
    <SurahVerseSelector
      chapters={chapters}
      isLoading={isLoading}
      selectedSurah={localRepeat.surahId}
      selectedVerse={undefined}
      onSurahChange={handleSurahChange}
      onVerseChange={noopVerseChange}
      hideVerse
    />
  );
}

function RangeFields({
  localRepeat,
  setLocalRepeat,
  setRangeWarning,
  chapters,
  isLoading,
}: {
  localRepeat: RepeatOptions;
  setLocalRepeat: React.Dispatch<React.SetStateAction<RepeatOptions>>;
  setRangeWarning: React.Dispatch<React.SetStateAction<string | null>>;
  chapters: ReturnType<typeof useSurahNavigationData>['chapters'];
  isLoading: boolean;
}): React.JSX.Element {
  const startSurahId = localRepeat.startSurahId ?? localRepeat.surahId;
  const endSurahId = localRepeat.endSurahId ?? startSurahId;
  const selectedStartVerse = localRepeat.startVerseNumber ?? localRepeat.start;
  const selectedEndVerse = localRepeat.endVerseNumber ?? localRepeat.end;

  const startChapter = useMemo(
    () => chapters.find((chapter) => chapter.id === startSurahId),
    [chapters, startSurahId]
  );
  const endChapter = useMemo(
    () => chapters.find((chapter) => chapter.id === endSurahId),
    [chapters, endSurahId]
  );

  useEffect(() => {
    if (!startChapter?.verses_count || !selectedStartVerse) return;
    if (selectedStartVerse > startChapter.verses_count) {
      setLocalRepeat((prev) => ({
        ...prev,
        startVerseNumber: startChapter.verses_count,
        start: startChapter.verses_count,
      }));
    }
  }, [selectedStartVerse, startChapter?.verses_count, setLocalRepeat]);

  useEffect(() => {
    if (!endChapter?.verses_count || !selectedEndVerse) return;
    if (selectedEndVerse > endChapter.verses_count) {
      setLocalRepeat((prev) => ({
        ...prev,
        endVerseNumber: endChapter.verses_count,
        end: endChapter.verses_count,
      }));
    }
  }, [selectedEndVerse, endChapter?.verses_count, setLocalRepeat]);

  useEffect(() => {
    if (!startChapter || localRepeat.startVerseNumber !== undefined) return;
    setLocalRepeat((prev) => ({ ...prev, startVerseNumber: 1, start: 1 }));
  }, [localRepeat.startVerseNumber, setLocalRepeat, startChapter]);

  useEffect(() => {
    if (!endChapter || localRepeat.endVerseNumber !== undefined) return;
    setLocalRepeat((prev) => {
      const fallbackEnd = prev.startVerseNumber ?? prev.start ?? 1;
      return { ...prev, endVerseNumber: fallbackEnd, end: fallbackEnd };
    });
  }, [localRepeat.endVerseNumber, setLocalRepeat, endChapter]);

  const handleStartSurahChange = useCallback(
    (id: number | undefined) => {
      setLocalRepeat((prev) => ({
        ...prev,
        startSurahId: id,
        startVerseNumber: undefined,
        start: undefined,
        ...(prev.endSurahId ? {} : { endSurahId: id }),
      }));
      setRangeWarning(null);
    },
    [setLocalRepeat, setRangeWarning]
  );

  const handleStartVerseChange = useCallback(
    (verse: number | undefined) => {
      setLocalRepeat((prev) => {
        const startSurah = prev.startSurahId ?? prev.surahId;
        const endSurah = prev.endSurahId ?? startSurah;
        const shouldSyncEnd =
          !prev.endVerseNumber && !prev.end && startSurah && endSurah === startSurah;
        return {
          ...prev,
          startVerseNumber: verse,
          start: verse,
          ...(shouldSyncEnd ? { endVerseNumber: verse, end: verse } : {}),
        };
      });
      setRangeWarning(null);
    },
    [setLocalRepeat, setRangeWarning]
  );

  const handleEndSurahChange = useCallback(
    (id: number | undefined) => {
      setLocalRepeat((prev) => ({
        ...prev,
        endSurahId: id,
        endVerseNumber: undefined,
        end: undefined,
      }));
      setRangeWarning(null);
    },
    [setLocalRepeat, setRangeWarning]
  );

  const handleEndVerseChange = useCallback(
    (verse: number | undefined) => {
      setLocalRepeat((prev) => ({ ...prev, endVerseNumber: verse, end: verse }));
      setRangeWarning(null);
    },
    [setLocalRepeat, setRangeWarning]
  );

  return (
    <>
      <SurahVerseSelector
        chapters={chapters}
        isLoading={isLoading}
        selectedSurah={startSurahId}
        selectedVerse={selectedStartVerse}
        onSurahChange={handleStartSurahChange}
        onVerseChange={handleStartVerseChange}
        surahLabel="Start Surah"
        verseLabel="Start Verse"
      />

      <SurahVerseSelector
        chapters={chapters}
        isLoading={isLoading}
        selectedSurah={endSurahId}
        selectedVerse={selectedEndVerse}
        onSurahChange={handleEndSurahChange}
        onVerseChange={handleEndVerseChange}
        surahLabel="End Surah"
        verseLabel="End Verse"
      />
    </>
  );
}

import { compareVerseKeys } from '@/app/shared/player/utils/repeat';

import { restartVerseWithDelay } from './repeatHelpers';

interface RangeRepeatArgs {
  start: number;
  end: number;
  startKey?: string | null;
  endKey?: string | null;
  currentAyah: number | null;
  currentKey?: string | null;
  delay: number;
  verseRepeatsLeft: number;
  repeatEach: number;
  onNext?: () => boolean;
  onPrev?: () => boolean;
  seek: (s: number) => void;
  play: () => void;
  setVerseRepeatsLeft: (n: number) => void;
  setPlayRepeatsLeft: (n: number) => void;
  playRepeatsLeft: number;
  rangeSize?: number;
}

export function createRangeRepeatHandler({
  start,
  end,
  startKey,
  endKey,
  currentAyah,
  currentKey,
  delay,
  verseRepeatsLeft,
  repeatEach,
  onNext,
  onPrev,
  seek,
  play,
  setVerseRepeatsLeft,
  setPlayRepeatsLeft,
  playRepeatsLeft,
  rangeSize,
}: RangeRepeatArgs): () => boolean {
  const shouldAdvance = (): boolean => {
    if (currentKey && endKey) {
      return compareVerseKeys(currentKey, endKey) < 0;
    }
    if (currentAyah !== null) return currentAyah < end;
    return false;
  };

  const getRewindSteps = (): number => {
    if (rangeSize && rangeSize > 0) return Math.max(0, rangeSize - 1);
    return Math.max(0, end - start);
  };

  const restartRange = (): void => {
    const steps = getRewindSteps();
    if (steps <= 0) {
      restartVerseWithDelay({ delay, seek, play });
      return;
    }
    setTimeout(() => {
      for (let i = 0; i < steps; i += 1) {
        onPrev?.();
      }
    }, delay);
  };

  return () => {
    if (verseRepeatsLeft > 1) {
      setVerseRepeatsLeft(verseRepeatsLeft - 1);
      restartVerseWithDelay({ delay, seek, play });
      return true;
    }
    setVerseRepeatsLeft(repeatEach);
    if (shouldAdvance()) {
      onNext?.();
      return true;
    }
    if (playRepeatsLeft > 1) {
      setPlayRepeatsLeft(playRepeatsLeft - 1);
      restartRange();
      return true;
    }
    return false;
  };
}

export type { RangeRepeatArgs };

'use client';

import { useEffect, useMemo, useRef } from 'react';

import { useAudio } from '@/app/shared/player/context/AudioContext';
import { useQdcAudioFile } from '@/app/shared/player/hooks/useQdcAudioFile';

import type { QdcAudioSegment, QdcAudioVerseTiming } from '@/lib/audio/qdcAudio';

function parseChapterIdFromVerseKey(verseKey: string): number | null {
  const [surahRaw] = verseKey.split(':');
  const parsed = Number.parseInt(surahRaw ?? '', 10);
  return Number.isFinite(parsed) ? parsed : null;
}

function cssEscape(value: string): string {
  if (typeof CSS !== 'undefined' && typeof CSS.escape === 'function') {
    return CSS.escape(value);
  }
  return value.replace(/"/g, '\\"');
}

function findActiveWord(segments: QdcAudioSegment[], currentMs: number): number | null {
  for (const [word, startMs, endMs] of segments) {
    if (currentMs >= startMs && currentMs < endMs) {
      return word;
    }
  }
  return null;
}

function resolveVerseTiming(
  timings: QdcAudioVerseTiming[] | undefined,
  verseKey: string
): QdcAudioVerseTiming | null {
  if (!timings?.length) return null;
  return timings.find((t) => t.verseKey === verseKey) ?? null;
}

export type SelectorBuilder = (
  verseKey: string,
  activeWord: number,
  cssEscape: (val: string) => string
) => string;

interface UseAudioWordSyncOptions {
  highlightClass: string;
  selectorBuilder: SelectorBuilder;
}

export function useAudioWordSync({
  highlightClass,
  selectorBuilder,
}: UseAudioWordSyncOptions): void {
  const audio = useAudio();

  const chapterId = useMemo(() => {
    const key = audio.activeVerse?.verse_key;
    if (!key) return null;
    return parseChapterIdFromVerseKey(key);
  }, [audio.activeVerse?.verse_key]);

  const verseKey = audio.activeVerse?.verse_key ?? null;

  const { audioFile } = useQdcAudioFile(audio.reciter.id, chapterId, true);

  const verseTiming = useMemo(() => {
    if (!verseKey) return null;
    const timing = resolveVerseTiming(audioFile?.verseTimings, verseKey);
    // Spread into new object to avoid leaking accidental mutations.
    return timing ? { ...timing } : null;
  }, [audioFile?.verseTimings, verseKey]);

  const previousElRef = useRef<HTMLElement | null>(null);
  const previousWordRef = useRef<number | null>(null);

  useEffect(() => {
    // We do NOT perform a global cleanup here anymore because it can cause race conditions
    // where highlights are removed when the effect re-runs (e.g. playbackSessionId change)
    // but the new highlight hasn't been applied yet.
    // We rely on the return cleanup (below) and the internal logic of handleTimeUpdate.

    if (!audio.isPlaying) return;
    if (!verseKey) return;

    const segments = verseTiming?.segments;
    if (!segments?.length) return;

    let attachedAudio: HTMLAudioElement | null = null;
    let rafId: number | null = null;
    let cancelled = false;

    const handleTimeUpdate = (): void => {
      if (!attachedAudio) return;
      const currentMs = (attachedAudio.currentTime || 0) * 1000;
      const activeWord = findActiveWord(segments, currentMs);

      if (activeWord === previousWordRef.current) return;
      previousWordRef.current = activeWord;

      if (previousElRef.current) {
        previousElRef.current.classList.remove(highlightClass);
        previousElRef.current = null;
      }

      if (!activeWord) return;

      const selector = selectorBuilder(verseKey, activeWord, cssEscape);
      const next = document.querySelector<HTMLElement>(selector);
      if (!next) return;
      next.classList.add(highlightClass);
      previousElRef.current = next;
    };

    const attach = (): void => {
      if (cancelled) return;
      const el = audio.audioRef.current;
      // Ensure we have an element AND it is actually in the DOM.
      // If the player was just closed/re-opened, the ref might still point to the
      // old unmounted (detached) element until the new one mounts and updates the ref.
      if (!el || !el.isConnected) {
        rafId = requestAnimationFrame(attach);
        return;
      }
      attachedAudio = el;
      el.addEventListener('timeupdate', handleTimeUpdate);
      handleTimeUpdate();
    };

    attach();

    return () => {
      cancelled = true;
      if (rafId) cancelAnimationFrame(rafId);
      if (attachedAudio) attachedAudio.removeEventListener('timeupdate', handleTimeUpdate);
      previousElRef.current?.classList.remove(highlightClass);
      previousElRef.current = null;
      previousWordRef.current = null;

      // Failsafe: ensure no stuck highlights remain when unmounting or changing verses
      document.querySelectorAll(`.${highlightClass}`).forEach((el) => {
        el.classList.remove(highlightClass);
      });
    };
  }, [
    audio.isPlaying,
    audio.playbackSessionId,
    audio.audioRef,
    verseKey,
    verseTiming,
    highlightClass,
    selectorBuilder,
  ]);

  // Handle clicking on words to seek
  useEffect(() => {
    const handleDocumentClick = (e: MouseEvent): void => {
      if (!audio.isPlayerVisible) return;

      const target = e.target as HTMLElement;
      const wordElement = target.closest('[data-verse-word="true"]');
      if (!wordElement) return;

      const elementVerseKey = wordElement.getAttribute('data-verse-key');
      const elementWordPosition = wordElement.getAttribute('data-word-position');

      if (!elementVerseKey || !elementWordPosition || !audioFile?.verseTimings) return;

      // Find timing for the clicked verse
      const timing = resolveVerseTiming(audioFile.verseTimings, elementVerseKey);
      if (!timing) return;

      const wordPosition = parseInt(elementWordPosition, 10);
      const segments = timing?.segments;
      if (!segments) return;

      const segment = segments.find((s) => s[0] === wordPosition);

      if (segment) {
        // segment[1] is start timestamp in ms
        const seekTimeSeconds = segment[1] / 1000;

        const audioEl = audio.audioRef.current;
        if (audioEl) {
          audioEl.currentTime = seekTimeSeconds;

          if (audioEl.paused) {
            audioEl
              .play()
              .then(() => {
                audio.setIsPlaying(true);
              })
              .catch(() => {
                // ignore play errors (e.g. if no source loaded yet)
              });
          }
        }
      }
    };

    document.addEventListener('click', handleDocumentClick);
    return () => {
      document.removeEventListener('click', handleDocumentClick);
    };
  }, [audio, audioFile]);
}

import { useRouter } from 'next/navigation';
import { Dispatch, SetStateAction, useEffect, useMemo, useRef, useState } from 'react';

import { useSettings } from '@/app/providers/SettingsContext';
import { useSurahNavigationData } from '@/app/shared/navigation/hooks/useSurahNavigationData';
import { buildSurahRoute } from '@/app/shared/navigation/routes';
import { useAudio } from '@/app/shared/player/context/AudioContext';
import {
  hasNonIntegerValues,
  adjustRange,
  deriveRangeBoundaries,
} from '@/app/shared/player/utils/repeat';
import { getVerseByKey } from '@/lib/api/verses';
import { ensureLanguageCode } from '@/lib/text/languageCodes';

import type { RepeatOptions } from '@/app/shared/player/types';

/**
 * Local state manager for playback options and reciter selection.
 *
 * @param onClose callback to close the options modal.
 * @returns current selections and helpers to commit changes.
 */
interface UsePlaybackOptionsReturn {
  localReciter: number;
  setLocalReciter: Dispatch<SetStateAction<number>>;
  localRepeat: RepeatOptions;
  setLocalRepeat: Dispatch<SetStateAction<RepeatOptions>>;
  rangeWarning: string | null;
  setRangeWarning: Dispatch<SetStateAction<string | null>>;
  commit: () => void;
}

export function usePlaybackOptions(isOpen: boolean, onClose: () => void): UsePlaybackOptionsReturn {
  const router = useRouter();
  const {
    reciter,
    setReciterId,
    repeatOptions,
    setRepeatOptions,
    activeVerse,
    setActiveVerse,
    setPlayingId,
    setLoadingId,
    setIsPlaying,
    openPlayer,
  } = useAudio();
  const { settings } = useSettings();
  const { chapters } = useSurahNavigationData();
  const translationIds = useMemo(() => {
    const ids = settings.translationIds?.filter((id) => Number.isFinite(id));
    if (ids?.length) return ids;
    if (Number.isFinite(settings.translationId)) return [settings.translationId];
    return [20];
  }, [settings.translationId, settings.translationIds]);
  const wordLang = useMemo(() => ensureLanguageCode(settings.wordLang), [settings.wordLang]);
  const [localReciter, setLocalReciter] = useState(reciter.id);
  const [localRepeat, setLocalRepeat] = useState<RepeatOptions>(repeatOptions);
  const [rangeWarning, setRangeWarning] = useState<string | null>(null);
  const activeVerseRef = useRef(activeVerse);

  useEffect(() => {
    activeVerseRef.current = activeVerse;
  }, [activeVerse]);

  const activeVerseNumber = useMemo((): number | undefined => {
    const key = activeVerse?.verse_key;
    if (!key) return undefined;
    const [, verse] = key.split(':');
    const parsed = Number.parseInt(verse ?? '', 10);
    return Number.isFinite(parsed) ? parsed : undefined;
  }, [activeVerse?.verse_key]);

  useEffect(() => {
    if (!isOpen) return;
    setLocalReciter(reciter.id);

    const activeVerseSnapshot = activeVerseRef.current;
    const activeSurahId = activeVerseSnapshot?.chapter_id;
    const activeVerseNumberSnapshot = (() => {
      const key = activeVerseSnapshot?.verse_key;
      if (!key) return undefined;
      const [, verse] = key.split(':');
      const parsed = Number.parseInt(verse ?? '', 10);
      return Number.isFinite(parsed) ? parsed : undefined;
    })();
    const effectiveMode = repeatOptions.mode === 'off' ? 'single' : repeatOptions.mode;

    const singleDefaults: Partial<RepeatOptions> =
      effectiveMode === 'single'
        ? {
            surahId: repeatOptions.surahId ?? activeSurahId,
            verseNumber: repeatOptions.verseNumber ?? activeVerseNumberSnapshot,
            start: repeatOptions.verseNumber ?? activeVerseNumberSnapshot ?? repeatOptions.start,
            end: repeatOptions.verseNumber ?? activeVerseNumberSnapshot ?? repeatOptions.end,
          }
        : {};
    const surahDefaults: Partial<RepeatOptions> =
      effectiveMode === 'surah'
        ? {
            surahId: repeatOptions.surahId ?? activeSurahId,
            verseNumber: undefined,
            start: 1,
            end: 1,
          }
        : {};
    const baseRangeDefaults: Partial<RepeatOptions> = {
      startSurahId: repeatOptions.startSurahId ?? repeatOptions.surahId ?? activeSurahId,
      endSurahId:
        repeatOptions.endSurahId ??
        repeatOptions.startSurahId ??
        repeatOptions.surahId ??
        activeSurahId,
      startVerseNumber:
        repeatOptions.startVerseNumber ?? repeatOptions.start ?? activeVerseNumberSnapshot ?? 1,
      endVerseNumber:
        repeatOptions.endVerseNumber ??
        repeatOptions.end ??
        repeatOptions.startVerseNumber ??
        repeatOptions.start ??
        activeVerseNumberSnapshot ??
        1,
      rangeSize: repeatOptions.rangeSize,
    };
    const rangeDefaults: Partial<RepeatOptions> =
      effectiveMode === 'range'
        ? {
            ...baseRangeDefaults,
            start:
              baseRangeDefaults.startVerseNumber ??
              repeatOptions.start ??
              activeVerseNumberSnapshot ??
              1,
            end:
              baseRangeDefaults.endVerseNumber ??
              baseRangeDefaults.startVerseNumber ??
              repeatOptions.end ??
              activeVerseNumberSnapshot ??
              1,
          }
        : baseRangeDefaults;

    setLocalRepeat({
      ...repeatOptions,
      mode: effectiveMode,
      ...singleDefaults,
      ...surahDefaults,
      ...rangeDefaults,
    });
  }, [isOpen, reciter.id, repeatOptions]);

  const commit = (): void => {
    const applyChanges = async (): Promise<void> => {
      setRangeWarning(null);

      if (hasNonIntegerValues(localRepeat)) {
        setRangeWarning('Please enter whole numbers only.');
        return;
      }

      // Update reciter if changed
      if (localReciter !== reciter.id) {
        setReciterId(localReciter);
      }

      if (localRepeat.mode === 'single') {
        const surahId = localRepeat.surahId ?? activeVerse?.chapter_id;
        const verseNumber =
          localRepeat.verseNumber ??
          (surahId && activeVerse?.chapter_id === surahId ? activeVerseNumber : undefined);
        if (!surahId || !verseNumber) {
          setRangeWarning('Select a surah and verse to repeat.');
          return;
        }
        const normalizedVerse = Math.max(1, verseNumber);
        const nextRepeat: RepeatOptions = {
          ...localRepeat,
          mode: 'single',
          surahId,
          verseNumber: normalizedVerse,
          start: normalizedVerse,
          end: normalizedVerse,
          playCount: 1,
        };
        try {
          const verseKey = `${surahId}:${normalizedVerse}`;
          const verse = await getVerseByKey(verseKey, translationIds, wordLang);
          setActiveVerse(verse);
          setPlayingId(verse.id);
          setLoadingId(verse.id);
          setIsPlaying(true);
          openPlayer();
          setRangeWarning(null);
          setRepeatOptions(nextRepeat);

          const href = buildSurahRoute(surahId, { startVerse: normalizedVerse, forceSeq: true });
          router.push(href, { scroll: false });

          onClose();
        } catch {
          setRangeWarning('Unable to load the selected verse. Please try again.');
        }
        return;
      }

      if (localRepeat.mode === 'surah') {
        const surahId = localRepeat.surahId ?? activeVerse?.chapter_id;
        if (!surahId) {
          setRangeWarning('Select a surah to repeat.');
          return;
        }
        const nextRepeat: RepeatOptions = {
          ...localRepeat,
          mode: 'surah',
          surahId,
          verseNumber: undefined,
          start: 1,
          end: 1,
          playCount: localRepeat.playCount ?? 1,
          repeatEach: localRepeat.repeatEach ?? 1,
          delay: localRepeat.delay ?? 0,
        };
        try {
          const verseKey = `${surahId}:1`;
          const verse = await getVerseByKey(verseKey, translationIds, wordLang);
          setActiveVerse(verse);
          setPlayingId(verse.id);
          setLoadingId(verse.id);
          setIsPlaying(true);
          openPlayer();
          setRangeWarning(null);
          setRepeatOptions(nextRepeat);

          const href = buildSurahRoute(surahId, { startVerse: 1, forceSeq: true });
          router.push(href, { scroll: false });

          onClose();
        } catch {
          setRangeWarning('Unable to load the selected surah. Please try again.');
        }
        return;
      }

      if (localRepeat.mode === 'range') {
        const range = deriveRangeBoundaries(localRepeat, chapters);
        if (!range) {
          setRangeWarning('Select a start and end surah and verse to repeat.');
          return;
        }
        const nextRepeat: RepeatOptions = {
          ...localRepeat,
          mode: 'range',
          surahId: range.startSurahId,
          startSurahId: range.startSurahId,
          startVerseNumber: range.startVerseNumber,
          endSurahId: range.endSurahId,
          endVerseNumber: range.endVerseNumber,
          start: range.startVerseNumber,
          end: range.endVerseNumber,
          rangeSize: range.rangeSize,
          playCount: localRepeat.playCount ?? 1,
          repeatEach: localRepeat.repeatEach ?? 1,
          delay: localRepeat.delay ?? 0,
        };
        try {
          const verse = await getVerseByKey(range.startKey, translationIds, wordLang);
          setActiveVerse(verse);
          setPlayingId(verse.id);
          setLoadingId(verse.id);
          setIsPlaying(true);
          openPlayer();
          setRangeWarning(null);
          setRepeatOptions(nextRepeat);

          const href = buildSurahRoute(range.startSurahId, {
            startVerse: range.startVerseNumber,
            forceSeq: true,
          });
          router.push(href, { scroll: false });

          onClose();
        } catch {
          setRangeWarning('Unable to load the selected range. Please try again.');
        }
        return;
      }

      const { start, end, adjusted } = adjustRange(localRepeat);
      if (adjusted) {
        setRangeWarning('Start and end values adjusted to a valid range.');
        setLocalRepeat({ ...localRepeat, start, end });
        return;
      }
      setRangeWarning(null);
      setRepeatOptions({ ...localRepeat, start, end });
      onClose();
    };

    void applyChanges();
  };

  return {
    localReciter,
    setLocalReciter,
    localRepeat,
    setLocalRepeat,
    rangeWarning,
    setRangeWarning,
    commit,
  };
}

import { useCallback, useEffect, useMemo, useState, MutableRefObject } from 'react';

import { formatTime } from '@/app/shared/player/utils/timeline';

import { useAudioPlayer } from './useAudioPlayer';

import type { Track } from '@/app/shared/player/types';

interface TrackMeta {
  title: string;
  artist: string;
  interactable: boolean;
}

function getTrackMeta(track?: Track | null): TrackMeta {
  if (!track) {
    return { title: 'No track selected', artist: '', interactable: false };
  }
  return {
    title: track.title ?? 'No track selected',
    artist: track.artist ?? '',
    interactable: Boolean(track.src),
  };
}

interface Opts {
  track?: Track | null;
  volume: number;
  playbackRate: number;
  contextRef: MutableRefObject<HTMLAudioElement | null>;
}

export interface TrackTimingReturn {
  audioRef: MutableRefObject<HTMLAudioElement | null>;
  play: () => void;
  pause: () => void;
  seek: (sec: number) => void;
  current: number;
  duration: number;
  elapsed: string;
  total: string;
  interactable: boolean;
  title: string;
  artist: string;
}

export function useTrackTiming({
  track,
  volume,
  playbackRate,
  contextRef,
}: Opts): TrackTimingReturn {
  const [current, setCurrent] = useState(0);
  const [duration, setDuration] = useState(track?.durationSec ?? 0);

  const segment = useMemo(() => {
    const start = track?.segmentStartSec;
    const end = track?.segmentEndSec;
    if (typeof start !== 'number' || typeof end !== 'number') return null;
    if (!Number.isFinite(start) || !Number.isFinite(end) || end <= start) return null;
    return { start, end, duration: end - start };
  }, [track?.segmentStartSec, track?.segmentEndSec]);

  const handleTimeUpdate = useCallback(
    (timeSec: number): void => {
      if (!segment) {
        setCurrent(timeSec);
        return;
      }
      const relative = timeSec - segment.start;
      setCurrent(Math.max(0, Math.min(segment.duration, relative)));
    },
    [segment]
  );

  const handleLoadedMetadata = useCallback(
    (loadedDuration: number): void => {
      if (segment) {
        setDuration(segment.duration);
        return;
      }
      setDuration(loadedDuration);
    },
    [segment]
  );

  const playerOptions: {
    src?: string;
    defaultDuration?: number;
    onTimeUpdate?: (time: number) => void;
    onLoadedMetadata?: (duration: number) => void;
  } = {
    onTimeUpdate: handleTimeUpdate,
    onLoadedMetadata: handleLoadedMetadata,
  };
  if (track?.src !== undefined) playerOptions.src = track.src;
  if (track?.durationSec !== undefined) playerOptions.defaultDuration = track.durationSec;

  const {
    audioRef,
    play,
    pause,
    seek: rawSeek,
    setVolume,
    setPlaybackRate,
  } = useAudioPlayer(playerOptions);

  const seek = useCallback(
    (sec: number): void => {
      if (!segment) {
        rawSeek(sec);
        return;
      }
      const a = audioRef.current;
      if (!a) return;
      const clamped = Math.max(0, Math.min(segment.duration, sec));
      try {
        a.currentTime = segment.start + clamped;
      } catch {
        // ignore invalid seek states (e.g., before metadata is loaded)
      }
      setCurrent(clamped);
    },
    [audioRef, rawSeek, segment]
  );

  useEffect(() => {
    contextRef.current = audioRef.current;
  }, [contextRef, audioRef]);
  useEffect(() => {
    setCurrent(0);
    setDuration(segment?.duration ?? track?.durationSec ?? 0);
  }, [segment?.duration, track?.durationSec, track?.id, track?.src]);
  useEffect(() => {
    if (!segment) return;
    // Seek to start of segment when segment changes
    const a = audioRef.current;
    if (!a) return;
    try {
      // Check if we're already close to the start time (continuous playback)
      // If within 0.3s, don't seek to avoid audio hiccups
      const diff = Math.abs(a.currentTime - segment.start);
      if (diff > 0.3) {
        a.currentTime = segment.start;
        setCurrent(0);
      } else {
        // Just sync the internal state
        setCurrent(Math.max(0, a.currentTime - segment.start));
      }
    } catch {
      // ignore invalid seek states
    }
  }, [segment, audioRef]);
  useEffect(() => {
    setVolume(volume);
    setPlaybackRate(playbackRate);
  }, [volume, playbackRate, setVolume, setPlaybackRate]);
  const elapsed = useMemo(() => formatTime(current), [current]);
  const total = useMemo(() => formatTime(duration || 0), [duration]);
  const { title, artist, interactable } = useMemo(() => getTrackMeta(track), [track]);
  return {
    audioRef,
    play,
    pause,
    seek,
    current,
    duration,
    elapsed,
    total,
    interactable,
    title,
    artist,
  };
}

