interface ReaderShellProps extends Pick<UseVerseListingParams, 'initialVerses'> {
  resourceId: string;
  resourceKind?: MushafResourceKind;
  lookup: LookupFn;
  emptyLabelKey?: string;
  endLabelKey?: string;
  totalVerses?: number | undefined;
  initialVersesParams?: UseVerseListingParams['initialVersesParams'];
  initialVerseNumber?: number | undefined;
  initialVerseKey?: string | undefined;
  initialScrollNonce?: string | undefined;
  initialMode?: 'verse' | 'mushaf';
}

export function ReaderShell({
  resourceId,
  resourceKind = 'surah',
  lookup,
  initialVerses,
  emptyLabelKey,
  endLabelKey,
  totalVerses,
  initialVersesParams,
  initialVerseNumber,
  initialVerseKey,
  initialScrollNonce,
  initialMode = 'verse',
}: ReaderShellProps): React.JSX.Element {
  const { mode, setMode, enableReaderMode, isReaderModeAvailable } = useReaderMode();
  const { setSettingsOpen } = useUIState();
  const readerView = useReaderView({
    resourceId,
    resourceKind,
    lookup,
    initialVerses,
    ...(typeof totalVerses === 'number' ? { totalVerses } : {}),
    ...(initialVersesParams ? { initialVersesParams } : {}),
    ...(typeof initialVerseNumber === 'number' ? { initialVerseNumber } : {}),
  });
  const { verseListing, panels, mushafParams } = readerView;
  const initialModeRef = useRef(initialMode);

  useEffect(() => {
    if (!isReaderModeAvailable) {
      enableReaderMode(initialModeRef.current);
    } else {
      // Preserve the previously selected reader mode across surah navigations.
      enableReaderMode(mode);
    }
  }, [enableReaderMode, isReaderModeAvailable, mode]);

  const chapterId = useMemo(() => {
    if (resourceKind === 'surah') {
      const parsed = Number.parseInt(resourceId, 10);
      if (Number.isFinite(parsed)) {
        return parsed;
      }
    }
    return verseListing.verses[0]?.chapter_id ?? initialVerses?.[0]?.chapter_id ?? undefined;
  }, [resourceKind, resourceId, verseListing.verses, initialVerses]);

  const handleReadingPanelOpen = useCallback(() => {
    setMode('mushaf');
    setSettingsOpen(false);
  }, [setMode, setSettingsOpen]);

  const handleTranslationTabOpen = useCallback(() => {
    setMode('verse');
    setSettingsOpen(false);
  }, [setMode, setSettingsOpen]);

  const surahId = useMemo(() => {
    if (resourceKind === 'surah') {
      const parsed = Number.parseInt(resourceId, 10);
      if (Number.isFinite(parsed)) {
        return parsed;
      }
    }
    return verseListing.verses[0]?.chapter_id ?? initialVerses?.[0]?.chapter_id ?? undefined;
  }, [resourceKind, resourceId, verseListing.verses, initialVerses]);

  const surahMain = createSurahMain({
    surahId,
    verseListing,
    ...(typeof emptyLabelKey === 'string' ? { emptyLabelKey } : {}),
    ...(typeof endLabelKey === 'string' ? { endLabelKey } : {}),
    ...(typeof initialVerseKey === 'string' ? { initialVerseKey } : {}),
    ...(typeof initialScrollNonce === 'string' ? { initialScrollNonce } : {}),
    ...(resourceKind === 'surah' && typeof chapterId === 'number' ? { chapterId } : {}),
  });

  const mushafMain = (
    <MushafMain
      mushafName={panels.selectedMushafName ?? 'Mushaf view'}
      mushafId={panels.selectedMushafId}
      resourceId={resourceId}
      resourceKind={resourceKind}
      {...(typeof mushafParams.initialPageNumber === 'number'
        ? { initialPageNumber: mushafParams.initialPageNumber }
        : {})}
      {...(typeof initialVerseKey === 'string' ? { initialVerseKey } : {})}
      chapterId={chapterId}
      {...(typeof mushafParams.juzNumber === 'number' ? { juzNumber: mushafParams.juzNumber } : {})}
      {...(typeof mushafParams.reciterId === 'number' ? { reciterId: mushafParams.reciterId } : {})}
      {...(mushafParams.wordByWordLocale
        ? { wordByWordLocale: mushafParams.wordByWordLocale }
        : {})}
      {...(mushafParams.translationIds ? { translationIds: mushafParams.translationIds } : {})}
      endLabelKey={endLabelKey}
    />
  );
  const mainContent = mode === 'mushaf' ? mushafMain : surahMain;
  const activeReaderTab = mode === 'mushaf' ? 'reading' : 'translation';
  const settingsSidebar = createSettingsSidebar(
    panels,
    handleReadingPanelOpen,
    handleTranslationTabOpen,
    activeReaderTab
  );
  const workspaceSettingsSidebar = createWorkspaceSettingsPanel(
    panels,
    handleReadingPanelOpen,
    handleTranslationTabOpen,
    activeReaderTab
  );
  const audioProps = mapToAudioProps(verseListing);
  const centerContentClassName = mode === 'mushaf' ? 'px-0 sm:px-0 lg:px-0' : undefined;

  return (
    <WorkspaceReaderLayout
      main={mainContent}
      desktopLeft={<SurahWorkspaceNavigation />}
      desktopRight={workspaceSettingsSidebar}
      mobileLeft={<SurahListSidebar />}
      mobileRight={settingsSidebar}
      audio={audioProps}
      {...(centerContentClassName ? { contentClassName: centerContentClassName } : {})}
    />
  );
}

'use client';

import React, { createContext, useContext, useMemo } from 'react';

import { useHeaderVisibility } from '@/app/(features)/layout/context/HeaderVisibilityContext';
import { cn } from '@/lib/utils/cn';

interface WorkspaceColumnsContextValue {
  hasLeftSidebar: boolean;
  hasRightSidebar: boolean;
  isRootHeaderAware: boolean;
}

const WorkspaceColumnsContext = createContext<WorkspaceColumnsContextValue>({
  hasLeftSidebar: false,
  hasRightSidebar: false,
  isRootHeaderAware: false,
});

export const useWorkspaceColumns = (): WorkspaceColumnsContextValue =>
  useContext(WorkspaceColumnsContext);

interface ThreeColumnWorkspaceProps {
  left?: React.ReactNode;
  center: React.ReactNode;
  right?: React.ReactNode;
  className?: string;
  leftContainerClassName?: string;
  rightContainerClassName?: string;
  centerContainerClassName?: string;
}

export function ThreeColumnWorkspace({
  left,
  center,
  right,
  className,
  leftContainerClassName,
  rightContainerClassName,
  centerContainerClassName,
}: ThreeColumnWorkspaceProps): React.JSX.Element {
  // ARCHITECTURE NOTE for Body Scrolling (like Quran.com):
  // - The page uses body scrolling, so scrollbar is on the right edge of browser
  // - Sidebars use `position: fixed` to stay in place while main content scrolls
  // - Header slides up/down based on scroll direction
  const { isHidden } = useHeaderVisibility();
  const hasLeftSidebar = Boolean(left);
  const hasRightSidebar = Boolean(right);

  // Sidebar positioning: fixed with top offset based on header visibility
  const sidebarTopClass = isHidden
    ? 'top-[var(--reader-safe-area-top)]'
    : 'top-[calc(var(--reader-header-height)+var(--reader-safe-area-top))]';

  // Sidebar height: viewport minus header (when visible) and safe area
  const sidebarHeightClass = isHidden
    ? 'h-[calc(100dvh-var(--reader-safe-area-top))]'
    : 'h-[calc(100dvh-var(--reader-header-height)-var(--reader-safe-area-top))]';

  const workspaceValue = useMemo<WorkspaceColumnsContextValue>(
    () => ({
      hasLeftSidebar,
      hasRightSidebar,
      isRootHeaderAware: false,
    }),
    [hasLeftSidebar, hasRightSidebar]
  );

  return (
    <WorkspaceColumnsContext.Provider value={workspaceValue}>
      <div
        className={cn(
          'relative flex w-full bg-background text-foreground workspace-root-height',
          className
        )}
        data-slot="workspace-root"
      >
        {/* Fixed Left Sidebar - positioned after the 64px icon sidebar */}
        {left ? (
          <aside
            className={cn(
              'hidden xl:flex xl:w-reader-sidebar-left xl:flex-col xl:gap-4',
              'xl:fixed xl:left-16 xl:z-10',
              'workspace-sidebar-left',
              'transition-all duration-300',
              sidebarTopClass,
              sidebarHeightClass,
              leftContainerClassName
            )}
            data-slot="workspace-left"
          >
            {left}
          </aside>
        ) : null}

        {/* Main content area - reserves space for fixed sidebars and icon sidebar */}
        <div
          className={cn(
            'flex min-w-0 flex-1 flex-col',
            // Account for icon sidebar (64px) + left sidebar on xl screens
            hasLeftSidebar && 'xl:ml-[var(--reader-sidebar-width-left)]',
            hasRightSidebar && '2xl:mr-reader-sidebar-right',
            centerContainerClassName
          )}
          data-slot="workspace-center"
        >
          {center}
        </div>

        {/* Fixed Right Sidebar - TEMPORARILY CENTERED FOR DEBUGGING */}
        {right ? (
          <aside
            className={cn(
              'hidden 2xl:flex 2xl:w-reader-sidebar-right 2xl:flex-col 2xl:gap-4',
              '2xl:fixed 2xl:right-0 2xl:z-10',
              'workspace-sidebar-right',
              'transition-all duration-300',
              sidebarTopClass,
              sidebarHeightClass,
              rightContainerClassName
            )}
            data-slot="workspace-right"
          >
            {right}
          </aside>
        ) : null}
      </div>
    </WorkspaceColumnsContext.Provider>
  );
}

'use client';

import { forwardRef, memo, useMemo, type ReactNode } from 'react';

import { useSettings } from '@/app/providers/SettingsContext';
import { ResponsiveVerseActions } from '@/app/shared/ResponsiveVerseActions';
import { VerseArabic } from '@/app/shared/VerseArabic';
import { sanitizeHtml } from '@/lib/text/sanitizeHtml';
import { cn } from '@/lib/utils/cn';

import type { VerseActionsProps } from '@/app/shared/verse-actions';
import type { Translation, Verse as VerseType } from '@/types';

type VerseCardVariant = 'separated' | 'contained';

export interface ReaderVerseCardProps {
  verse: VerseType;
  actions?: VerseActionsProps | null;
  variant?: VerseCardVariant;
  className?: string;
  actionsClassName?: string;
  contentClassName?: string;
  showArabic?: boolean;
  /**
   * Extends the Arabic selection area into the WorkspaceMain right gutter.
   * Helps prevent accidental selection jumping when dragging into the gutter next to the sidebar.
   */
  extendArabicSelectionGutter?: boolean;
  showTranslations?: boolean;
  translationFontSize?: number;
  children?: ReactNode;
  footer?: ReactNode;
  idPrefix?: string;
  resourceLanguages?: Record<number, string>;
  /** When true, applies a highlight style to indicate the verse is being played */
  isPlaying?: boolean;
}

const getVariantClasses = (variant: VerseCardVariant, isPlaying?: boolean): string => {
  const playingHighlight = isPlaying
    ? 'bg-accent/5 rounded-lg transition-colors duration-300 md:-mt-8 md:pt-8 px-3 -mx-3'
    : '';

  if (variant === 'contained') {
    const base = 'relative rounded-lg border border-border bg-surface p-6 shadow-sm';
    return isPlaying ? `${base} ring-2 ring-accent/30` : base;
  }

  const base = 'mb-0 pb-4 pt-4 md:mb-8 md:pb-8 md:pt-0 border-b border-border';
  return `${base} ${playingHighlight}`.trim();
};

const ReaderVerseCardComponent = forwardRef<HTMLDivElement, ReaderVerseCardProps>(
  (
    {
      verse,
      actions = null,
      variant = 'separated',
      className,
      actionsClassName,
      contentClassName,
      showArabic = true,
      extendArabicSelectionGutter = false,
      showTranslations = true,
      translationFontSize,
      children,
      footer,
      idPrefix = 'verse',
      resourceLanguages,
      isPlaying = false,
    },
    ref
  ) => {
    const { settings } = useSettings();
    const containerClasses = cn(getVariantClasses(variant, isPlaying), className);
    const fontSize = translationFontSize ?? settings.translationFontSize ?? 18;
    const arabicSelectionGutterClassName = extendArabicSelectionGutter
      ? '-mr-4 pr-1 sm:-mr-6 sm:pr-3 xl:-mr-6 xl:pr-3'
      : undefined;

    const sortedTranslations = useMemo(() => {
      if (!verse.translations || verse.translations.length === 0) {
        return [];
      }

      if (!settings.translationIds) {
        return verse.translations;
      }

      if (settings.translationIds.length === 0) {
        return [];
      }

      // Create a set for O(1) lookup of selected translation IDs
      const selectedIdsSet = new Set(settings.translationIds);

      // Create order map for sorting
      const orderMap = new Map<number, number>();
      settings.translationIds.forEach((id, index) => {
        orderMap.set(id, index);
      });

      // Filter to only include selected translations, then sort by order
      return verse.translations
        .filter((t) => selectedIdsSet.has(t.resource_id))
        .sort((a, b) => {
          const indexA = orderMap.get(a.resource_id) ?? 9999;
          const indexB = orderMap.get(b.resource_id) ?? 9999;
          return indexA - indexB;
        });
    }, [verse.translations, settings.translationIds]);

    return (
      <div id={`${idPrefix}-${verse.id}`} ref={ref} className={containerClasses}>
        <div className="space-y-4 md:space-y-0 md:flex md:items-stretch md:gap-x-6">
          {actions ? (
            <ResponsiveVerseActions
              {...actions}
              className={cn(
                'md:w-16 md:h-full md:flex md:flex-col md:justify-center',
                actions?.className,
                actionsClassName
              )}
            />
          ) : null}

          <div className={cn('space-y-6 md:flex-grow', contentClassName)}>
            {showArabic ? (
              <VerseArabic verse={verse} className={arabicSelectionGutterClassName} />
            ) : null}

            {showTranslations && sortedTranslations.length ? (
              <div className="space-y-6">
                {sortedTranslations.map((translation: Translation) => {
                  const lang = resourceLanguages?.[translation.resource_id];
                  const isEnglish = lang === 'en';
                  return (
                    <div key={translation.resource_id} className="group">
                      {translation.resource_name && (
                        <p className="mb-2 text-xs font-normal uppercase tracking-wider text-muted-foreground">
                          {translation.resource_name}
                        </p>
                      )}
                      <p
                        className={cn(
                          'text-left leading-relaxed text-slate-900 dark:text-slate-50',
                          isEnglish ? 'font-[family-name:var(--font-crimson-text)]' : ''
                        )}
                        lang={lang}
                        dir="auto"
                        style={{ fontSize: `${fontSize}px` }}
                        dangerouslySetInnerHTML={{ __html: sanitizeHtml(translation.text) }}
                      />
                    </div>
                  );
                })}
              </div>
            ) : null}

            {children}
          </div>
        </div>

        {footer}
      </div>
    );
  }
);

ReaderVerseCardComponent.displayName = 'ReaderVerseCard';

export const ReaderVerseCard = memo(ReaderVerseCardComponent);

