  translations: [
    {
      resource_id: 20,
      text: 'In the name of Allah, the Entirely Merciful, the Especially Merciful',
    },
  ],
  words: [
    { id: 1, uthmani: 'بِسْمِ', text_madani: 'بِسْمِ', text_imlaei_simple: 'بسم' },
    { id: 2, uthmani: 'اللَّهِ', text_madani: 'اللَّهِ', text_imlaei_simple: 'الله' },
  ],
};

afterEach(() => {
  localStorage.clear();
});

describe('ReaderVerseCard', () => {
  it('renders verse content and translations', () => {
    renderWithProviders(<ReaderVerseCard verse={baseVerse} />);

    expect(screen.getByText('بِسْمِ')).toBeInTheDocument();
    expect(screen.getByText('اللَّهِ')).toBeInTheDocument();
    expect(
      screen.getByText('In the name of Allah, the Entirely Merciful, the Especially Merciful')
    ).toBeInTheDocument();
  });

  it('supports slot customization through children and footer', () => {
    renderWithProviders(
      <ReaderVerseCard verse={baseVerse} footer={<div data-testid="footer-slot" />} />
    );

    expect(screen.getByTestId('footer-slot')).toBeInTheDocument();
  });

  it('applies variant styling when contained', () => {
    const { container } = renderWithProviders(
      <ReaderVerseCard verse={baseVerse} variant="contained" className="rounded-md shadow" />
    );

    const card = container.firstElementChild as HTMLElement;
    expect(card).toHaveClass('rounded-md');
    expect(card).toHaveClass('shadow');
  });

  it('honors custom translation font sizing when provided', () => {
    renderWithProviders(<ReaderVerseCard verse={baseVerse} translationFontSize={22} />);

    const translation = screen.getByText(
      'In the name of Allah, the Entirely Merciful, the Especially Merciful'
    );
    expect(translation).toHaveStyle({ fontSize: '22px' });
  });

  it('sanitizes translation content', () => {
    const maliciousVerse: Verse = {
      ...baseVerse,
      id: 2,
      verse_key: '1:2',
      translations: [
        {
          resource_id: 20,
          text: '<script>alert("bad")</script>Safe content',
        },
      ],
    };

    renderWithProviders(<ReaderVerseCard verse={maliciousVerse} />);

    expect(document.querySelector('script')).toBeNull();
    expect(screen.getByText('Safe content')).toBeInTheDocument();
  });

  it('strips unsupported silent alif marks when QPC Hafs font is selected', async () => {
    const verseWithSilentAlif: Verse = {
      id: 3,
      verse_key: '1:3',
      text_uthmani: 'و\u06DF',
      words: [{ id: 3, uthmani: 'و\u06DF' }],
    };

    localStorage.setItem(
      'quranAppSettings',
      JSON.stringify({ ...defaultSettings, arabicFontFace: '"UthmanicHafs1Ver18", serif' })
    );

    const { container } = renderWithProviders(<ReaderVerseCard verse={verseWithSilentAlif} />);

    await waitFor(() => {
      expect(container.textContent).not.toContain('\u06DF');
    });
    expect(screen.getByText('و')).toBeInTheDocument();
  });
});

'use client';

import React from 'react';

import { cn } from '@/lib/utils/cn';

import { FontSettings } from './FontSettings';
import { MushafSettings } from './MushafSettings';
import { TafsirSettings } from './TafsirSettings';
import { TranslationSettings } from './TranslationSettings';
import { SettingsContentProps } from './types';

import type { ReactElement } from 'react';

export const SettingsContent = ({
  activeTab,
  openSections,
  onSectionToggle,
  onArabicFontPanelOpen,
  onTajweedRulesPanelOpen,
  onTranslationPanelOpen,
  onWordLanguagePanelOpen,
  onTafsirPanelOpen,
  onMushafPanelOpen,
  selectedTranslationName,
  selectedTafsirName,
  selectedWordLanguageName,
  selectedMushafName = '',
  showTafsirSetting = false,
  idPrefix,
  isMushafMode = false,
  pageType,
}: SettingsContentProps): ReactElement => {
  const mushafVisible = isMushafMode || activeTab === 'reading';

  const translationSettings = (
    <TranslationSettings
      onTranslationPanelOpen={onTranslationPanelOpen}
      onWordLanguagePanelOpen={onWordLanguagePanelOpen}
      onTajweedRulesPanelOpen={onTajweedRulesPanelOpen}
      selectedTranslationName={selectedTranslationName}
      selectedWordLanguageName={selectedWordLanguageName}
      isOpen={openSections.includes('translation')}
      onToggle={() => onSectionToggle('translation')}
      {...(idPrefix ? { idPrefix: `${idPrefix}-translation` } : {})}
    />
  );

  const tafsirSettings = (
    <TafsirSettings
      {...(onTafsirPanelOpen !== undefined ? { onTafsirPanelOpen } : {})}
      {...(selectedTafsirName !== undefined ? { selectedTafsirName } : {})}
      showTafsirSetting={showTafsirSetting}
      isOpen={openSections.includes('tafsir')}
      onToggle={() => onSectionToggle('tafsir')}
      {...(idPrefix ? { idPrefix: `${idPrefix}-tafsir` } : {})}
    />
  );

  const fontSettings = (
    <FontSettings
      onArabicFontPanelOpen={onArabicFontPanelOpen}
      isOpen={openSections.includes('font')}
      onToggle={() => onSectionToggle('font')}
      {...(idPrefix ? { idPrefix: `${idPrefix}-font` } : {})}
      isArabicOnly={isMushafMode}
    />
  );

  const baseSettings =
    pageType === 'tafsir' ? (
      <>
        {tafsirSettings}
        {!isMushafMode && translationSettings}
        {fontSettings}
      </>
    ) : (
      <>
        {!isMushafMode && translationSettings}
        {tafsirSettings}
        {fontSettings}
      </>
    );

  return (
    <>
      <div
        data-testid="mushaf-settings-wrapper"
        aria-hidden={!mushafVisible}
        className={cn(
          'transition-all duration-300',
          mushafVisible
            ? 'max-h-[999px] opacity-100 translate-y-0'
            : 'max-h-0 opacity-0 -translate-y-2 pointer-events-none'
        )}
      >
        <MushafSettings
          selectedMushafName={selectedMushafName}
          onMushafPanelOpen={onMushafPanelOpen || (() => {})}
          isOpen={openSections.includes('mushaf')}
          onToggle={() => onSectionToggle('mushaf')}
          {...(idPrefix ? { idPrefix: `${idPrefix}-mushaf` } : {})}
        />
      </div>
      {baseSettings}
    </>
  );
};

