        aria-pressed={active}
      >
        <span
          className={`inline-block h-5 w-5 transform rounded-full bg-white shadow-[0_2px_4px_rgba(0,0,0,0.2)] ring-0 transition-transform duration-300 ${
            active ? 'translate-x-6' : 'translate-x-1'
