          </div>
          {formattedUpdatedAt ? (
            <span className="ml-auto inline-flex items-center gap-1 text-[11px] font-medium text-muted/80 whitespace-nowrap text-right">
              <ClockIcon className="h-3.5 w-3.5" />
              {formattedUpdatedAt}
            </span>
          ) : null}
        </div>
      </div>
    </BaseCard>
  );
});

