import { Bookmark } from '@/src/domain/entities';
import { BookmarkPosition } from '@/src/domain/value-objects/BookmarkPosition';

describe('Bookmark', () => {
  const position = new BookmarkPosition(1, 1, new Date('2026-01-01T00:00:00.000Z'));

  const createBookmark = (overrides: Partial<ConstructorParameters<typeof Bookmark>[0]> = {}) =>
    new Bookmark({
      id: 'bookmark-1',
      userId: 'user-1',
      verseId: 'verse-1',
      position,
      createdAt: new Date('2026-01-02T00:00:00.000Z'),
      ...overrides,
    });

  it('creates a valid bookmark with default tags', () => {
    const bookmark = createBookmark();
    expect(bookmark.tags).toEqual([]);
    expect(bookmark.notes).toBeUndefined();
  });

  it('validates required inputs', () => {
    expect(() => createBookmark({ id: '' })).toThrow('Bookmark ID cannot be empty');
    expect(() => createBookmark({ userId: '   ' })).toThrow('User ID cannot be empty');
    expect(() => createBookmark({ verseId: '' })).toThrow('Verse ID cannot be empty');
    expect(() => createBookmark({ createdAt: null as unknown as Date })).toThrow(
      'Created date is required'
    );
  });

  it('checks ownership via belongsToUser', () => {
    const bookmark = createBookmark({ userId: 'owner' });
    expect(bookmark.belongsToUser('owner')).toBe(true);
    expect(bookmark.belongsToUser('other')).toBe(false);
  });

  it('formats display text with notes and tags', () => {
    const bookmark = createBookmark({ notes: 'Note', tags: ['a', 'b'] });
    expect(bookmark.getDisplayText()).toBe('Surah 1, Verse 1 - Note [a, b]');

    const withoutNotesOrTags = createBookmark({ notes: '   ', tags: [] });
    expect(withoutNotesOrTags.getDisplayText()).toBe('Surah 1, Verse 1');
  });

  it('compares equality by id', () => {
    const a = createBookmark({ id: 'same' });
    const b = createBookmark({ id: 'same' });
    const c = createBookmark({ id: 'different' });
    expect(a.equals(b)).toBe(true);
    expect(a.equals(c)).toBe(false);
  });

  it('serializes to a plain object', () => {
    const bookmark = createBookmark({ notes: '', tags: ['tag'] });
    const plain = bookmark.toPlainObject();

    expect(plain.notes).toBeUndefined();
    expect(plain).toEqual(
      expect.objectContaining({
        id: 'bookmark-1',
        userId: 'user-1',
        verseId: 'verse-1',
        createdAt: '2026-01-02T00:00:00.000Z',
        tags: ['tag'],
        hasNotes: false,
        hasTags: true,
        displayText: 'Surah 1, Verse 1 [tag]',
      })
    );
    expect(plain.position).toEqual(
      expect.objectContaining({
        surahId: 1,
        ayahNumber: 1,
        verseKey: '1:1',
      })
    );
  });
});

import { Tafsir } from '@/src/domain/entities';

describe('Tafsir', () => {
  it('validates input on construction', () => {
    expect(() => new Tafsir({ id: 0, name: 'T', lang: 'english' })).toThrow();
    expect(() => new Tafsir({ id: 1, name: '', lang: 'english' })).toThrow();
    expect(() => new Tafsir({ id: 1, name: 'T', lang: '' })).toThrow();
  });

  it('exposes getters and formatting helpers', () => {
    const tafsir = new Tafsir({
      id: 10,
      name: 'Ibn Kathir',
      lang: 'english',
      authorName: 'Ibn Kathir',
      slug: 'ibn-kathir',
    });

    expect(tafsir.id).toBe(10);
    expect(tafsir.name).toBe('Ibn Kathir');
    expect(tafsir.language).toBe('english');
    expect(tafsir.authorName).toBe('Ibn Kathir');
    expect(tafsir.slug).toBe('ibn-kathir');
    expect(tafsir.displayName).toBe('Ibn Kathir');
    expect(tafsir.formattedLanguage).toBe('English');
  });

  it('matches languages and search terms case-insensitively', () => {
    const tafsir = new Tafsir({
      id: 11,
      name: 'Tafsir Name',
      lang: 'Bangla',
      authorName: 'Some Author',
    });

    expect(tafsir.isInLanguage('bangla')).toBe(true);
    expect(tafsir.isInLanguage('ENGLISH')).toBe(false);

    expect(tafsir.matchesSearch('name')).toBe(true);
    expect(tafsir.matchesSearch('BANGLA')).toBe(true);
    expect(tafsir.matchesSearch('author')).toBe(true);
    expect(tafsir.matchesSearch('missing')).toBe(false);
  });

  it('assigns language priority for sorting', () => {
    expect(new Tafsir({ id: 1, name: 'A', lang: 'english' }).getLanguagePriority()).toBe(0);
    expect(new Tafsir({ id: 2, name: 'B', lang: 'bengali' }).getLanguagePriority()).toBe(1);
    expect(new Tafsir({ id: 3, name: 'C', lang: 'Bangla' }).getLanguagePriority()).toBe(1);
    expect(new Tafsir({ id: 4, name: 'D', lang: 'arabic' }).getLanguagePriority()).toBe(2);
    expect(new Tafsir({ id: 5, name: 'E', lang: 'urdu' }).getLanguagePriority()).toBe(3);
  });

  it('serializes/deserializes and compares by id', () => {
    const tafsir = new Tafsir({ id: 123, name: 'X', lang: 'english', authorName: 'Y' });
    expect(tafsir.toJSON()).toEqual({ id: 123, name: 'X', lang: 'english', authorName: 'Y' });

    const restored = Tafsir.fromJSON(tafsir.toJSON());
    expect(restored.equals(tafsir)).toBe(true);
    expect(new Tafsir({ id: 999, name: 'X', lang: 'english' }).equals(tafsir)).toBe(false);
  });
});

import {
  Bookmark,
  hasNotes,
  hasTag,
  hasTags,
  withAddedTag,
  withNotes,
  withRemovedTag,
  withTags,
} from '@/src/domain/entities';
import { BookmarkPosition } from '@/src/domain/value-objects/BookmarkPosition';

describe('bookmarkHelpers', () => {
  const position = new BookmarkPosition(1, 1, new Date('2026-01-01T00:00:00.000Z'));

  const createBookmark = (overrides: Partial<ConstructorParameters<typeof Bookmark>[0]> = {}) =>
    new Bookmark({
      id: 'id',
      userId: 'user',
      verseId: 'verse',
      position,
      createdAt: new Date('2026-01-02T00:00:00.000Z'),
      tags: [],
      ...overrides,
    });

  it('updates notes and tags immutably', () => {
    const original = createBookmark({ notes: 'old', tags: ['a'] });

    const updatedNotes = withNotes(original, 'new');
    expect(updatedNotes.notes).toBe('new');
    expect(updatedNotes.tags).toEqual(['a']);
    expect(updatedNotes).not.toBe(original);

    const updatedTags = withTags(original, ['b']);
    expect(updatedTags.notes).toBe('old');
    expect(updatedTags.tags).toEqual(['b']);
    expect(updatedTags).not.toBe(original);
  });

  it('adds and removes tags without duplicates', () => {
    const original = createBookmark({ tags: ['a'] });

    const added = withAddedTag(original, 'b');
    expect(added.tags).toEqual(['a', 'b']);

    const addedDuplicate = withAddedTag(added, 'b');
    expect(addedDuplicate.tags).toEqual(['a', 'b']);

    const removed = withRemovedTag(added, 'a');
    expect(removed.tags).toEqual(['b']);
  });

  it('provides tag/notes predicates', () => {
    const bookmark = createBookmark({ notes: '  note  ', tags: ['x'] });
    expect(hasNotes(bookmark)).toBe(true);
    expect(hasTags(bookmark)).toBe(true);
    expect(hasTag(bookmark, 'x')).toBe(true);
    expect(hasTag(bookmark, 'missing')).toBe(false);

    const empty = createBookmark({ notes: '   ', tags: [] });
    expect(hasNotes(empty)).toBe(false);
    expect(hasTags(empty)).toBe(false);
  });
});

import { isStoredBookmark } from '@/src/domain/value-objects/StoredBookmark';

describe('StoredBookmark type guard', () => {
